INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_001','北京邮电大学','校园','["大学","教育","科技","通信","校园"]','["信息科技","通信特色","创新研究","学术氛围"]',5.0,902,2737,39.9577000,116.3577000,'北京市海淀区西土城路10号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京邮电大学.jpg','北京邮电大学是一所以信息科技为特色，工学门类为主体，工、管、文、理相结合的多科性全国重点大学。','北京邮电大学是教育部直属、工业和信息化部共建的全国重点大学，以信息科技为鲜明特色，在通信工程、计算机科学、网络安全等领域享有盛誉，被誉为"信息通信领域的黄埔军校"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_002','清华大学','校园','["大学","教育","工程","科技","研究"]','["工程技术","自然科学","创新研究","国际化"]',3.6,961,1473,39.9577000,116.3577000,'北京市海淀区清华园1号','校园参观时间：09:00-17:00（需预约）','uploads/images/清华大学.jpg','清华大学是中国著名的综合性研究型大学，以工程技术和自然科学见长，被誉为''红色工程师的摇篮''。','清华大学是中国最顶尖的高等学府之一，以工程技术见长，在自然科学、计算机科学、经济管理等诸多领域均处于国内领先地位。学校的前身清华学堂成立于1911年，百余年来培养了众多杰出科学家、工程师和国家领导人。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_003','北京大学','校园','["大学","教育","文理","学术","历史"]','["文理并重","学术自由","历史悠久","人文荟萃"]',4.3,574,2025,39.9577000,116.3577000,'北京市海淀区颐和园路5号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京大学.jpg','北京大学是中国近代第一所国立大学，以文理并重著称，被誉为中国高等教育的最高学府。','北京大学是中国近代第一所国立综合性大学，创办于1898年。学校以文、史、哲、理、工、医等多学科协调发展著称，人文学科和基础科学研究在国内首屈一指，元培学院、光华管理学院等享有极高声誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_004','中国人民大学','校园','["大学","教育","人文","社科","法学"]','["人文社科","法学强势","马克思主义","社会科学"]',3.9,326,2965,39.9577000,116.3577000,'北京市海淀区中关村大街59号','校园参观时间：09:00-17:00（需预约）','uploads/images/中国人民大学.jpg','中国人民大学是一所以人文社会科学为主的综合性研究型全国重点大学，被誉为''人民共和国建设者的摇篮''。','中国人民大学是新中国创办的第一所新型正规大学，以人文社会科学见长，在法学、经济学、新闻传播学、社会学等领域具有突出的学术优势，被誉为"人民共和国建设者的摇篮"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_005','北京交通大学','校园','["大学","教育","交通","工程","轨道"]','["交通特色","轨道交通","工程技术","行业领先"]',4.1,287,1759,39.9577000,116.3577000,'北京市海淀区上园村3号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京交通大学.jpg','北京交通大学是一所以交通科学与技术为特色的多科性大学，在轨道交通领域享有盛誉。','北京交通大学是教育部直属的全国重点大学，以交通科学与技术为鲜明特色，在轨道交通、交通运输工程、通信信号等领域处于国内领先地位，被誉为中国轨道交通工程师的摇篮。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_006','北京工业大学','校园','["大学","教育","工科","技术","创新"]','["工科优势","多学科","产学研","创新实践"]',4.7,1301,1632,39.9577000,116.3577000,'北京市朝阳区平乐园100号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京工业大学.jpg','北京工业大学是一所以工为主，理、工、经、管、文、法、艺术相结合的多科性市属重点大学。','北京工业大学是北京市属重点大学，以工科为主，理、工、经、管、文、法、艺术等多学科协调发展。学校在材料科学、机械工程、环境工程等领域具有较强的教学科研实力，是北京市科技创新的重要力量。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_007','北京航空航天大学','校园','["大学","教育","航空","航天","工程"]','["航空航天","工程技术","国防科技","创新研发"]',4.4,345,889,39.9577000,116.3577000,'北京市海淀区学院路37号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京航空航天大学.jpg','北京航空航天大学是一所以航空航天科学技术为特色的综合性全国重点大学，被誉为''航天工程师的摇篮''。','北京航空航天大学是新中国创建的第一所航空航天高等学府，隶属于工业和信息化部。学校在航空宇航科学与技术、力学、控制科学与工程、计算机科学与技术等领域实力雄厚，为中国的航空航天事业培养了大批核心人才。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_008','北京理工大学','校园','["大学","教育","理工","国防","科技"]','["理工强势","国防科技","军工特色","科技创新"]',5.0,717,2288,39.9577000,116.3577000,'北京市海淀区中关村南大街5号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京理工大学.jpg','北京理工大学是一所以理工为主，工、理、管、文协调发展的全国重点大学，在国防科技领域享有盛誉。','北京理工大学是中国共产党创办的第一所理工科大学，隶属于工业和信息化部，是国家"双一流"建设高校。学校以兵器科学与技术、机械工程、光学工程、信息与通信工程等学科见长，在国防科技领域享有崇高声誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_009','北京科技大学','校园','["大学","教育","材料","冶金","工程"]','["材料科学","冶金工程","工程技术","产业特色"]',4.3,545,2040,39.9577000,116.3577000,'北京市海淀区学院路30号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京科技大学.jpg','北京科技大学是一所以工为主，工、理、管、文、经、法等多学科协调发展的教育部直属全国重点大学。','北京科技大学是教育部直属的全国重点大学，以材料科学与工程、冶金工程为传统优势学科，在国内外享有盛誉，被誉为"钢铁摇篮"。学校的材料科学、工程学、化学等学科进入ESI全球排名前1%。
