INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_011','中国农业大学','校园','["大学","教育","农业","生命科学","食品"]','["农业科学","生命科学","食品工程","生态环境"]',4.8,571,2379,39.9577000,116.3577000,'北京市海淀区圆明园西路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/中国农业大学.jpg','中国农业大学是一所以农学、生命科学、农业工程和食品科学为特色和优势的研究型大学。','中国农业大学是教育部直属的全国重点大学，以农学、生命科学、食品科学和农业工程为优势和特色，在作物学、畜牧学、兽医学、农业资源与环境等学科领域实力雄厚。
