INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_015','北京外国语大学','校园','["大学","教育","外语","国际","翻译"]','["多语种教学","国际交流","翻译研究","外交人才"]',3.6,1144,1082,39.9577000,116.3577000,'北京市海淀区西三环北路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京外国语大学.jpg','北京外国语大学是中国外国语类高等院校中历史悠久、教授语种最多的全国重点大学。','北京外国语大学是教育部直属的全国重点大学，是中国外国语类高等院校中历史最悠久、教授语种最多的大学，素有"外交官的摇篮"之美誉。学校目前开设了超过100个语种的教学课程。
