INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_017','中央财经大学','校园','["大学","教育","财经","经济","管理"]','["经济学","金融学","会计学","管理科学"]',4.9,1397,1593,39.9577000,116.3577000,'北京市海淀区学院南路39号','校园参观时间：09:00-17:00（需预约）','uploads/images/中央财经大学.jpg','中央财经大学是一所以经济学、管理学和法学学科为主体的全国重点大学。','中央财经大学是教育部直属的全国重点大学，以经济学、管理学和法学为主体学科，在金融学、会计学、财政学等领域具有突出的学术优势和社会影响力，被誉为"中国财经管理专家的摇篮"。
