INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_019','北京体育大学','校园','["大学","教育","体育","运动","健康"]','["体育科学","运动训练","体育教育","运动医学"]',4.3,1369,1364,39.9577000,116.3577000,'北京市海淀区信息路48号','校园参观时间：09:00-17:00（需预约）','uploads/images/北京体育大学.jpg','北京体育大学是一所以体育科学为特色，教育学、管理学、医学等多学科协调发展的全国重点大学。','北京体育大学是国家体育总局直属的全国重点大学，以体育学为核心学科，在运动训练、体育教育、运动人体科学、体育管理等方向具有明显优势，是中国体育类院校的最高学府。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_020','中央音乐学院','校园','["大学","教育","音乐","艺术","表演"]','["音乐表演","音乐创作","音乐理论","艺术实践"]',4.5,988,1799,39.9577000,116.3577000,'北京市西城区鲍家街43号','校园参观时间：09:00-17:00（需预约）','uploads/images/中央音乐学院.jpg','中央音乐学院是一所培养高级专门音乐人才的高等学府，代表了中国专业音乐教育的最高水平。','中央音乐学院是教育部直属的全国重点大学，是中国音乐表演、音乐创作和音乐理论研究的最高学府，代表了中国专业音乐教育的最高水平，在国内外音乐界享有盛誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_021','中央民族大学','校园','["大学","教育","民族","文化","历史"]','["民族学","民族文化","语言研究","历史传承"]',4.8,793,2002,39.9577000,116.3577000,'北京市海淀区中关村南大街27号','校园参观时间：09:00-17:00（需预约）','uploads/images/中央民族大学.jpg','中央民族大学是一所以民族学、中国语言文学、历史学等为主要特色的综合性大学。','中央民族大学是国家民族事务委员会直属的全国重点大学，以民族学、中国语言文学、历史学等学科为特色，是中国培养少数民族高级专门人才的重要基地，也是展示中华民族多元文化的重要窗口。
