INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_027','天津大学','校园','["大学","教育","工程","建筑","化工"]','["建筑工程","化学工程","机械工程","电子信息"]',4.9,477,2963,39.9577000,116.3577000,'天津市南开区卫津路92号','校园参观时间：09:00-17:00（需预约）','uploads/images/天津大学.jpg','天津大学是中国第一所现代大学，以工为主、理工结合，经、管、文、法、医、教育、艺术等多学科协调发展。','天津大学是中国第一所现代大学，前身为北洋大学，创办于1895年。学校以工科见长，在化学工程与技术、建筑学、精密仪器与光电子、水利工程等领域具有突出优势，是"建筑老八校"之一。
