INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_052','浙江大学','校园','["大学","教育","综合","创新","国际"]','["综合实力","创新创业","国际化","多学科"]',4.7,623,1633,39.9577000,116.3577000,'浙江省杭州市西湖区余杭塘路866号','校园参观时间：09:00-17:00（需预约）','uploads/images/浙江大学.jpg','浙江大学是一所历史悠久、声誉卓著的高等学府，坐落于中国历史文化名城、风景旅游胜地杭州。','浙江大学是中国最顶尖的综合性研究型大学之一，位列C9联盟、华东五校，国家"双一流""211工程""985工程"重点建设高校。学校历史悠久，前身是1897年创办的求是书院，被誉为"东方剑桥"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_053','中国科学技术大学','校园','["大学","教育","科技","理学","创新"]','["基础科学","高新技术","理论物理","计算机科学"]',4.3,1017,1026,39.9577000,116.3577000,'安徽省合肥市包河区金寨路96号','校园参观时间：09:00-17:00（需预约）','uploads/images/中国科学技术大学.jpg','中国科学技术大学是一所以前沿科学和高新技术为主、兼有特色管理和人文学科的综合性全国重点大学。','中国科学技术大学是中国科学院直属的全国重点大学，C9联盟成员，国家"双一流""211工程""985工程"重点建设高校。学校1958年创办于北京，1970年南迁至安徽合肥，以培养基础科学研究和高新技术领域的拔尖创新人才而闻名于世。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_054','安徽大学','校园','["大学","教育","综合","文史","理工"]','["文史研究","理工科学","经济管理","法学教育"]',4.5,1118,1441,39.9577000,116.3577000,'安徽省合肥市肥西路3号','校园参观时间：09:00-17:00（需预约）','uploads/images/安徽大学.jpg','安徽大学是一所办学历史悠久、学科门类齐全、师资力量雄厚、办学特色鲜明的省属重点综合性大学。','安徽大学是安徽省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校前身是1928年创办的省立安徽大学，是安徽现代高等教育的开端，在安徽乃至全国都具有重要地位。
