INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_056','厦门大学','校园','["大学","教育","综合","海洋","经济"]','["海洋科学","经济学","化学工程","国际关系"]',3.7,1100,2966,39.9577000,116.3577000,'福建省厦门市思明区思明南路422号','校园参观时间：09:00-17:00（需预约）','uploads/images/厦门大学.jpg','厦门大学是一所学科门类齐全、师资力量雄厚、居国内一流、在国际上有广泛影响的综合性大学。','厦门大学是中国最美的大学之一，国家"双一流""211工程""985工程"重点建设高校。学校由著名爱国华侨领袖陈嘉庚先生于1921年创办，是中国近代教育史上第一所由华侨创办的大学。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_057','福州大学','校园','["大学","教育","理工","化工","土木"]','["化学工程","土木工程","机械工程","电气工程"]',4.1,722,2200,39.9577000,116.3577000,'福建省福州市闽侯县上街镇大学新区学园路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/福州大学.jpg','福州大学是一所以工为主、理工结合，理、工、经、管、文、法、艺等多学科协调发展的重点大学。','福州大学是福建省属重点大学，国家"211工程"和"双一流"建设高校。学校以工为主、理工结合，在化学工程、土木工程、电气工程等领域积淀深厚，是福建省最重要的工程技术人才培养基地。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_058','南昌大学','校园','["大学","教育","综合","医学","材料"]','["医学科学","材料科学","食品工程","新闻传播"]',3.8,1356,2295,39.9577000,116.3577000,'江西省南昌市红谷滩新区学府大道999号','校园参观时间：09:00-17:00（需预约）','uploads/images/南昌大学.jpg','南昌大学是一所''文理工医渗透、学研产用结合''的综合性大学，是江西省人民政府和教育部共建的国家211工程重点建设大学。','南昌大学是江西省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校由原江西大学、江西工业大学和江西医学院合并组建，学科门类齐全，是江西省规模最大、综合实力最强的高校。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_059','华东师范大学','校园','["大学","教育","师范","心理学","地理"]','["师范教育","心理学","地理科学","教育科学"]',4.7,630,2873,39.9577000,116.3577000,'上海市普陀区中山北路3663号','校园参观时间：09:00-17:00（需预约）','uploads/images/华东师范大学.jpg','华东师范大学是一所综合性研究型大学，在国内外享有很高声誉。','华东师范大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校成立于1951年，是以教育学和地理学著称的综合性研究型大学，在师范教育领域稳居全国前二。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_060','上海外国语大学','校园','["大学","教育","外语","国际","翻译"]','["多语种教学","国际关系","翻译研究","跨文化交流"]',4.1,272,2592,39.9577000,116.3577000,'上海市虹口区大连西路550号','校园参观时间：09:00-17:00（需预约）','uploads/images/上海外国语大学.jpg','上海外国语大学是一所以语言文学类学科为主，文学、教育学、经济学、管理学、法学等多学科协调发展的多科性大学。','上海外国语大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校前身是1949年创办的华东人民革命大学附设上海俄文学校，是中国外语高等教育的发祥地之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_061','上海财经大学','校园','["大学","教育","财经","经济","金融"]','["经济学","金融学","会计学","统计学"]',4.7,531,2999,39.9577000,116.3577000,'上海市杨浦区国定路777号','校园参观时间：09:00-17:00（需预约）','uploads/images/上海财经大学.jpg','上海财经大学是一所以经济管理学科为主，经、管、法、文、理协调发展的多科性研究型重点大学。','上海财经大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校前身是1917年创办的南京高等师范学校商科，是中国最早开办商学教育的高等学府之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_062','山东大学','校园','["大学","教育","综合","历史","文理"]','["综合实力","文史哲学","理工科学","医学教育"]',4.7,771,2632,39.9577000,116.3577000,'山东省济南市历城区山大南路27号','校园参观时间：09:00-17:00（需预约）','uploads/images/山东大学.jpg','山东大学是一所历史悠久、学科齐全、学术实力雄厚、办学特色鲜明的教育部直属重点综合性大学。','山东大学是中国历史最悠久的高等学府之一，国家"双一流""211工程""985工程"重点建设高校。学校前身是1901年创办的山东大学堂，是中国近代高等教育的源头之一，办学历史横跨三个世纪。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_063','中国海洋大学','校园','["大学","教育","海洋","水产","环境"]','["海洋科学","水产养殖","海洋工程","环境科学"]',4.3,1469,640,39.9577000,116.3577000,'山东省青岛市崂山区松岭路238号','校园参观时间：09:00-17:00（需预约）','uploads/images/中国海洋大学.jpg','中国海洋大学是一所海洋和水产学科特色显著、学科门类齐全的教育部直属重点综合性大学。','中国海洋大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校以海洋科学和水产学科为鲜明特色，是中国海洋高等教育的最高学府，也是亚洲海洋类学科最齐全的高校。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_064','中国石油大学(华东)','校园','["大学","教育","石油","化工","工程"]','["石油工程","化学工程","地质勘探","海洋油气"]',4.2,284,2115,39.9577000,116.3577000,'山东省青岛市黄岛区长江西路66号','校园参观时间：09:00-17:00（需预约）','uploads/images/中国石油大学(华东).jpg','中国石油大学是一所以工为主，石油石化特色鲜明，多学科协调发展的教育部直属全国重点大学。','中国石油大学（华东）是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校前身是1953年创办的北京石油学院，以石油石化为鲜明特色，被誉为"石油科技人才的摇篮"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_065','郑州大学','校园','["大学","教育","综合","医学","工程"]','["医学科学","工程技术","文史研究","综合发展"]',4.1,310,2444,39.9577000,116.3577000,'河南省郑州市科学大道100号','校园参观时间：09:00-17:00（需预约）','uploads/images/郑州大学.jpg','郑州大学是一所涵盖理学、工学、医学、文学、历史学、哲学、法学、经济学、管理学、教育学、农学、艺术学等12大学科门类的综合性研究型大学。','郑州大学是河南省属重点综合性大学，国家"211工程"和"双一流"建设高校，也是全国在校生规模最大的大学之一。学校由原郑州大学、郑州工业大学和河南医科大学于2000年合并组建，学科门类涵盖12大门类。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_066','华中科技大学','校园','["大学","教育","科技","医学","工程"]','["工程技术","医学科学","光电技术","机械制造"]',3.7,451,2732,39.9577000,116.3577000,'湖北省武汉市洪山区珞喻路1037号','校园参观时间：09:00-17:00（需预约）','uploads/images/华中科技大学.jpg','华中科技大学是一所学科门类齐全、学术实力雄厚的综合性研究型大学，被誉为''新中国高等教育发展的缩影''。','华中科技大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校由原华中理工大学、同济医科大学和武汉城市建设学院于2000年合并组建，以工科和医科为两大支柱，被誉为"新中国高等教育发展的缩影"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_067','武汉大学','校园','["大学","教育","综合","樱花","人文"]','["人文社科","理学研究","工程技术","医学教育"]',3.6,1028,2952,39.9577000,116.3577000,'湖北省武汉市武昌区珞珈山','校园参观时间：09:00-17:00（需预约）','uploads/images/武汉大学.jpg','武汉大学是一所中国著名的综合性研究型大学，也是近代中国建立的第一批国立大学。','武汉大学是中国最美丽的大学之一，国家"双一流""211工程""985工程"重点建设高校。学校前身是1893年张之洞创办的自强学堂，历经百余年发展，已成为享誉海内外的综合性研究型大学。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_068','华中师范大学','校园','["大学","教育","师范","教育学","心理学"]','["师范教育","教育科学","心理学","文学研究"]',5.0,258,2014,39.9577000,116.3577000,'湖北省武汉市洪山区珞喻路152号','校园参观时间：09:00-17:00（需预约）','uploads/images/华中师范大学.jpg','华中师范大学是一所以师范教育为特色，多学科协调发展的教育部直属重点综合性大学。','华中师范大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校前身是1903年创办的文华书院大学部，以师范教育和人文社会科学著称，是教育部直属六所师范大学之一。
