INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_071','中国地质大学(武汉)','校园','["大学","教育","地质","地球科学","资源"]','["地球科学","地质工程","资源勘探","环境地质"]',4.7,1016,1608,39.9577000,116.3577000,'湖北省武汉市洪山区鲁磨路388号','校园参观时间：09:00-17:00（需预约）','uploads/images/中国地质大学(武汉).jpg','中国地质大学是一所以地球科学为主要特色，学科门类齐全、理工文管协调发展的教育部直属全国重点大学。','中国地质大学（武汉）是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校以地球科学为鲜明特色，在地质学、地质资源与地质工程等领域享有世界级声誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_072','湖南大学','校园','["大学","教育","综合","历史","岳麓"]','["机械工程","土木工程","化学化工","经济管理"]',4.3,809,1675,39.9577000,116.3577000,'湖南省长沙市岳麓区麓山南路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/湖南大学.jpg','湖南大学是一所历史悠久、蜚声中外的综合性研究型大学，坐落在中国历史文化名城长沙。','湖南大学是中国历史最悠久的高等学府之一，国家"双一流""211工程""985工程"重点建设高校。学校起源于公元976年创建的岳麓书院，千年学府，弦歌不绝，是中国高等教育"活着的化石"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_073','中南大学','校园','["大学","教育","工医","材料","交通"]','["材料科学","医学科学","交通运输","矿物工程"]',4.4,699,2069,39.9577000,116.3577000,'湖南省长沙市麓山南路932号','校园参观时间：09:00-17:00（需预约）','uploads/images/中南大学.jpg','中南大学是一所以工学和医学为特长，涵盖理学、文学、法学、经济学、管理学、哲学、教育学、历史学、艺术学等10大学科门类的综合研究型大学。','中南大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校于2000年由原中南工业大学、湖南医科大学和长沙铁道学院合并组建，以工科和医科为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_074','湖南师范大学','校园','["大学","教育","师范","文学","历史"]','["师范教育","文学研究","历史学","教育科学"]',4.9,948,2103,39.9577000,116.3577000,'湖南省长沙市岳麓区麓山路36号','校园参观时间：09:00-17:00（需预约）','uploads/images/湖南师范大学.jpg','湖南师范大学是一所以师范教育著称、具有悠久历史的著名综合性师范大学。','湖南师范大学是湖南省属重点大学，国家"211工程"和"双一流"建设高校。学校前身是1938年创办的国立师范学院，是中国独立设置的八所师范院校之一，以师范教育和人文社会科学著称。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_075','中山大学','校园','["大学","教育","综合","医学","管理"]','["医学科学","管理学","哲学社科","理学研究"]',4.7,273,2760,39.9577000,116.3577000,'广东省广州市海珠区新港西路135号','校园参观时间：09:00-17:00（需预约）','uploads/images/中山大学.jpg','中山大学是一所包括人文科学、社会科学、自然科学、技术科学、工学、医学、药学、经济学和管理学等在内的综合性大学。','中山大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校由孙中山先生于1924年亲手创办，是中国南方最顶尖的综合性研究型大学之一，位列"华南第一学府"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_076','暨南大学','校园','["大学","教育","华侨","新闻","经济"]','["华侨教育","新闻传播","经济管理","医学教育"]',3.9,397,668,39.9577000,116.3577000,'广东省广州市天河区黄埔大道西601号','校园参观时间：09:00-17:00（需预约）','uploads/images/暨南大学.jpg','暨南大学是中国第一所由政府创办的华侨学府，是中央部属高校、全国重点大学。','暨南大学是中国第一所由国家创办的华侨高等学府，国家"211工程"和"双一流"建设高校，直属中央统战部管理。学校素有"华侨最高学府"之称，以服务海外华侨华人和港澳台同胞为办学使命。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_077','华南理工大学','校园','["大学","教育","理工","建筑","化工"]','["建筑工程","化学工程","材料科学","电子信息"]',4.8,908,2274,39.9577000,116.3577000,'广东省广州市天河区五山路381号','校园参观时间：09:00-17:00（需预约）','uploads/images/华南理工大学.jpg','华南理工大学是一所以工见长，理工结合，管、经、文、法、医等多学科协调发展的综合性研究型大学。','华南理工大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校以工科见长，在建筑学、轻工技术与工程、材料科学、食品科学与工程等领域享誉全国，是华南地区工科实力最强的高校。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_078','华南师范大学','校园','["大学","教育","师范","心理学","体育"]','["师范教育","心理学","体育科学","教育技术"]',4.1,1307,814,39.9577000,116.3577000,'广东省广州市天河区中山大道西55号','校园参观时间：09:00-17:00（需预约）','uploads/images/华南师范大学.jpg','华南师范大学是一所学科门类齐全的国家211工程重点建设大学，是广东省人民政府和教育部共建高校。','华南师范大学是广东省属重点大学，国家"211工程"和"双一流"建设高校。学校前身是1933年创办的广东省立勷勤大学师范学院，以师范教育和心理学著称，是华南地区最重要的师资培养基地。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_079','广西大学','校园','["大学","教育","综合","农业","工程"]','["农业科学","工程技术","文理并重","民族特色"]',3.6,614,2020,39.9577000,116.3577000,'广西壮族自治区南宁市西乡塘区大学东路100号','校园参观时间：09:00-17:00（需预约）','uploads/images/广西大学.jpg','广西大学是一所历史悠久的地方综合性大学，是广西办学历史最久、规模最大的综合性大学。','广西大学是广西壮族自治区属重点综合性大学，国家"211工程"和"双一流"建设高校。学校于1928年由马君武博士创办，是广西办学历史最悠久、规模最大的高等学府。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_080','海南大学','校园','["大学","教育","热带","海洋","旅游"]','["热带农业","海洋科学","旅游管理","法学教育"]',4.4,793,2713,39.9577000,116.3577000,'海南省海口市美兰区人民大道58号','校园参观时间：09:00-17:00（需预约）','uploads/images/海南大学.jpg','海南大学是一所综合性重点大学，是海南省人民政府与教育部、财政部共建高校。','海南大学是海南省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校于2007年由原海南大学和华南热带农业大学合并组建，以热带农业、海洋科学和旅游管理为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_081','华南农业大学','校园','["大学","教育","农业","生命科学","热带"]','["热带农业","生命科学","食品科学","园艺学"]',4.1,1446,2796,39.9577000,116.3577000,'广东省广州市天河区五山路483号','校园参观时间：09:00-17:00（需预约）','uploads/images/华南农业大学.jpg','华南农业大学是一所以农业科学和生命科学为优势，以热带亚热带区域农业研究为特色的全国重点大学。','华南农业大学是广东省属重点大学，国家"双一流"建设高校。学校前身是1909年创办的广东全省农事试验场附设农业讲习所，是中国高等农业教育的重要发祥地之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_082','重庆大学','校园','["大学","教育","综合","建筑","机械"]','["建筑工程","机械工程","电气工程","材料科学"]',4.5,279,1610,39.9577000,116.3577000,'重庆市沙坪坝区沙正街174号','校园参观时间：09:00-17:00（需预约）','uploads/images/重庆大学.jpg','重庆大学是一所国家教育部直属的全国重点大学，是国家211工程和985工程重点建设的高水平研究型综合性大学。','重庆大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校以工科见长，在建筑学、土木工程、电气工程、机械工程等领域享有盛誉，是西南地区实力最强的高校之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_083','西南大学','校园','["大学","教育","师范","农业","综合"]','["师范教育","农业科学","心理学","教育学"]',4.2,1164,2707,39.9577000,116.3577000,'重庆市北碚区天生路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/西南大学.jpg','西南大学是一所以师范教育为特色，农业科学为优势，文、理、工、经、法、教、管、艺等学科门类齐全的综合性大学。','西南大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校于2005年由原西南师范大学和西南农业大学合并组建，以师范教育和农业科学为两大支点。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_084','四川大学','校园','["大学","教育","综合","医学","文史"]','["医学科学","文史哲学","工程技术","基础科学"]',4.3,1125,1129,39.9577000,116.3577000,'四川省成都市武侯区一环路南一段24号','校园参观时间：09:00-17:00（需预约）','uploads/images/四川大学.jpg','四川大学是一所学科门类齐全、规模宏大、学术实力雄厚的综合性研究型大学。','四川大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校由原四川大学、成都科技大学和华西医科大学三所重点大学合并组建，是西南地区实力最强的综合性研究型大学。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_085','西南交通大学','校园','["大学","教育","交通","工程","铁路"]','["交通运输","土木工程","机械工程","电气工程"]',4.2,793,2764,39.9577000,116.3577000,'四川省成都市金牛区二环路北一段111号','校园参观时间：09:00-17:00（需预约）','uploads/images/西南交通大学.jpg','西南交通大学是一所以工为主，工、科、文、经、管、法等多学科协调发展的研究型大学。','西南交通大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校创建于1896年，前身是山海关北洋铁路官学堂，是中国近代交通工程高等教育的发源地，被誉为"东方康奈尔"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_086','电子科技大学','校园','["大学","教育","电子","信息","通信"]','["电子信息","通信工程","计算机","集成电路"]',3.7,1372,2713,39.9577000,116.3577000,'四川省成都市高新区西区西源大道2006号','校园参观时间：09:00-17:00（需预约）','uploads/images/电子科技大学.jpg','电子科技大学是一所完整覆盖整个电子类学科，以电子信息科学技术为核心，以工为主，理工渗透，理、工、管、文、医协调发展的多科性研究型大学。','电子科技大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校以电子信息科学技术为核心，在通信工程、计算机科学、网络安全、集成电路等领域享有"中国电子类高校的排头兵"之美誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_087','四川农业大学','校园','["大学","教育","农业","生物","科技"]','["农业科学","生物技术","动物科学","食品科学"]',3.8,230,1398,39.9577000,116.3577000,'四川省雅安市雨城区新康路46号','校园参观时间：09:00-17:00（需预约）','uploads/images/四川农业大学.jpg','四川农业大学是一所以生物科技为特色，农业科技为优势，多学科协调发展的国家211工程重点建设大学。','四川农业大学是四川省属重点大学，国家"211工程"和"双一流"建设高校。学校前身是1906年创办的四川通省农业学堂，以农业科学和生命科学为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_088','贵州大学','校园','["大学","教育","综合","民族","资源"]','["民族文化","资源环境","农业科学","工程技术"]',4.8,1224,2727,39.9577000,116.3577000,'贵州省贵阳市花溪区','校园参观时间：09:00-17:00（需预约）','uploads/images/贵州大学.jpg','贵州大学是一所具有人文精神和科学传统的综合性大学，是贵州省人民政府与教育部共建高校。','贵州大学是贵州省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校前身是1902年创办的贵州大学堂，是贵州省办学历史最悠久、综合实力最强的高等学府。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_089','云南大学','校园','["大学","教育","综合","民族","生态"]','["民族学","生态学","生物多样性","国际关系"]',5.0,700,2890,39.9577000,116.3577000,'云南省昆明市翠湖北路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/云南大学.jpg','云南大学是一所历史悠久、文化底蕴深厚、在国际上有影响力的中国著名大学。','云南大学是云南省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校始建于1922年，是中国西部边疆地区最早的综合性大学之一，以民族学和生态学为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_090','西藏大学','校园','["大学","教育","民族","藏学","高原"]','["藏学研究","民族文化","高原生态","藏医学"]',4.0,1102,2298,39.9577000,116.3577000,'西藏自治区拉萨市城关区江苏路36号','校园参观时间：09:00-17:00（需预约）','uploads/images/西藏大学.jpg','西藏大学是西藏自治区所属的综合性大学，是列入教育部直属高校序列的国家211工程重点建设大学。','西藏大学是西藏自治区属重点综合性大学，国家"211工程"和"双一流"建设高校。学校坐落在海拔3650米的雪域高原，是世界上海拔最高的"211工程"大学，以高原科学研究和藏族文化研究为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_091','西北大学','校园','["大学","教育","综合","地质","考古"]','["地质学","考古学","化学工程","经济学"]',4.0,1331,2583,39.9577000,116.3577000,'陕西省西安市碑林区太白北路229号','校园参观时间：09:00-17:00（需预约）','uploads/images/西北大学.jpg','西北大学是一所学科门类齐全的全国重点综合性大学。','西北大学是陕西省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校前身是1902年创办的陕西大学堂，以地质学和考古学闻名于世，是中国西北地区历史最悠久的高等学府之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_092','西安交通大学','校园','["大学","教育","理工","医学","管理"]','["机械工程","电气工程","医学科学","管理科学"]',4.1,647,808,39.9577000,116.3577000,'陕西省西安市碑林区咸宁西路28号','校园参观时间：09:00-17:00（需预约）','uploads/images/西安交通大学.jpg','西安交通大学是一所具有理工特色，涵盖理、工、医、经、管、文、法、哲、教、艺等10个学科门类的综合性研究型大学。','西安交通大学是教育部直属的全国重点大学，C9联盟成员，国家"双一流""211工程""985工程"重点建设高校。学校前身是1896年创办于上海的南洋公学，1956年主体西迁至西安，铸就了"胸怀大局、无私奉献、弘扬传统、艰苦创业"的西迁精神。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_093','西北工业大学','校园','["大学","教育","航空","航天","航海"]','["航空工程","航天技术","航海工程","材料科学"]',4.5,599,1579,39.9577000,116.3577000,'陕西省西安市碑林区友谊西路127号','校园参观时间：09:00-17:00（需预约）','uploads/images/西北工业大学.jpg','西北工业大学是一所以发展航空、航天、航海等领域人才培养和科学研究为特色的多科性、研究型、开放式大学。','西北工业大学是工业和信息化部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校以航空、航天、航海（"三航"）工程为鲜明特色，是中国唯一一所以同时发展三航工程教育和科研为特色的高校。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_094','西安电子科技大学','校园','["大学","教育","电子","信息","通信"]','["电子信息","通信工程","计算机","网络安全"]',4.1,1427,1913,39.9577000,116.3577000,'陕西省西安市雁塔区太白南路2号','校园参观时间：09:00-17:00（需预约）','uploads/images/西安电子科技大学.jpg','西安电子科技大学是一所以信息与电子学科为主，工、理、管、文多学科协调发展的全国重点大学。','西安电子科技大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校前身是1931年诞生于江西瑞金的中央军委无线电学校，是毛泽东等老一辈革命家亲手创建的第一所工程技术学校。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_095','长安大学','校园','["大学","教育","交通","公路","工程"]','["交通运输","公路工程","汽车工程","地质工程"]',5.0,1267,1101,39.9577000,116.3577000,'陕西省西安市南二环路中段','校园参观时间：09:00-17:00（需预约）','uploads/images/长安大学.jpg','长安大学是一所以工为主，理工结合，人文社会科学与基础医学协调发展的多科性大学。','长安大学是教育部直属的全国重点大学，国家"211工程"和"双一流"建设高校。学校于2000年由原西安公路交通大学、西安工程学院和西北建筑工程学院合并组建，以公路交通、地质工程和城乡建设为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_096','西北农林科技大学','校园','["大学","教育","农林","水利","生态"]','["农林科学","水土保持","生态环境","食品科学"]',4.0,231,755,39.9577000,116.3577000,'陕西省咸阳市杨陵区邰城路3号','校园参观时间：09:00-17:00（需预约）','uploads/images/西北农林科技大学.jpg','西北农林科技大学是一所以农林水学科为特色，多学科协调发展的全国重点大学。','西北农林科技大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校前身是1934年创办的国立西北农林专科学校，是中国西北地区最早的高等农业学府。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_097','兰州大学','校园','["大学","教育","综合","化学","大气"]','["化学科学","大气科学","草地农业","核科学"]',4.7,1164,1132,39.9577000,116.3577000,'甘肃省兰州市城关区天水南路222号','校园参观时间：09:00-17:00（需预约）','uploads/images/兰州大学.jpg','兰州大学是一所学科门类齐全、特色鲜明、历史悠久、声誉卓著的教育部直属全国重点综合性大学。','兰州大学是教育部直属的全国重点大学，国家"双一流""211工程""985工程"重点建设高校。学校前身是1909年创办的甘肃法政学堂，是中国西北地区最具实力的综合性研究型大学之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_098','青海大学','校园','["大学","教育","综合","高原","民族"]','["高原医学","农牧科学","盐湖化工","民族文化"]',4.0,1349,2305,39.9577000,116.3577000,'青海省西宁市城北区宁大路251号','校园参观时间：09:00-17:00（需预约）','uploads/images/青海大学.jpg','青海大学是一所以工、农、医、管四大学科为主干，其他学科协调发展的综合性大学。','青海大学是青海省属重点综合性大学，国家"211工程"和"双一流"建设高校。学校始建于1958年，位于青藏高原东北部，以高原生态环境科学研究和藏医药学为鲜明特色。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_099','宁夏大学','校园','["大学","教育","综合","民族","西部"]','["民族学","西部发展","农业科学","化学工程"]',4.9,729,2532,39.9577000,116.3577000,'宁夏回族自治区银川市西夏区贺兰山西路489号','校园参观时间：09:00-17:00（需预约）','uploads/images/宁夏大学.jpg','宁夏大学是一所学科门类齐全、办学特色鲜明的综合性大学。','宁夏大学是宁夏回族自治区属重点综合性大学，国家"211工程"和"双一流"建设高校。学校始建于1958年，以服务宁夏及西部少数民族地区经济社会发展为使命。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_100','新疆大学','校园','["大学","教育","综合","民族","丝路"]','["民族学","中亚研究","化学工程","纺织工程"]',4.4,630,534,39.9577000,116.3577000,'新疆维吾尔自治区乌鲁木齐市胜利路666号','校园参观时间：09:00-17:00（需预约）','uploads/images/新疆大学.jpg','新疆大学是一所有着悠久办学历史、光荣革命传统、鲜明办学特色的综合性大学。','新疆大学是新疆维吾尔自治区属重点综合性大学，国家"211工程"和"双一流"建设高校。学校前身是1924年创办的新疆俄文法政专门学校，是新疆办学历史最悠久、规模最大的高等学府。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_101','石河子大学','校园','["大学","教育","农业","兵团","边疆"]','["农业科学","兵团文化","边疆建设","医学教育"]',4.2,269,2880,39.9577000,116.3577000,'新疆维吾尔自治区石河子市北四路','校园参观时间：09:00-17:00（需预约）','uploads/images/石河子大学.jpg','石河子大学是一所以农为特色，涵盖经济、法学、教育、文学、历史、理学、工学、农学、医学、管理、艺术等学科门类的综合性大学。','石河子大学是新疆生产建设兵团属重点综合性大学，国家"211工程"和"双一流"建设高校。学校始建于1949年，诞生于中国人民解放军进军新疆的征程中，以服务兵团和边疆发展为己任。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_102','故宫博物院','景区','["故宫","北京","历史文化","皇宫","明清建筑"]','["世界文化遗产","明清皇宫","古建筑群","文物珍藏"]',4.8,15678,45636,39.9163000,116.3972000,'北京市东城区景山前街4号','08:30-17:00','uploads/images/102.jpg','北京故宫是中国明清两代的皇家宫殿，旧称紫禁城，是世界上现存规模最大、保存最为完整的木质结构古建筑之一。','故宫博物院是中国明清两代的皇家宫殿，旧称紫禁城，位于北京中轴线的中心，是世界上现存规模最大、保存最完整的古代木结构宫殿建筑群，也是联合国教科文组织认定的世界文化遗产。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_103','天坛公园','景区','["天坛","北京","祭天建筑","明清古迹","皇家园林"]','["世界文化遗产","祭天圣地","古建筑艺术","皇家园林"]',4.7,8934,23456,39.8822000,116.4066000,'北京市东城区天坛路甲1号','06:00-22:00','uploads/images/103.jpg','天坛是明清两朝皇帝祭天祈谷的圣地，是中国古代建筑艺术的杰作，体现了中国传统的宇宙观和建筑美学。','天坛公园是明清两代皇帝祭天、祈谷的场所，位于北京市东城区，占地约273万平方米，是世界文化遗产。天坛始建于明永乐十八年（1420年），其建筑设计精妙绝伦，蕴含着中国古代"天人合一"的哲学思想。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_104','颐和园','景区','["颐和园","北京","皇家园林","昆明湖","万寿山"]','["世界文化遗产","皇家园林","湖光山色","古典建筑"]',4.6,12567,34789,39.9998000,116.2754000,'北京市海淀区新建宫门路19号','06:30-18:00','uploads/images/104.jpg','颐和园是中国现存规模最大、保存最完整的皇家园林，被誉为皇家园林博物馆，展现了中国古典园林艺术的精华。','颐和园是中国现存规模最大、保存最完整的皇家园林，世界文化遗产，位于北京市海淀区，占地约290公顷。它由万寿山和昆明湖组成，以杭州西湖为蓝本，汲取江南园林的精华而建。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_105','八达岭长城','景区','["长城","北京","万里长城","明代建筑","世界奇迹"]','["世界文化遗产","万里长城","军事防御","历史遗迹"]',4.5,23456,67890,40.3598000,116.0148000,'北京市延庆区G6京藏高速58号出口','07:00-18:00','uploads/images/105.jpg','八达岭长城是明长城的精华部分，是万里长城的杰出代表，以其宏伟的景观、完善的设施和深厚的文化历史内涵而著称于世。','八达岭长城是明长城中保存最完好、最具代表性的一段，位于北京市延庆区，距市区约70公里，是世界文化遗产。"不到长城非好汉"说的就是这里。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_106','明十三陵','景区','["明十三陵","北京","皇家陵寝","明代历史","古建筑群"]','["世界文化遗产","皇家陵寝","明代建筑","历史文化"]',4.4,6789,18765,40.2914000,116.2348000,'北京市昌平区十三陵镇','08:00-17:30','uploads/images/106.jpg','明十三陵是明朝十三位皇帝的陵墓群，是中国现存规模最大、帝后陵寝最多的皇家陵墓建筑群。','明十三陵是明朝迁都北京后13位皇帝的陵寝群，位于北京市昌平区天寿山南麓，占地约120平方公里，是世界文化遗产。陵区群山环绕，水流蜿蜒，是中国古代帝王陵寝选址"风水"理论的典范之作。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_107','恭王府','景区','["恭王府","北京","王府建筑","清代府邸","古典园林"]','["清代王府","古典园林","历史建筑","文化遗产"]',4.3,5432,15678,39.9378000,116.3831000,'北京市西城区柳荫街甲14号','08:30-17:00','uploads/images/107.jpg','恭王府是清代规模最大的一座王府，曾经是和珅、永璘的宅邸，后为恭亲王奕訢的府邸，被称为什刹海的明珠。','恭王府是清代规模最大、保存最完整的一座王府，位于北京市西城区柳荫街，毗邻什刹海。它先后作为和珅和恭亲王奕欣的府邸，故有"一座恭王府，半部清代史"之说。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_108','奥林匹克公园','景区','["奥林匹克公园","北京","鸟巢","水立方","现代建筑"]','["奥运场馆","现代建筑","体育文化","城市地标"]',4.2,9876,28765,39.9928000,116.3906000,'北京市朝阳区北四环中路奥林匹克公园','全天开放','uploads/images/108.jpg','北京奥林匹克公园是2008年北京奥运会的主要场地，包含鸟巢、水立方等标志性建筑，是现代北京的重要地标。','奥林匹克公园是2008年北京奥运会和2022年北京冬奥会的主会场，位于北京市朝阳区北四环中路，是集体育赛事、文化展示、休闲观光于一体的城市公共空间，也是世界首个"双奥"园区的核心区域。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_109','圆明园','景区','["圆明园","北京","皇家园林","历史遗址","爱国教育"]','["皇家园林遗址","历史教育","文化遗产","爱国主义"]',4.1,7654,21234,40.0084000,116.2972000,'北京市海淀区清华西路28号','07:00-19:00','uploads/images/109.jpg','圆明园曾是清朝皇家园林，被誉为万园之园，虽遭破坏但遗址仍展现着昔日的辉煌，是重要的爱国主义教育基地。','圆明园是清代著名的皇家园林，位于北京市海淀区清华西路，毗邻颐和园，占地约350公顷。它由圆明园、长春园和绮春园三园组成，曾被誉为"万园之园"和"东方凡尔赛宫"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_110','天津古文化街','景区','["古文化街","天津","传统文化","民俗风情","津门故里"]','["传统文化","民俗风情","古建筑","特色商街"]',4.0,4321,12345,39.1467000,117.1767000,'天津市南开区古文化街','09:00-21:00','uploads/images/110.jpg','天津古文化街是津门十景之一，集旅游商贸、民俗文化、购物休闲、健身娱乐、餐饮住宿等功能于一体的综合性文化旅游区。','天津古文化街是天津最具代表性的历史文化街区之一，位于天津市南开区，全长约687米，是国家5A级旅游景区。这里是感受"津味儿"文化的最佳去处。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_111','盘山风景名胜区','景区','["盘山","天津","自然风光","佛教文化","山水景观"]','["自然风光","佛教文化","山水景观","历史古迹"]',4.2,3456,9878,40.0456000,117.2678000,'天津市蓟州区盘山风景名胜区','08:00-17:00','uploads/images/111.jpg','盘山风景名胜区以山水风光和名胜古迹并著，被誉为京东第一山，是自然山水与人文景观相结合的综合性旅游区。','盘山风景名胜区位于天津市蓟州区，距天津市区约120公里，是国家5A级旅游景区，素有"京东第一山"之美誉。乾隆皇帝曾32次巡游盘山，留下"早知有盘山，何必下江南"的感叹。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_112','山海关景区','景区','["山海关","河北","长城","天下第一关","历史要塞"]','["万里长城东端","天下第一关","军事要塞","历史文化"]',4.4,6789,19876,40.0056000,119.7756000,'河北省秦皇岛市山海关区','07:30-18:00','uploads/images/112.jpg','山海关是万里长城的东端起点，被誉为天下第一关，是长城沿线保存完好的重要关隘，具有重要的历史和军事价值。','山海关景区位于河北省秦皇岛市山海关区，是明长城东端的起点，素有"天下第一关"之称，是世界文化遗产。山海关北倚燕山，南临渤海，地势险要，历来是华北通往东北的咽喉要道。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_113','白洋淀景区','景区','["白洋淀","河北","湿地","水乡风情","生态旅游"]','["华北明珠","湿地生态","水乡风情","红色文化"]',4.1,5432,16791,38.9345000,115.9876000,'河北省保定市安新县白洋淀景区','08:00-18:00','uploads/images/113.jpg','白洋淀是华北地区最大的淡水湖泊，被誉为华北明珠，以其独特的湿地生态和水乡风情吸引着众多游客。','白洋淀景区位于河北省保定市安新县，是华北平原最大的淡水湖泊，总面积约366平方公里，由143个大小淀泊和3700多条沟壕组成，被誉为"华北明珠"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_114','承德避暑山庄','景区','["避暑山庄","承德","皇家园林","清代建筑","避暑胜地"]','["世界文化遗产","皇家园林","清代建筑","避暑胜地"]',4.6,11234,32456,40.9739000,117.9616000,'河北省承德市双桥区丽正门大街22号','08:00-17:30','uploads/images/114.jpg','承德避暑山庄是清代皇家园林，是中国现存占地最大的古代帝王宫苑，体现了中国古典园林艺术的最高成就。','承德避暑山庄是清代皇帝的夏宫，位于河北省承德市双桥区，占地约564万平方米，是中国现存最大的皇家园林，也是世界文化遗产。它始建于康熙四十二年（1703年），历经康熙、雍正、乾隆三代皇帝，耗时89年建成。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_115','野三坡景区','景区','["野三坡","河北","自然风光","峡谷景观","地质奇观"]','["自然风光","峡谷景观","地质奇观","生态旅游"]',4.3,7890,23459,39.6834000,115.4567000,'河北省保定市涞水县野三坡镇','08:00-17:00','uploads/images/115.jpg','野三坡是国家重点风景名胜区，以雄险的峡谷景观、奇特的地质构造和丰富的生态资源而闻名。','野三坡景区位于河北省保定市涞水县，地处太行山脉与燕山山脉交汇处，是国家5A级旅游景区，集雄、奇、险、秀于一体，被誉为"北方小桂林"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_116','西柏坡景区','景区','["西柏坡","河北","红色旅游","革命圣地","历史教育"]','["革命圣地","红色教育","历史文化","爱国主义"]',4.5,8765,25680,38.3456000,114.1234000,'河北省石家庄市平山县西柏坡镇','08:30-17:30','uploads/images/116.jpg','西柏坡是中国革命圣地，中共中央和毛主席在此指挥了震惊中外的辽沈、淮海、平津三大战役，被誉为新中国从这里走来。','西柏坡景区位于河北省石家庄市平山县，是中国革命圣地之一，被誉为"新中国从这里走来"的地方。1948年5月至1949年3月，中共中央和解放军总部在此驻扎，指挥了三大战役，召开了具有伟大历史意义的七届二中全会。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_117','云冈石窟','景区','["云冈石窟","山西","佛教石窟","古代艺术","文化遗产"]','["世界文化遗产","佛教石窟","古代艺术","北魏文化"]',4.7,13456,38767,40.1123000,113.1345000,'山西省大同市云冈区云冈镇','08:30-17:20','uploads/images/117.jpg','云冈石窟是中国四大石窟之一，代表了公元5至6世纪时中国杰出的佛教石窟艺术成就，是东方石雕艺术的精华。','云冈石窟是中国四大石窟之一，位于山西省大同市云冈区，依武周山南麓开凿，东西绵延约1公里，是世界文化遗产。石窟始凿于北魏和平年间（公元460年），历时约60年，距今已有1500多年历史。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_118','五台山风景名胜区','景区','["五台山","山西","佛教名山","文殊菩萨","宗教文化"]','["世界文化遗产","佛教圣地","文殊道场","古建筑群"]',4.6,12345,35678,39.0167000,113.5833000,'山西省忻州市五台县台怀镇','06:00-18:30','uploads/images/118.jpg','五台山是中国佛教四大名山之首，文殊菩萨的道场，拥有众多古刹名寺，是佛教文化的重要圣地。','五台山风景名胜区位于山西省忻州市五台县，是中国四大佛教名山之首，文殊菩萨的道场，也是世界文化遗产。五台山由东台望海峰、南台锦绣峰、西台挂月峰、北台叶斗峰和中台翠岩峰五座山峰环抱而成，其中北台海拔3061米，有"华北屋脊"之称。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_119','皇城相府','景区','["皇城相府","山西","明清建筑","古堡建筑","历史文化"]','["明清古建筑","古堡建筑群","历史文化","康熙字典"]',4.4,6789,19879,35.4567000,112.8901000,'山西省晋城市阳城县北留镇皇城村','08:00-18:00','uploads/images/119.jpg','皇城相府是清代文渊阁大学士陈廷敬的故居，是一处罕见的明清两代城堡式官宦住宅建筑群。','皇城相府位于山西省晋城市阳城县北留镇皇城村，是清代康熙朝名相陈廷敬的故居，国家5A级旅游景区。这座城堡式官宅建筑群始建于明宣德年间，占地约3.6万平方米，有"中国北方第一文化巨族之宅"的美誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_120','绵山景区','景区','["绵山","山西","自然风光","道教文化","寒食节"]','["自然风光","道教文化","寒食节起源","山水景观"]',4.2,5678,16791,36.8456000,111.7890000,'山西省晋中市介休市绵山镇','08:00-18:00','uploads/images/120.jpg','绵山是中国寒食节的发源地，以其秀美的自然风光和深厚的历史文化底蕴而著称，是道教文化的重要圣地。','绵山景区位于山西省晋中市介休市，是太岳山的一条支脉，也是寒食节（清明节）的起源地，国家5A级旅游景区。相传春秋时期，介子推携母隐居绵山，晋文公重耳为逼其出山而放火烧山，介子推宁死不从，抱树而亡，后人以此纪念而衍生出寒食节。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_121','平遥古城','景区','["平遥古城","山西","古城墙","明清建筑","金融文化"]','["世界文化遗产","古城墙","明清建筑","票号文化"]',4.5,9877,28767,37.1956000,112.1789000,'山西省晋中市平遥县','全天开放','uploads/images/121.jpg','平遥古城是保存最为完好的四大古城之一，展现了明清时期中国汉民族城市的完整画卷，是中国古代城市的活化石。','平遥古城位于山西省晋中市平遥县，是中国保存最完好的四大古城之一，也是世界文化遗产。古城始建于西周宣王时期（约公元前827年），现存城墙为明洪武三年（1370年）扩建，距今已有600多年历史。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_122','响沙湾旅游景区','景区','["响沙湾","内蒙古","沙漠旅游","响沙奇观","生态体验"]','["沙漠奇观","响沙现象","生态旅游","民族文化"]',4.3,7654,22345,40.1234000,109.8765000,'内蒙古自治区鄂尔多斯市达拉特旗响沙湾','08:00-18:00','uploads/images/122.jpg','响沙湾是中国著名的沙漠旅游胜地，以神奇的响沙现象和丰富的沙漠娱乐项目而闻名，是体验蒙古族文化的绝佳场所。','响沙湾旅游景区位于内蒙古自治区鄂尔多斯市达拉特旗，地处库布其沙漠东端，因"这里的沙子会唱歌"而闻名，是国家5A级旅游景区。从沙丘上滑下时，沙粒会发出嗡嗡响声，如同交响乐一般奇妙。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_123','成吉思汗陵旅游区','景区','["成吉思汗陵","内蒙古","蒙古文化","历史名人","草原风情"]','["蒙古文化","历史纪念","草原风光","民族风情"]',4.4,8901,26790,39.5678000,109.2345000,'内蒙古自治区鄂尔多斯市伊金霍洛旗成吉思汗陵','08:00-18:30','uploads/images/123.jpg','成吉思汗陵是蒙古族人民心中的圣地，展现了一代天骄成吉思汗的丰功伟绩和蒙古民族的灿烂文化。','成吉思汗陵旅游区位于内蒙古自治区鄂尔多斯市伊金霍洛旗，是蒙古族人民心中的圣地，国家5A级旅游景区。成吉思汗陵是成吉思汗的衣冠冢，其真正的陵墓至今仍是一个千古之谜。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_124','沈阳植物园','景区','["植物园","沈阳","生态旅游","植物科普","休闲观光"]','["植物科普","生态教育","休闲观光","四季花卉"]',4.2,6543,18765,41.7345000,123.4567000,'辽宁省沈阳市浑南区双园路301号','08:00-17:00','uploads/images/124.jpg','沈阳植物园是集科研、科普、休闲、娱乐为一体的综合性植物园，拥有丰富的植物资源和优美的园林景观。','沈阳植物园位于辽宁省沈阳市浑南区，又称沈阳世博园，是2006年沈阳世界园艺博览会的举办地，国家5A级旅游景区。园区占地246公顷，汇集了世界各地的奇花异木，是东北地区规模最大的植物园。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_125','大连老虎滩海洋公园','景区','["老虎滩","大连","海洋公园","海洋动物","亲子旅游"]','["海洋动物","科普教育","亲子娱乐","海洋文化"]',4.5,11234,33456,38.8567000,121.5678000,'辽宁省大连市中山区滨海中路9号','08:00-17:00','uploads/images/125.jpg','大连老虎滩海洋公园是中国最大的现代化海滨游乐场，以丰富的海洋动物表演和海洋科普教育而著称。','大连老虎滩海洋公园位于辽宁省大连市中山区海滨，是中国最大的现代化海洋主题公园之一，国家5A级旅游景区。公园依山傍海，将海洋动物展示、科普教育和娱乐休闲完美结合。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_126','金石滩景区','景区','["金石滩","大连","海滨风光","地质奇观","度假胜地"]','["海滨风光","地质奇观","度假休闲","海蚀地貌"]',4.3,7890,23456,39.0123000,121.9876000,'辽宁省大连市金州区金石滩国家旅游度假区','08:00-17:30','uploads/images/126.jpg','金石滩以其奇特的海蚀地貌和优美的海滨风光而闻名，被誉为神力雕塑公园和天然地质博物馆。','金石滩景区位于辽宁省大连市金州区，是国家5A级旅游景区，以奇特的海蚀地貌和金色沙滩而闻名。金石滩海岸线长约30公里，沙滩宽阔平缓，沙质金黄细腻，踩上去软如棉毯。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_127','伪满皇宫博物院','景区','["伪满皇宫","长春","历史教育","近代史","爱国主义"]','["历史教育","近代史迹","爱国主义","文物展示"]',4.4,8765,25678,43.9123000,125.3456000,'吉林省长春市宽城区光复北路5号','08:30-17:00','uploads/images/127.jpg','伪满皇宫博物院是中国现存的三大宫廷遗址之一，见证了中国近代史上一段特殊的历史时期。','伪满皇宫博物院位于吉林省长春市宽城区，是中国末代皇帝爱新觉罗·溥仪充当伪满洲国傀儡皇帝时的宫廷遗址，国家5A级旅游景区。这里见证了日本侵华和伪满洲国那段屈辱的历史。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_128','长白山景区','景区','["长白山","吉林","天池","火山地貌","自然保护区"]','["天池奇观","火山地貌","原始森林","生物多样性"]',4.7,15678,45632,42.0167000,128.0833000,'吉林省白山市抚松县长白山保护开发区','07:00-16:00','uploads/images/128.jpg','长白山是中国东北第一高峰，以天池、瀑布、温泉、原始森林等自然景观而闻名，是重要的生态旅游目的地。','长白山景区位于吉林省白山市抚松县，是松花江、图们江和鸭绿江三江之源，也是中国东北最高峰，国家5A级旅游景区，联合国教科文组织人与生物圈保护区。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_129','净月潭景区','景区','["净月潭","长春","森林公园","人工湖泊","生态旅游"]','["森林公园","人工湖泊","生态旅游","休闲度假"]',4.1,5432,16791,43.7890000,125.4567000,'吉林省长春市南关区净月大街5840号','06:00-18:00','uploads/images/129.jpg','净月潭是亚洲最大的人工森林公园，以其优美的湖光山色和清新的空气而成为长春市民休闲度假的首选之地。','净月潭景区位于吉林省长春市南关区，被誉为"亚洲最大的人工森林"，国家5A级旅游景区。净月潭是一座建于1935年的水库，因水潭形状如弯月而得名，周围被约100平方公里的森林环抱。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_130','太阳岛景区','景区','["太阳岛","哈尔滨","湿地公园","冰雪文化","休闲度假"]','["湿地公园","冰雪文化","休闲度假","生态观光"]',4.2,6789,19876,45.7890000,126.6234000,'黑龙江省哈尔滨市松北区太阳岛风景区','08:00-17:00','uploads/images/130.jpg','太阳岛是哈尔滨著名的风景区，以其独特的湿地景观、冰雪文化和俄罗斯风情而吸引着众多游客。','太阳岛景区位于黑龙江省哈尔滨市松北区，是松花江上的一座河岛，国家5A级旅游景区。它以湿地生态和冰雪文化著称，因郑绪岚的一曲《太阳岛上》而闻名全国。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_131','五大连池景区','景区','["五大连池","黑龙江","火山地质","矿泉疗养","地质公园"]','["火山地质","矿泉疗养","地质奇观","生态保护"]',4.3,7654,22345,48.7123000,126.1456000,'黑龙江省黑河市五大连池市五大连池镇','08:00-17:00','uploads/images/131.jpg','五大连池是世界地质公园，以其独特的火山地貌、神奇的矿泉水和完整的火山地质景观而闻名于世。','五大连池景区位于黑龙江省黑河市五大连池市，是中国最年轻的火山群之一，世界地质公园。因火山喷发堵塞河道形成了五个串珠状的堰塞湖——五大连池，景色壮美绝伦。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_132','东方明珠广播电视塔','景区','["东方明珠","上海","电视塔","城市地标","观光塔"]','["城市地标","观光塔","现代建筑","夜景观赏"]',4.4,18765,56789,31.2397000,121.4997000,'上海市浦东新区世纪大道1号','08:00-21:30','uploads/images/132.jpg','东方明珠广播电视塔是上海的标志性建筑，以其独特的设计和壮观的城市景观而成为游客必访的景点。','东方明珠广播电视塔位于上海市浦东新区陆家嘴，高468米，是上海的标志性建筑之一，国家5A级旅游景区。它于1995年建成，曾是亚洲第一高塔，与对岸的外滩万国建筑群隔江相望。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_133','上海野生动物园','景区','["野生动物园","上海","动物保护","科普教育","亲子旅游"]','["野生动物","科普教育","亲子娱乐","动物保护"]',4.3,12345,36789,31.0456000,121.6789000,'上海市浦东新区南六公路178号','08:00-17:00','uploads/images/133.jpg','上海野生动物园是中国首座国家级野生动物园，以其丰富的动物种类和先进的饲养理念而闻名。','上海野生动物园位于上海市浦东新区南六公路，占地2300余亩，是中国首座国家级野生动物园，国家5A级旅游景区。这里汇集了来自世界各地的200余种、万余头（只）珍稀动物。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_134','上海科技馆','景区','["科技馆","上海","科普教育","现代科技","互动体验"]','["科普教育","互动体验","现代科技","寓教于乐"]',4.5,15678,45632,31.2231000,121.5456000,'上海市浦东新区世纪大道2000号','09:00-17:15','uploads/images/134.jpg','上海科技馆是中国重要的科普教育基地，以其丰富的科技展品和互动体验项目而深受游客喜爱。','上海科技馆位于上海市浦东新区世纪大道，与上海博物馆、上海图书馆并称上海三大文化设施，国家5A级旅游景区。它以"自然·人·科技"为主题，是一座集科普教育、学术交流、休闲旅游于一体的现代化科技馆。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_135','钟山风景名胜区','景区','["钟山","南京","中山陵","历史文化","陵园建筑"]','["历史文化","陵园建筑","自然风光","爱国教育"]',4.6,13456,39876,32.0678000,118.8456000,'江苏省南京市玄武区石象路7号','06:30-18:30','uploads/images/135.jpg','钟山风景名胜区以中山陵为核心，是纪念孙中山先生的重要场所，体现了中国近代建筑艺术的精华。','钟山风景名胜区位于江苏省南京市玄武区，以紫金山（钟山）为中心，占地约45平方公里，是国家5A级旅游景区。景区融山、水、城、林于一体，人文景观与自然风光交相辉映。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_136','夫子庙秦淮风光带','景区','["夫子庙","南京","秦淮河","古建筑","文化街区"]','["古建筑群","文化街区","秦淮风光","民俗文化"]',4.2,9876,28766,32.0234000,118.7890000,'江苏省南京市秦淮区夫子庙街道','全天开放','uploads/images/136.jpg','夫子庙秦淮风光带是南京历史文化荟萃之地，以其深厚的文化底蕴和独特的水乡风情而著称。','夫子庙秦淮风光带位于江苏省南京市秦淮区，以夫子庙和秦淮河为核心，融历史古迹、民俗文化和美食购物于一体，是国家5A级旅游景区，也是南京最负盛名的旅游地标。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_137','无锡影视基地三国水浒景区','景区','["影视基地","无锡","三国","水浒","古装拍摄"]','["影视拍摄","古装体验","文化娱乐","主题公园"]',4.1,7654,22345,31.4567000,120.2345000,'江苏省无锡市滨湖区山水西路128号','08:00-17:00','uploads/images/137.jpg','无锡影视基地是中国最早的影视拍摄基地之一，以其精美的古建筑和丰富的影视文化而闻名。','无锡影视基地三国水浒景区位于江苏省无锡市滨湖区太湖之滨，是央视87版《三国演义》和98版《水浒传》的主要拍摄地，也是中国最早、最成功的影视旅游基地之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_138','灵山大佛景区','景区','["灵山大佛","无锡","佛教文化","青铜大佛","宗教旅游"]','["佛教文化","青铜大佛","宗教艺术","心灵净化"]',4.5,11234,33456,31.4123000,120.1789000,'江苏省无锡市滨湖区马山镇灵山路1号','07:00-17:30','uploads/images/138.jpg','灵山大佛是世界最高的青铜释迦牟尼立像，以其庄严神圣的佛教文化和壮观的建筑群而成为重要的宗教旅游胜地。','灵山大佛景区位于江苏省无锡市滨湖区马山镇，依秦履峰而建，面朝太湖，国家5A级旅游景区。景区以88米高的灵山大佛铜像为核心，是世界上最高的露天青铜立佛之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_139','鼋头渚景区','景区','["鼋头渚","无锡","太湖","樱花","湖光山色"]','["太湖风光","樱花胜地","湖光山色","自然美景"]',4.4,10987,31234,31.5234000,120.2678000,'江苏省无锡市滨湖区鼋渚路1号','08:00-17:00','uploads/images/139.jpg','鼋头渚是太湖风景的精华所在，以其秀美的湖光山色和浪漫的樱花而被誉为太湖第一名胜。','鼋头渚景区位于江苏省无锡市滨湖区太湖之滨，是太湖风景的精华所在，国家5A级旅游景区。"太湖佳绝处，毕竟在鼋头"——郭沫若的这句诗就是对鼋头渚最好的概括。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_140','苏州园林','景区','["苏州园林","苏州","古典园林","拙政园","江南文化"]','["古典园林","江南文化","园林艺术","文化遗产"]',4.7,16789,48765,31.3123000,120.6234000,'江苏省苏州市姑苏区东北街178号','07:30-17:30','uploads/images/140.jpg','苏州园林是中国古典园林的杰出代表，以其精巧的设计和深厚的文化内涵而被誉为园林之母。','苏州园林是苏州古城内众多古典园林的总称，是世界文化遗产。苏州园林始于春秋、盛于明清，以"咫尺之内再造乾坤"的造园艺术闻名于世。其中最著名的包括拙政园、留园、虎丘和狮子林等。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_141','周庄古镇','景区','["周庄","苏州","古镇","水乡","江南风情"]','["古镇风貌","水乡文化","江南风情","民俗体验"]',4.3,8765,25678,31.1156000,120.8456000,'江苏省苏州市昆山市周庄镇全福路43号','08:00-21:00','uploads/images/141.jpg','周庄古镇是中国第一水乡，以其完整的明清建筑群和独特的水乡风情而成为江南古镇的典型代表。','周庄古镇位于江苏省苏州市昆山市，始建于北宋元祐元年（1086年），是中国第一水乡，国家5A级旅游景区。古镇四面环水，以河成街，桥街相连，完整保留了明清时期的江南水乡风貌。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_142','杭州西湖风景名胜区','景区','["西湖","杭州","湖光山色","古典园林","人文景观"]','["世界文化遗产","湖光山色","古典园林","人文景观"]',4.8,25678,78907,30.2741000,120.1551000,'浙江省杭州市西湖区龙井路1号','全天开放','uploads/images/142.jpg','杭州西湖以其秀丽的湖光山色和众多的名胜古迹闻名中外，是中国著名的旅游胜地，被誉为人间天堂。','杭州西湖风景名胜区位于浙江省杭州市西湖区，是中国最负盛名的湖泊风景区之一，世界文化遗产。西湖三面环山，一面临城，湖面约6.39平方公里，"欲把西湖比西子，淡妆浓抹总相宜"是苏轼对它的完美写照。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_143','雁荡山风景名胜区','景区','["雁荡山","温州","奇峰异石","瀑布群","地质奇观"]','["奇峰异石","瀑布群","地质奇观","自然美景"]',4.5,12345,36789,28.3567000,121.0789000,'浙江省温州市乐清市雁荡镇','07:00-17:30','uploads/images/143.jpg','雁荡山以其奇峰怪石、飞瀑流泉而闻名，被誉为海上名山、寰中绝胜，是中国十大名山之一。','雁荡山风景名胜区位于浙江省温州市乐清市，以奇峰、怪石、飞瀑、幽洞著称，被誉为"东南第一山"，是世界地质公园，也是中国十大名山之一。"欲写龙湫难着笔，不游雁荡是虚生"——徐霞客对雁荡山的赞誉流传至今。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_144','普陀山风景名胜区','景区','["普陀山","舟山","佛教名山","观音道场","海岛风光"]','["佛教圣地","观音道场","海岛风光","宗教文化"]',4.6,14567,42345,29.9789000,122.3890000,'浙江省舟山市普陀区普陀山镇','06:00-18:00','uploads/images/144.jpg','普陀山是中国佛教四大名山之一，观音菩萨的道场，以其神圣的佛教文化和秀美的海岛风光而闻名。','普陀山风景名胜区位于浙江省舟山市，是舟山群岛中的一个小岛，面积约12.5平方公里。它是中国四大佛教名山之一，观世音菩萨的道场，素有"海天佛国"之美誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_145','黄山风景名胜区','景区','["黄山","安徽","奇松怪石","云海温泉","自然奇观"]','["世界自然遗产","奇松怪石","云海温泉","自然奇观"]',4.7,18765,56789,30.1167000,118.1667000,'安徽省黄山市黄山区汤口镇','06:00-17:30','uploads/images/145.jpg','黄山以奇松、怪石、云海、温泉四绝著称于世，被誉为天下第一奇山，是中国山水画的重要源泉。','黄山风景名胜区位于安徽省黄山市，是中国最负盛名的山岳风景区之一，世界文化与自然双重遗产，世界地质公园。"五岳归来不看山，黄山归来不看岳"——徐霞客的这句诗道尽了黄山的非凡魅力。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_146','九华山风景名胜区','景区','["九华山","池州","佛教名山","地藏道场","古寺庙群"]','["佛教圣地","地藏道场","古寺庙群","山水风光"]',4.4,9876,28765,30.4789000,117.8012000,'安徽省池州市青阳县九华山镇','07:00-17:00','uploads/images/146.jpg','九华山是中国佛教四大名山之一，地藏菩萨的道场，以其深厚的佛教文化和秀美的山水风光而著称。','九华山风景名胜区位于安徽省池州市青阳县，是中国四大佛教名山之一，地藏菩萨的道场。九华山因有九座山峰形似莲花而得名，山中古刹林立，现存寺院90余座，佛像万余尊，佛教文化积淀极为深厚。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_147','鼓浪屿风景名胜区','景区','["鼓浪屿","厦门","海岛风光","万国建筑","音乐之岛"]','["海岛风光","万国建筑","音乐文化","历史街区"]',4.5,13456,39876,24.4456000,118.0678000,'福建省厦门市思明区鼓浪屿','全天开放','uploads/images/147.jpg','鼓浪屿是厦门的海上花园，以其独特的万国建筑风格和浓厚的音乐文化氛围而成为著名的旅游胜地。','鼓浪屿风景名胜区位于福建省厦门市思明区，是厦门湾中的一座小岛，面积约1.88平方公里，世界文化遗产。岛上禁止机动车辆通行，保留了完整的清末民初建筑风貌和优雅的生活氛围，被誉为"海上花园"和"钢琴之岛"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_148','武夷山风景名胜区','景区','["武夷山","南平","丹霞地貌","九曲溪","茶文化"]','["世界自然遗产","丹霞地貌","九曲溪","茶文化"]',4.6,11234,33456,27.7567000,117.9890000,'福建省南平市武夷山市武夷山国家旅游度假区','08:00-17:00','uploads/images/148.jpg','武夷山以其典型的丹霞地貌、清澈的九曲溪水和深厚的茶文化而闻名，是自然与文化的完美结合。','武夷山风景名胜区位于福建省南平市武夷山市，世界文化与自然双重遗产，世界人与生物圈保护区。武夷山以丹霞地貌、碧水清流和深厚的茶文化闻名，是中国十大名山之一。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_149','庐山风景名胜区','景区','["庐山","九江","避暑胜地","瀑布群","文化名山"]','["避暑胜地","瀑布群","文化名山","历史遗迹"]',4.4,10987,31234,29.5789000,115.9876000,'江西省九江市庐山市庐山风景区','07:00-18:00','uploads/images/149.jpg','庐山以其秀美的自然风光、凉爽的气候和深厚的文化底蕴而成为著名的避暑胜地和文化名山。','庐山风景名胜区位于江西省九江市，北临长江，东濒鄱阳湖，是世界文化景观遗产、世界地质公园。庐山以雄、奇、险、秀闻名，是中国山水文化名山的杰出代表。"不识庐山真面目，只缘身在此山中"——苏东坡的这一千古名句让庐山家喻户晓。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_150','井冈山风景名胜区','景区','["井冈山","吉安","红色旅游","革命圣地","自然风光"]','["革命圣地","红色教育","自然风光","历史文化"]',4.5,12345,36791,26.5890000,114.1567000,'江西省吉安市井冈山市茨坪镇','08:00-17:00','uploads/images/150.jpg','井冈山是中国革命的摇篮，以其光荣的革命历史和秀美的自然风光而成为重要的红色旅游胜地。','井冈山风景名胜区位于江西省吉安市井冈山市，是中国革命的摇篮，中国第一个农村革命根据地的诞生地，被誉为"天下第一山"。这里自然风光与红色文化完美融合。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_151','蓬莱阁旅游区','景区','["蓬莱阁","烟台","海上仙境","古建筑群","神话传说"]','["海上仙境","古建筑群","神话传说","海滨风光"]',4.3,8765,25678,37.8234000,120.7567000,'山东省烟台市蓬莱区迎宾路7号','07:30-18:00','uploads/images/151.jpg','蓬莱阁素有海上仙境之称，以其神奇的海市蜃楼奇观和深厚的神话文化而成为著名的旅游胜地。','蓬莱阁旅游区位于山东省烟台市蓬莱区，雄踞丹崖山巅，面朝黄海和渤海交汇处，是中国古代四大名楼之一，国家5A级旅游景区。它以"人间仙境"和"八仙过海"的传说而闻名天下。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_152','三孔景区','景区','["三孔","济宁","孔庙","孔府","孔林"]','["世界文化遗产","儒家文化","古建筑群","文化教育"]',4.6,14567,42345,35.5890000,116.9876000,'山东省济宁市曲阜市静轩西路46号','08:00-17:30','uploads/images/152.jpg','三孔景区是孔子故里，包括孔庙、孔府、孔林，是中国儒家文化的发源地和重要的文化教育基地。','三孔景区位于山东省济宁市曲阜市，是中国历代纪念孔子、推崇儒学的圣地，由孔庙、孔府和孔林三部分组成，世界文化遗产。这里是儒家文化的发源地，被誉为"东方圣城"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_153','泰山风景名胜区','景区','["泰山","泰安","五岳之首","日出奇观","文化名山"]','["世界自然遗产","五岳之首","日出奇观","文化名山"]',4.7,19876,58765,36.2567000,117.1234000,'山东省泰安市泰山区红门路45号','全天开放','uploads/images/153.jpg','泰山是五岳之首，以其雄伟壮观的自然景色和深厚的文化底蕴而被誉为中华民族的象征。','泰山风景名胜区位于山东省泰安市，是五岳之首——东岳，被誉为"天下第一山"，世界文化与自然双重遗产。泰山自古被视为帝王封禅的神山，"登泰山而小天下"承载了中国人对崇高境界的精神追求。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_154','嵩山少林景区','景区','["少林寺","登封","武术文化","佛教文化","古建筑"]','["武术文化","佛教文化","古建筑群","功夫表演"]',4.5,16789,48765,34.5123000,113.0456000,'河南省郑州市登封市嵩山少林景区','08:00-17:00','uploads/images/154.jpg','嵩山少林景区是中国武术的发源地，以其深厚的武术文化和佛教文化而闻名于世。','嵩山少林景区位于河南省郑州市登封市，包含少林寺和嵩山两大核心部分，是世界文化遗产、世界地质公园。嵩山为五岳之中岳，少林寺则是禅宗祖庭和少林武术的发源地，有"天下第一名刹"之誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_155','龙门石窟','景区','["龙门石窟","洛阳","佛教石窟","石刻艺术","文化遗产"]','["世界文化遗产","佛教石窟","石刻艺术","古代文化"]',4.6,13456,39876,34.5567000,112.4789000,'河南省洛阳市洛龙区龙门中街13号','08:00-18:00','uploads/images/155.jpg','龙门石窟是中国四大石窟之一，以其精美的石刻艺术和深厚的佛教文化而成为世界文化遗产。','龙门石窟是中国四大石窟之一，位于河南省洛阳市洛龙区，伊河两岸的龙门山和香山之上，南北绵延约1公里，是世界文化遗产。石窟始凿于北魏孝文帝迁都洛阳前后（约公元493年），之后历经东魏、西魏、北齐、隋唐、五代等朝代连续大规模营造达400余年。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_156','云台山风景名胜区','景区','["云台山","焦作","红石峡","瀑布群","地质公园"]','["地质公园","红石峡","瀑布群","自然奇观"]',4.4,11234,33456,35.4123000,113.4567000,'河南省焦作市修武县云台山镇','07:00-18:00','uploads/images/156.jpg','云台山以其独特的地质地貌、壮观的瀑布群和秀美的山水风光而成为著名的地质公园。','云台山风景名胜区位于河南省焦作市修武县，是国家5A级旅游景区、世界地质公园。云台山以独特的红石峡丹霞地貌和北方罕见的瀑布群闻名，被誉为"北方山水之冠"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_157','南岳衡山','景区','["衡山","衡阳","五岳之一","道教文化","祝融峰"]','["五岳之一","道教文化","祝融峰","宗教圣地"]',4.3,9876,28765,27.2345000,112.6789000,'湖南省衡阳市南岳区南岳镇','08:00-17:00','uploads/images/157.jpg','南岳衡山是五岳之一，以其秀美的自然风光和深厚的道教文化而成为重要的宗教圣地。','南岳衡山位于湖南省衡阳市南岳区，是五岳之一——南岳，以"独秀"名世。衡山山势雄伟，绵延800里，72峰中以祝融峰最高，海拔1300.2米，茂密的森林和丰富的宗教文化使其成为道教圣地和佛教名山。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_158','张家界武陵源风景名胜区','景区','["张家界","武陵源","石柱群","天门山","自然奇观"]','["世界自然遗产","石柱群","天门山","自然奇观"]',4.8,23456,68902,29.3456000,110.4789000,'湖南省张家界市武陵源区金鞭路279号','07:00-18:00','uploads/images/158.jpg','张家界武陵源以其独特的石英砂岩峰林地貌和壮观的自然景观而成为世界自然遗产。','张家界武陵源风景名胜区位于湖南省张家界市武陵源区，是世界自然遗产、世界地质公园，也是《阿凡达》电影"哈利路亚山"的原型地。这里以独特的石英砂岩峰林地貌著称，三千多座石峰拔地而起，如刀削斧劈，蔚为壮观。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_159','三峡大坝旅游区','景区','["三峡大坝","宜昌","水利工程","长江三峡","现代奇迹"]','["水利工程","长江三峡","现代奇迹","科技成就"]',4.2,8765,25678,30.8234000,111.0012000,'湖北省宜昌市夷陵区三斗坪镇','08:00-17:30','uploads/images/159.jpg','三峡大坝是世界最大的水利枢纽工程，展现了中国现代水利建设的伟大成就。','三峡大坝旅游区位于湖北省宜昌市夷陵区，是当今世界上最大的水利枢纽工程，国家5A级旅游景区。三峡大坝集防洪、发电、航运功能于一体，是人类工程史上的一大奇迹。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_160','黄鹤楼公园','景区','["黄鹤楼","武汉","江南名楼","长江文化","诗词文化"]','["江南名楼","长江文化","诗词文化","历史建筑"]',4.4,12345,36789,30.5456000,114.2890000,'湖北省武汉市武昌区蛇山西坡特1号','08:00-18:00','uploads/images/160.jpg','黄鹤楼是江南三大名楼之一，以其深厚的历史文化底蕴和优美的诗词文化而闻名。','黄鹤楼公园位于湖北省武汉市武昌区蛇山之上，临长江而建，是中国古代四大名楼之一，享有"天下绝景"之盛誉。黄鹤楼因唐代诗人崔颢的《黄鹤楼》一诗名扬千古："昔人已乘黄鹤去，此地空余黄鹤楼。"
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_161','长隆旅游度假区','景区','["长隆","广州","主题公园","野生动物","亲子娱乐"]','["主题公园","野生动物","亲子娱乐","现代游乐"]',4.5,18765,56791,23.0012000,113.3456000,'广东省广州市番禺区汉溪大道东299号','09:30-18:00','uploads/images/161.jpg','长隆旅游度假区是中国著名的主题公园，以其丰富的娱乐项目和野生动物展示而深受游客喜爱。','长隆旅游度假区位于广东省广州市番禺区，是中国最顶级的综合性主题旅游度假区之一，国家5A级旅游景区。度假区汇集了长隆野生动物世界、长隆欢乐世界、长隆水上乐园、长隆国际大马戏和长隆飞鸟乐园等多个主题园区。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_162','丹霞山风景名胜区','景区','["丹霞山","韶关","丹霞地貌","红石奇观","地质公园"]','["世界自然遗产","丹霞地貌","红石奇观","地质公园"]',4.4,11234,33456,24.9876000,113.7234000,'广东省韶关市仁化县丹霞山镇','08:00-17:30','uploads/images/162.jpg','丹霞山是世界丹霞地貌的命名地，以其独特的红色砂岩地貌和壮观的自然景观而闻名。','丹霞山风景名胜区位于广东省韶关市仁化县，是世界自然遗产、世界地质公园。丹霞山是中国"丹霞地貌"的命名地——世界上所有类似的红层地貌都以"丹霞"命名，其特殊的地质构造和赤壁丹崖的壮美景观令人叹服。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_163','白云山风景名胜区','景区','["白云山","广州","城市绿肺","自然风光","休闲登山"]','["城市绿肺","自然风光","休闲登山","空气清新"]',4.2,8765,25680,23.1789000,113.2890000,'广东省广州市白云区白云大道南685号','06:00-18:00','uploads/images/163.jpg','白云山是广州的城市绿肺，以其清新的空气和优美的自然风光而成为市民休闲健身的好去处。','白云山风景名胜区位于广东省广州市白云区，是南粤名山之一，自古有"羊城第一秀"的称号。白云山由30多座山峰组成，主峰摩星岭海拔382米，是广州城区的最高点，登顶可俯瞰广州全城风貌。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_164','青秀山旅游区','景区','["青秀山","南宁","城市公园","植物园","休闲观光"]','["城市公园","植物园","休闲观光","文化景观"]',4.1,6789,19876,22.8234000,108.3567000,'广西壮族自治区南宁市青秀区凤岭南路6号','06:00-24:00','uploads/images/164.jpg','青秀山是南宁市的城市名片，以其丰富的植物资源和优美的园林景观而成为重要的旅游景区。','青秀山旅游区位于广西壮族自治区南宁市青秀区，是南宁市最著名的城市风景名胜区，国家5A级旅游景区。青秀山濒临邕江，由青山岭和凤凰岭等18座山峰组成，海拔最高289米。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_165','漓江风景名胜区','景区','["漓江","桂林","山水甲天下","喀斯特地貌","竹筏漂流"]','["山水甲天下","喀斯特地貌","竹筏漂流","自然美景"]',4.7,18765,56789,25.2890000,110.2345000,'广西壮族自治区桂林市秀峰区漓江路','07:00-18:00','uploads/images/165.jpg','漓江以桂林山水甲天下而闻名，其独特的喀斯特地貌和秀美的山水风光吸引着世界各地的游客。','漓江风景名胜区位于广西壮族自治区桂林市，是中国最具代表性的喀斯特山水风光胜地，世界自然遗产。漓江发源于兴安县猫儿山，流经桂林、阳朔，全长约164公里，其中最精华的是桂林至阳朔的83公里水路。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_166','乐山大佛景区','景区','["乐山大佛","乐山","石刻大佛","佛教文化","世界遗产"]','["世界文化遗产","石刻大佛","佛教文化","古代艺术"]',4.5,14567,42345,29.5456000,103.7890000,'四川省乐山市市中区凌云路2435号','07:30-18:30','uploads/images/166.jpg','乐山大佛是世界最大的石刻弥勒佛坐像，以其宏伟的规模和精湛的雕刻艺术而成为世界文化遗产。','乐山大佛景区位于四川省乐山市市中区，大佛开凿于唐代开元元年（713年），完成于贞元十九年（803年），历时90年，是世界最大的石刻弥勒佛坐像，世界文化与自然双重遗产。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_167','峨眉山风景名胜区','景区','["峨眉山","乐山","佛教名山","普贤道场","金顶日出"]','["世界自然遗产","佛教圣地","普贤道场","金顶日出"]',4.6,16789,48765,29.6012000,103.4567000,'四川省乐山市峨眉山市峨眉山景区','06:00-18:30','uploads/images/167.jpg','峨眉山是中国佛教四大名山之一，普贤菩萨的道场，以其秀美的自然风光和深厚的佛教文化而闻名。','峨眉山风景名胜区位于四川省乐山市峨眉山市，是中国四大佛教名山之一，普贤菩萨的道场，世界文化与自然双重遗产。峨眉山以"雄、奇、秀、险、幽"著称，素有"峨眉天下秀"的美誉。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_168','九寨沟风景名胜区','景区','["九寨沟","阿坝","彩池瀑布","原始森林","童话世界"]','["世界自然遗产","彩池瀑布","原始森林","童话世界"]',4.8,25678,78904,33.2567000,103.9234000,'四川省阿坝藏族羌族自治州九寨沟县漳扎镇','07:00-18:00','uploads/images/168.jpg','九寨沟以其绚丽多彩的湖泊、瀑布和原始森林而被誉为童话世界，是世界自然遗产。','九寨沟风景名胜区位于四川省阿坝藏族羌族自治州九寨沟县，是世界自然遗产、世界人与生物圈保护区。九寨沟因沟内有九个藏族村寨而得名，以翠海、叠瀑、彩林、雪峰和蓝冰"五绝"著称，被誉为"人间仙境"和"童话世界"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_169','黄龙风景名胜区','景区','["黄龙","阿坝","钙化池","雪山彩池","高原湿地"]','["世界自然遗产","钙化池","雪山彩池","高原湿地"]',4.5,12345,36789,32.7567000,103.8234000,'四川省阿坝藏族羌族自治州松潘县','08:00-17:00','uploads/images/169.jpg','黄龙以其独特的钙化池景观和高原湿地生态而成为世界自然遗产，被誉为人间瑶池。','黄龙风景名胜区位于四川省阿坝藏族羌族自治州松潘县，与九寨沟毗邻，是世界自然遗产。黄龙以规模宏大、结构完整、色彩斑斓的钙华梯池著称于世，被誉为"人间瑶池"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_170','都江堰景区','景区','["都江堰","成都","古代水利","李冰父子","工程奇迹"]','["世界文化遗产","古代水利","工程奇迹","历史文化"]',4.4,10987,31234,31.0234000,103.6789000,'四川省成都市都江堰市公园路','08:00-18:00','uploads/images/170.jpg','都江堰是世界文化遗产，中国古代水利工程的杰作，至今仍发挥着重要的灌溉作用。','都江堰景区位于四川省成都市都江堰市，是世界上最古老、至今仍在发挥作用的无坝引水水利工程，世界文化遗产。都江堰由秦国蜀郡太守李冰父子于公元前256年主持修建，至今已2200多年。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_171','青城山风景名胜区','景区','["青城山","成都","道教名山","天下幽","古建筑群"]','["道教圣地","天下幽","古建筑群","宗教文化"]',4.3,9876,28765,30.9012000,103.5678000,'四川省成都市都江堰市青城山镇','08:00-17:00','uploads/images/171.jpg','青城山是中国道教发源地之一，以天下幽而著称，拥有众多古建筑和深厚的道教文化。','青城山风景名胜区位于四川省成都市都江堰市，是中国道教的发祥地之一，世界文化遗产。青城山以"幽"著称，有"青城天下幽"的美誉，是道教名山和避暑胜地。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_172','石林风景名胜区','景区','["石林","昆明","喀斯特地貌","石林奇观","阿诗玛"]','["世界自然遗产","喀斯特地貌","石林奇观","民族文化"]',4.5,13456,39876,24.8123000,103.2890000,'云南省昆明市石林彝族自治县石林中路延长线','07:00-18:00','uploads/images/172.jpg','石林是世界自然遗产，以其独特的喀斯特地貌和石林奇观而闻名，被誉为天下第一奇观。','石林风景名胜区位于云南省昆明市石林彝族自治县，是世界自然遗产、世界地质公园。石林是典型的喀斯特地貌，形成于2.7亿年前的二叠纪时期，石灰岩在亿万年的溶蚀、风化作用下形成了如森林般密布的奇石奇峰，被誉为"天下第一奇观"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_173','丽江古城','景区','["丽江古城","丽江","纳西文化","古城风貌","世界遗产"]','["世界文化遗产","纳西文化","古城风貌","民族风情"]',4.6,18765,56789,26.8567000,100.2345000,'云南省丽江市古城区大研古城','全天开放','uploads/images/173.jpg','丽江古城是世界文化遗产，以其独特的纳西族文化和完整的古城风貌而成为著名的旅游胜地。','丽江古城位于云南省丽江市古城区，始建于宋末元初（公元13世纪后期），是世界文化遗产。古城以四方街为中心，三山为屏、三河穿城，是中国保存最完整、最具纳西族特色的古代城镇。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_174','玉龙雪山景区','景区','["玉龙雪山","丽江","雪山风光","冰川公园","高山植物"]','["雪山风光","冰川公园","高山植物","自然保护区"]',4.4,12345,36789,27.1234000,100.1789000,'云南省丽江市玉龙纳西族自治县','07:00-18:00','uploads/images/174.jpg','玉龙雪山是纳西族心中的神山，以其壮美的雪山风光和丰富的高山植物而成为重要的自然保护区。','玉龙雪山景区位于云南省丽江市玉龙纳西族自治县，是北半球最南端的雪山，也是纳西族的神山。玉龙雪山有13座山峰，主峰扇子陡海拔5596米，终年积雪，如一条银色的巨龙横卧于丽江坝子北面。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_175','三江并流风景名胜区','景区','["三江并流","迪庆","金沙江","澜沧江","怒江"]','["世界自然遗产","三江并流","生物多样性","高原风光"]',4.3,8765,25678,28.3456000,99.7890000,'云南省迪庆藏族自治州','08:00-18:00','uploads/images/175.jpg','三江并流是世界自然遗产，金沙江、澜沧江、怒江在此并行流淌，形成了独特的地理奇观。','三江并流风景名胜区位于云南省迪庆藏族自治州和怒江傈僳族自治州，是世界自然遗产。金沙江、澜沧江和怒江三条大江在滇西北横断山区并行南流，最短处三江仅距66公里，江水深切、峡谷深邃，形成了地球上最壮观的高山峡谷景观。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_176','大理古城','景区','["大理古城","大理","白族文化","苍山洱海","古城风韵"]','["白族文化","苍山洱海","古城风韵","民族风情"]',4.2,9876,28765,25.6789000,100.1567000,'云南省大理白族自治州大理市一塔路42号','全天开放','uploads/images/176.jpg','大理古城是白族文化的重要载体，背靠苍山，面临洱海，以其独特的白族风情和古城风韵而闻名。','大理古城位于云南省大理白族自治州大理市，东临洱海，西倚苍山，是中国历史文化名城之一。古城始建于明洪武十五年（1382年），曾是南诏国和大理国的都城，也是金庸武侠小说《天龙八部》中段誉的故乡。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_177','华山风景名胜区','景区','["华山","渭南","西岳华山","险峻奇峰","道教文化"]','["西岳华山","险峻奇峰","道教文化","登山挑战"]',4.6,16789,48765,34.4890000,110.0856000,'陕西省渭南市华阴市华山镇','全天开放','uploads/images/177.jpg','华山是五岳之一，以其险峻的山势和奇特的峰林而被誉为奇险天下第一山。','华山风景名胜区位于陕西省渭南市华阴市，是五岳之一——西岳，以"险"著称天下，被誉为"奇险天下第一山"。华山由一块完整的花岗岩体构成，五峰如莲花般耸立云端。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_178','兵马俑博物馆','景区','["兵马俑","西安","秦始皇陵","世界奇迹","考古发现"]','["世界文化遗产","秦始皇陵","世界奇迹","考古发现"]',4.7,23456,68902,34.3845000,109.2789000,'陕西省西安市临潼区秦陵北路','08:30-17:00','uploads/images/178.jpg','兵马俑是世界第八大奇迹，秦始皇陵的重要组成部分，展现了中国古代军事文化的辉煌。','秦始皇兵马俑博物馆位于陕西省西安市临潼区，是世界文化遗产，被誉为"世界第八大奇迹"。1974年，当地农民在打井时意外发现了这一深埋地下两千多年的庞大地下军团，震惊了整个世界。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_179','华清宫景区','景区','["华清宫","西安","唐代宫殿","温泉文化","历史故事"]','["唐代宫殿","温泉文化","历史故事","皇家园林"]',4.3,10987,31234,34.3623000,109.2145000,'陕西省西安市临潼区华清路38号','07:00-19:00','uploads/images/179.jpg','华清宫是唐代皇家温泉宫殿，以其深厚的历史文化和美丽的爱情故事而成为著名景区。','华清宫景区位于陕西省西安市临潼区骊山北麓，与兵马俑博物馆毗邻，是国家5A级旅游景区。华清宫是唐代皇家温泉离宫，也是"西安事变"的发生地，以温泉汤池和唐玄宗与杨贵妃的爱情故事闻名。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_180','大雁塔大慈恩寺','景区','["大雁塔","西安","佛教文化","唐代建筑","玄奘法师"]','["佛教文化","唐代建筑","玄奘法师","古塔建筑"]',4.4,14567,42345,34.2189000,108.9645000,'陕西省西安市雁塔区雁塔路','08:00-17:30','uploads/images/180.jpg','大雁塔是唐代佛教建筑的杰作，玄奘法师译经之地，是西安的标志性建筑之一。','大雁塔大慈恩寺位于陕西省西安市雁塔区，是西安最著名的地标之一。大慈恩寺是唐代皇家寺院，由唐高宗李治为纪念其母文德皇后而建。大雁塔是玄奘法师为保存从印度带回的经卷和佛像而亲自设计建造的。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_181','金丝峡景区','景区','["金丝峡","商洛","峡谷风光","瀑布群","生态旅游"]','["峡谷风光","瀑布群","生态旅游","自然奇观"]',4.2,7654,22345,33.8567000,110.8234000,'陕西省商洛市商南县金丝峡镇','08:00-18:00','uploads/images/181.jpg','金丝峡以其壮观的峡谷风光和丰富的瀑布群而成为秦岭南麓的重要生态旅游景区。','金丝峡景区位于陕西省商洛市商南县，是秦岭地区保存最完整的峡谷生态系统之一，国家5A级旅游景区。金丝峡以"窄、深、幽、秀、奇"著称，被誉为"中国最美的大峡谷"和"峡谷之都"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_182','青海湖景区','景区','["青海湖","西宁","高原湖泊","油菜花海","藏族文化"]','["高原湖泊","油菜花海","藏族文化","生态保护"]',4.5,14567,42345,36.8234000,100.1567000,'青海省海南藏族自治州共和县','全天开放','uploads/images/182.jpg','青海湖是中国最大的内陆湖泊，以其壮美的高原湖光山色和独特的藏族文化而成为著名景区。','青海湖景区位于青海省海南藏族自治州共和县，是中国最大的内陆湖和咸水湖，面积约4583平方公里，湖面海拔约3196米。青海湖如同一颗巨大的蓝宝石镶嵌在青藏高原之上，藏语称其为"措温布"，意为"青色的海"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_183','塔尔寺','景区','["塔尔寺","西宁","藏传佛教","宗喀巴","宗教文化"]','["藏传佛教","宗教文化","古建筑群","朝圣圣地"]',4.4,11234,33456,36.4567000,101.5678000,'青海省西宁市湟中区金塔路56号','08:00-17:00','uploads/images/183.jpg','塔尔寺是藏传佛教格鲁派的重要寺院，宗喀巴大师的诞生地，具有深厚的宗教文化底蕴。','塔尔寺位于青海省西宁市湟中区，是藏传佛教格鲁派（黄教）六大寺院之一，也是格鲁派创始人宗喀巴大师的诞生地。塔尔寺藏语称"衮本贤巴林"，意为"十万狮子吼佛像的弥勒寺"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_184','茶卡盐湖景区','景区','["茶卡盐湖","海西","天空之镜","盐湖奇观","摄影胜地"]','["天空之镜","盐湖奇观","摄影胜地","自然奇观"]',4.3,9876,28765,36.7012000,99.0234000,'青海省海西蒙古族藏族自治州乌兰县茶卡镇','07:00-18:30','uploads/images/184.jpg','茶卡盐湖被誉为天空之镜，以其独特的盐湖景观和完美的倒影效果而成为著名的摄影胜地。','茶卡盐湖景区位于青海省海西蒙古族藏族自治州乌兰县茶卡镇，是一个天然结晶盐湖，湖面海拔3059米，被誉为中国的"天空之镜"。因湖水含盐量极高，湖面结晶形成了一层薄薄的盐水层，平静时如同一面巨大的镜子完美倒映出蓝天白云和远处的雪山。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_185','天山天池风景名胜区','景区','["天山天池","昌吉","高山湖泊","雪山倒影","瑶池仙境"]','["高山湖泊","雪山倒影","瑶池仙境","自然美景"]',4.4,12345,36789,43.8890000,88.1234000,'新疆维吾尔自治区昌吉回族自治州阜康市','09:00-19:00','uploads/images/185.jpg','天山天池是天山山脉中的高山湖泊，被誉为瑶池仙境，以其清澈的湖水和雪山倒影而闻名。','天山天池风景名胜区位于新疆维吾尔自治区昌吉回族自治州阜康市，博格达峰北坡，是国家5A级旅游景区。天池形成于约200万年前第四纪冰川时期，湖面海拔约1910米，呈半月形，湖水清澈如碧玉，四周雪峰环绕、云杉耸立。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_186','喀纳斯景区','景区','["喀纳斯","阿勒泰","神秘湖泊","原始森林","图瓦文化"]','["神秘湖泊","原始森林","图瓦文化","自然保护区"]',4.6,16789,48765,48.7012000,87.0456000,'新疆维吾尔自治区阿勒泰地区布尔津县','08:00-20:00','uploads/images/186.jpg','喀纳斯是神秘的高山湖泊，以其变幻莫测的湖水颜色和原始的自然风光而被誉为人间仙境。','喀纳斯景区位于新疆维吾尔自治区阿勒泰地区布尔津县，阿尔泰山中段，是中国最美的湖泊之一。喀纳斯湖是一个高山冰碛堰塞湖，湖面海拔1374米，形如弯月，湖水因含有矿物质和季节变化而呈现出蓝绿交错的"变色湖"奇观。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_187','那拉提旅游风景区','景区','["那拉提","伊犁","空中草原","哈萨克文化","高山草甸"]','["空中草原","哈萨克文化","高山草甸","牧民风情"]',4.3,8765,25678,43.3456000,83.8012000,'新疆维吾尔自治区伊犁哈萨克自治州新源县','08:00-20:00','uploads/images/187.jpg','那拉提草原被誉为空中草原，以其辽阔的高山草甸和浓郁的哈萨克民族风情而闻名。','那拉提旅游风景区位于新疆维吾尔自治区伊犁哈萨克自治州新源县，地处天山腹地，伊犁河谷东端，是世界四大草原之一——那拉提草原的重要组成部分。那拉提蒙古语意为"最先见到太阳的地方"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_188','葡萄沟风景区','景区','["葡萄沟","吐鲁番","葡萄文化","维吾尔风情","绿洲景观"]','["葡萄文化","维吾尔风情","绿洲景观","民族特色"]',4.2,7654,22345,42.9567000,89.1890000,'新疆维吾尔自治区吐鲁番市高昌区','08:00-20:00','uploads/images/188.jpg','葡萄沟是吐鲁番的绿洲景观，以其甘甜的葡萄和浓郁的维吾尔族风情而成为著名景区。','葡萄沟风景区位于新疆维吾尔自治区吐鲁番市高昌区，火焰山西侧的一条峡谷中，是国家5A级旅游景区。吐鲁番是中国最热、最干旱的地方之一，而葡萄沟却绿树成荫、流水潺潺，形成了一处沙漠中的绿色奇迹。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_189','布达拉宫景区','景区','["布达拉宫","拉萨","藏传佛教","宫殿建筑","世界遗产"]','["世界文化遗产","藏传佛教","宫殿建筑","朝圣圣地"]',4.8,25678,78902,29.6567000,91.1167000,'西藏自治区拉萨市城关区北京中路35号','09:00-16:00','uploads/images/189.jpg','布达拉宫是世界文化遗产，藏传佛教的圣地，以其宏伟的建筑和深厚的宗教文化而闻名于世。','布达拉宫景区位于西藏自治区拉萨市城关区，是世界上海拔最高的古代宫殿，也是西藏最神圣、最具代表性的建筑，世界文化遗产。布达拉宫始建于公元7世纪，是吐蕃赞普松赞干布为迎娶文成公主而建，17世纪五世达赖喇嘛重建后成为历代达赖喇嘛的冬宫。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_190','大昭寺','景区','["大昭寺","拉萨","藏传佛教","释迦牟尼","朝圣中心"]','["藏传佛教","朝圣中心","古建筑","宗教文化"]',4.7,18765,56789,29.6534000,91.1345000,'西藏自治区拉萨市城关区八廓街','09:00-18:00','uploads/images/190.jpg','大昭寺是藏传佛教的朝圣中心，供奉着珍贵的释迦牟尼佛像，是西藏最神圣的寺庙。','大昭寺位于西藏自治区拉萨市城关区八廓街，是藏传佛教最神圣的寺院，也是西藏现存最古老的土木结构建筑，世界文化遗产。大昭寺因供奉着释迦牟尼12岁等身像（觉沃佛）而成为藏传佛教信徒一生向往的朝圣圣地。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_191','纳木错景区','景区','["纳木错","拉萨","圣湖","高原湖泊","念青唐古拉"]','["圣湖","高原湖泊","念青唐古拉","朝圣之地"]',4.5,13456,39876,30.7234000,90.9012000,'西藏自治区拉萨市当雄县','09:00-18:00','uploads/images/191.jpg','纳木错是西藏三大圣湖之一，位于念青唐古拉山脚下，以其神圣的地位和壮美的湖光山色而闻名。','纳木错景区位于西藏自治区拉萨市当雄县和那曲市班戈县之间，是西藏三大圣湖之首，也是世界上海拔最高的大型湖泊（湖面海拔4718米），藏语意为"天湖"。纳木错面积约1920平方公里，湖水湛蓝如天，与念青唐古拉山相依相伴。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_192','呼伦贝尔大草原','景区','["呼伦贝尔","呼伦贝尔","大草原","蒙古族文化","牧民生活"]','["大草原","蒙古族文化","牧民生活","自然生态"]',4.6,15678,45633,49.2123000,119.7567000,'内蒙古自治区呼伦贝尔市','全天开放','uploads/images/192.jpg','呼伦贝尔大草原是世界著名的天然牧场，以其辽阔的草原风光和浓郁的蒙古族文化而闻名。','呼伦贝尔大草原位于内蒙古自治区呼伦贝尔市，是世界四大草原之一，也是中国保存最完好、最优质的天然草原。呼伦贝尔因呼伦湖和贝尔湖而得名，总面积约10万平方公里，相当于一个江苏省的面积。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_193','阿尔山国家森林公园','景区','["阿尔山","兴安盟","森林公园","火山地貌","温泉资源"]','["森林公园","火山地貌","温泉资源","生态旅游"]',4.4,11234,33456,47.1789000,119.9456000,'内蒙古自治区兴安盟阿尔山市','08:00-17:00','uploads/images/193.jpg','阿尔山国家森林公园以其独特的火山地貌、丰富的温泉资源和原始的森林景观而成为重要的生态旅游区。','阿尔山国家森林公园位于内蒙古自治区兴安盟阿尔山市，地处大兴安岭西南麓，是国家5A级旅游景区。阿尔山全称"哈伦·阿尔山"，蒙古语意为"热的圣水"，以火山地貌、原始森林和温泉著称。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_194','满洲里国门景区','景区','["满洲里","呼伦贝尔","国门","中俄边境","口岸文化"]','["国门景观","中俄边境","口岸文化","异域风情"]',4.2,8765,25678,49.5967000,117.4789000,'内蒙古自治区呼伦贝尔市满洲里市','08:00-17:30','uploads/images/194.jpg','满洲里国门景区是中俄边境的重要口岸，以其独特的国门建筑和浓郁的异域风情而吸引游客。','满洲里国门景区位于内蒙古自治区呼伦贝尔市满洲里市，中俄边境线上，是中国最大的陆路口岸。景区以第五代国门为核心，展示了中俄边境的历史变迁和中国的国门形象。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_195','额济纳胡杨林景区','景区','["额济纳","阿拉善","胡杨林","沙漠绿洲","金秋美景"]','["胡杨林","沙漠绿洲","金秋美景","生态奇观"]',4.5,13457,39881,42.0678000,101.0567000,'内蒙古自治区阿拉善盟额济纳旗','08:00-18:00','uploads/images/195.jpg','额济纳胡杨林是世界仅存的三大胡杨林之一，以其金秋时节的绚烂色彩而成为摄影爱好者的天堂。','额济纳胡杨林景区位于内蒙古自治区阿拉善盟额济纳旗，是世界三大胡杨林之一，也是中国最壮观的胡杨林景观地。胡杨被誉为"生而一千年不死，死而一千年不倒，倒而一千年不朽"的沙漠英雄树。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_196','腾冲热海景区','景区','["腾冲","保山","温泉","地热奇观","火山活动"]','["地热奇观","温泉疗养","火山活动","自然景观"]',4.3,9876,28766,25.1234000,98.4567000,'云南省保山市腾冲市热海路','08:00-19:00','uploads/images/196.jpg','腾冲热海景区是中国著名的地热景区，以其丰富的温泉资源和独特的地热奇观而闻名。','腾冲热海景区位于云南省保山市腾冲市，是中国三大地热区之一，以温泉群和地热奇观而闻名，国家5A级旅游景区。腾冲地处欧亚板块与印度板块碰撞带，地热活动极为活跃。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_197','西双版纳热带植物园','景区','["西双版纳","景洪","热带植物","科研基地","生物多样性"]','["热带植物","科研基地","生物多样性","科普教育"]',4.4,12345,36790,21.9234000,101.2567000,'云南省西双版纳傣族自治州勐腊县','08:00-18:00','uploads/images/197.jpg','西双版纳热带植物园是中国面积最大的植物园，以其丰富的热带植物资源和重要的科研价值而闻名。','西双版纳热带植物园位于云南省西双版纳傣族自治州勐腊县勐仑镇，是中国面积最大、植物种类最丰富的植物园，国家5A级旅游景区。它由中国科学院于1959年创建，占地约1125公顷，在澜沧江（湄公河）支流罗梭江环绕的葫芦岛上。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_198','崇圣寺三塔文化旅游区','景区','["崇圣寺","大理","三塔","佛教文化","大理文化"]','["佛教文化","古塔建筑","大理文化","历史遗迹"]',4.3,10987,31234,25.6890000,100.1234000,'云南省大理白族自治州大理市崇圣寺三塔旅游区','08:00-19:00','uploads/images/198.jpg','崇圣寺三塔是大理的标志性建筑，见证了大理国的辉煌历史，是佛教文化的重要载体。','崇圣寺三塔文化旅游区位于云南省大理白族自治州大理市，是大理最古老、最雄伟的建筑群，国家5A级旅游景区。三塔矗立于苍山应乐峰下、洱海之滨，是大理"文献名邦"的象征，也是大理古国的皇家寺院遗址。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_199','泸沽湖景区','景区','["泸沽湖","丽江","摩梭文化","母系社会","高原湖泊"]','["摩梭文化","母系社会","高原湖泊","民族风情"]',4.5,14567,42345,27.6789000,100.7890000,'云南省丽江市宁蒗彝族自治县','全天开放','uploads/images/199.jpg','泸沽湖是摩梭人的母亲湖，以其独特的母系社会文化和秀美的高原湖泊风光而成为著名景区。','泸沽湖景区位于云南省丽江市宁蒗彝族自治县和四川省凉山彝族自治州盐源县交界处，是中国最清澈的高原湖泊之一，湖面海拔约2685米，最大水深达105.3米。泸沽湖是摩梭人的母亲湖，摩梭人至今保留着母系氏族社会的走婚习俗，因此泸沽湖被誉为"神秘的东方女儿国"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_200','香格里拉普达措国家公园','景区','["香格里拉","迪庆","普达措","高原生态","藏族文化"]','["高原生态","藏族文化","国家公园","生物多样性"]',4.4,11234,33456,27.8567000,99.9012000,'云南省迪庆藏族自治州香格里拉市','08:00-16:00','uploads/images/200.jpg','普达措国家公园是中国大陆第一个国家公园，以其原始的高原生态和丰富的生物多样性而闻名。','香格里拉普达措国家公园位于云南省迪庆藏族自治州香格里拉市，是中国大陆第一个国家公园，总面积约1313平方公里。"普达措"是梵文音译，意为"普度众生的舟湖"。
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_201','梅里雪山景区','景区','["梅里雪山","迪庆","卡瓦格博","神山","朝圣之地"]','["神山","朝圣之地","雪山风光","藏族文化"]',4.6,16789,48765,28.3890000,98.6234000,'云南省迪庆藏族自治州德钦县','07:00-19:00','uploads/images/201.jpg','梅里雪山是藏区八大神山之首，卡瓦格博峰是云南第一高峰，是藏民心中神圣的朝圣之地。','梅里雪山景区位于云南省迪庆藏族自治州德钦县，是藏传佛教四大神山之一，也是云南的最高峰。梅里雪山有13座海拔6000米以上的雪峰，绵延数百里，被誉为"世界上最美的雪山"。主峰卡瓦格博峰海拔6740米，至今仍是人类未能征服的处女峰。
