INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_015','暂时逃离期中','中午到杭州 下午背着包就去了西湖！\n\t\n西湖东湖都去过啦！属于是公费旅游了（','place_142',2,14,4.0,3,'["uploads/images/20250529_211020_1_limpid_.jpg", "uploads/images/20250529_211026_2_limpid_.jpg", "uploads/images/20250529_211033_4_limpid_.jpg", "uploads/images/20250529_211041_3_limpid_.jpg"]',NULL,'["北邮", "西湖"]',0,'2025-05-29 21:10:44');
