INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_012','是北邮的超前点映！','本来想签个到就溜走，但是雄狮少年2画面很好很好非常好，还有一些熟悉的方言倍感亲切，把我硬控到九点。\n毛不易的《无名的人》更是点睛之笔！\n这下子六级要寄寄了😭','place_001',2,31,3.8,2,NULL,'["uploads/videos/20250529_003110_1__.mp4", "uploads/videos/20250529_003116_2__.mp4", "uploads/videos/20250529_003126_3__.mp4", "uploads/videos/20250529_003138_4__.mp4"]','["雄狮少年"]',0,'2025-05-29 00:31:42');
