INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_001','北邮校园调酒！','在正经学校里做不正经的事！👀\n码农做出来的酒会是什么味道呢？🤔\n今晚九点麦麦门口不见不散！🥳\n\t\n因摊主个人原因，小摊定点不定时刷新，敬请关注后续动态！','place_001',1,27,3.7,6,'["uploads/images/20250528_235635_1__.jpg"]',NULL,'["美食", "学术"]',0,'2025-05-28 23:57:01');
