INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_202','北海公园','景区','["北海公园","北京","皇家园林","白塔","太液池","4A景区"]','["皇家园林","白塔标志","湖光山色","古都风韵"]',4.5,45678,67890,39.9244000,116.3893000,'北京市西城区文津街1号','06:30-21:00（旺季4-10月），06:30-20:00（淡季11-3月）','uploads/images/北海公园.jpg','北海公园是中国现存最古老、最完整的皇家园林之一，以琼华岛白塔和太液池湖景闻名。','北海公园位于北京市西城区，始建于辽代，是中国现存历史最悠久、保存最完整的皇家园林之一。北海公园以琼华岛为中心，白塔是公园的标志性建筑，建于清顺治八年（1651年），为藏式喇嘛塔，高35.9米。太液池水面约占公园总面积的一半，可泛舟湖上。园内还有九龙壁（中国现存三座古代九龙壁中唯一双面琉璃九龙壁）、五龙亭、静心斋、快雪堂等众多名胜古迹。歌曲《让我们荡起双桨》描绘的正是北海泛舟的场景。建议游览时间2至3小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_203','雍和宫','景区','["雍和宫","北京","藏传佛教","皇家寺院","万福阁","4A景区"]','["北京最大藏传佛教寺院","皇家敕建","万福阁木雕大佛","香火鼎盛"]',4.6,54321,76543,39.9469000,116.4175000,'北京市东城区雍和宫大街12号','09:00-17:00（旺季4-10月），09:00-16:30（淡季11-3月）','uploads/images/雍和宫.jpg','雍和宫是北京最大的藏传佛教寺院，曾是雍正皇帝的行宫，以万福阁的白檀木弥勒大佛闻名。','雍和宫位于北京市东城区，始建于清康熙三十三年（1694年），原为雍正皇帝胤禛即位前的雍亲王府，乾隆皇帝也诞生于此。乾隆九年（1744年）改为藏传佛教寺院，是北京规模最大、保存最完整的藏传佛教格鲁派（黄教）寺院。万福阁是雍和宫最高的建筑，阁内供奉着一尊高达18米（地上部分）的白檀木雕弥勒菩萨巨像，由一整根白檀木雕刻而成，为中国现存最大的木雕佛造像。雍和宫香火极旺，每年除夕和正月初一前来烧香祈福的人山人海。雍和宫的建筑融合了汉、满、蒙、藏多民族风格，是清代皇家建筑与宗教文化结合的杰作。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_204','香山公园','景区','["香山","北京","红叶秋景","皇家山林","登山胜地","4A景区"]','["香山红叶","皇家山林","登山健身","京城名胜"]',4.5,45678,65432,39.9969000,116.1874000,'北京市海淀区买卖街40号','06:00-18:30（旺季4-11月），06:00-18:00（淡季12-3月）','uploads/images/香山公园.jpg','香山公园是北京最著名的赏红叶胜地，每年秋季满山红叶如霞似火，是京城秋日最美的风景。','香山公园位于北京市海淀区西郊，是清代皇家园林静宜园所在地。香山主峰香炉峰（俗称鬼见愁）海拔575米，是登山爱好者的热门目的地。香山最负盛名的是秋季的红叶景观，香山红叶以黄栌树为主，每年10月中下旬至11月上旬是最佳观赏期，漫山遍野的红叶层林尽染，如同火焰般绚烂。眼镜湖、见心斋、昭庙（宗镜大昭之庙）、碧云寺等景点散布山间。双清别墅是1949年毛泽东进京后最早的办公居住地，具有重要的历史意义。建议秋季清晨前往，避开周末人流高峰，坐缆车上山步行下山是最省力的游览方式。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_205','慕田峪长城','景区','["慕田峪","北京","明长城","原始风貌","国际友人","5A景区"]','["长城精华段","植被覆盖率高","国际游客最爱","设施完善"]',4.7,65432,87654,40.4319000,116.5617000,'北京市怀柔区渤海镇慕田峪村','07:30-17:30（旺季3-11月），08:00-17:00（淡季12-2月）','uploads/images/慕田峪长城.jpg','慕田峪长城是明长城保存最完好的段落之一，以敌楼密集和植被丰茂著称，深受外国游客喜爱。','慕田峪长城位于北京市怀柔区，距北京城区约73公里，是明代长城精华段之一。慕田峪长城全长约5400米，有敌楼23座，敌楼密度居各段长城之首。这一段长城修建于北齐，明代由徐达督建，城墙高约8米、底宽约6米，可五马并骑。慕田峪长城的森林覆盖率高达96%以上，四季景色各异：春来山花烂漫，夏季绿荫如盖，秋季红叶似火，冬季银装素裹。景区设有缆车直达14号敌楼，也可以选择徒步上山。相较于八达岭长城，慕田峪游客较少，游览体验更佳，尤其受外国游客喜爱，是外国政要游览长城的首选之地。建议游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_206','北京环球度假区','景区','["环球影城","北京","主题乐园","好莱坞","哈利波特","5A景区"]','["世界级主题乐园","哈利波特魔法世界","侏罗纪世界","变形金刚"]',4.7,98765,156789,39.7898000,116.6754000,'北京市通州区梨园镇环球大道','09:00-21:00（每日开放时间以官方公告为准）','uploads/images/北京环球度假区.jpg','北京环球度假区是全球第五座环球影城主题乐园，以哈利波特魔法世界和侏罗纪世界等沉浸式体验为核心。','北京环球度假区位于北京市通州区，于2021年9月开园，是全球第五座、亚洲第三座环球影城主题乐园。乐园包括哈利波特的魔法世界、侏罗纪世界努布拉岛、变形金刚基地、功夫熊猫盖世之地、小黄人乐园、好莱坞和未来水世界七大主题园区。哈利波特园区以霍格沃茨城堡和霍格莫德村为核心，黄油啤酒和鹰马飞行过山车是不可错过的体验。侏罗纪世界冒险以震撼的实景恐龙和激流勇进著称。霸天虎过山车以4.5秒弹射起步创造极致速度体验。城市大道汇集了环球影城商店和各类主题餐厅。建议提前下载官方App查看排队时间，并购买快速通行证节省排队时间，游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_207','天津之眼摩天轮','景区','["天津之眼","天津","海河","摩天轮","夜景","4A景区"]','["世界唯一桥上摩天轮","海河夜景","天津地标","浪漫打卡地"]',4.3,34567,56789,39.1533000,117.1837000,'天津市河北区李公祠大街与五马路交口永乐桥上','09:30-21:30（周二至周日），周一检修','uploads/images/天津之眼摩天轮.jpg','天津之眼是世界上唯一建在桥上的摩天轮，坐落在海河永乐桥上，是天津的城市地标。','天津之眼摩天轮位于天津市河北区海河永乐桥上，是世界上唯一一座建在桥上的摩天轮，也是天津的地标性建筑。摩天轮直径110米，最高点距地面约120米，共有48个透明座舱，每个可乘坐8人，旋转一周约需30分钟。乘坐摩天轮升至最高点时，可俯瞰海河蜿蜒流淌和天津城市全貌，夜景尤为璀璨迷人。永乐桥横跨海河，桥面以上为摩天轮，桥面以下为行车道，设计独特。天津之眼的灯光会在夜晚变幻出不同颜色和图案，是拍摄海河夜景的最佳机位。建议傍晚时分乘坐，可同时欣赏落日余晖和城市华灯初上的景象。游览时间约1小时，需提前网上预约。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_208','清东陵','景区','["清东陵","唐山","皇家陵寝","世界遗产","清代文化","5A景区"]','["世界文化遗产","清代皇家陵寝群","建筑艺术","历史研究价值"]',4.5,54321,65432,40.1853000,117.6522000,'河北省唐山市遵化市马兰峪镇','08:00-17:00（旺季4-10月），08:30-16:30（淡季11-3月）','uploads/images/清东陵.jpg','清东陵是中国现存规模最宏大、体系最完整的清代皇家陵寝建筑群，是研究清代历史的重要遗址。','清东陵位于河北省唐山市遵化市，是中国现存规模最大、体系最完整的帝王陵墓建筑群，世界文化遗产。清东陵始建于顺治十八年（1661年），共葬有5位皇帝（顺治、康熙、乾隆、咸丰、同治）、15位皇后、136位嫔妃等共161人。乾隆皇帝的裕陵地宫雕刻精美绝伦，四壁和券顶布满佛教经文和图案，被誉为石雕艺术宝库。慈禧太后的定东陵以奢华著称，隆恩殿前的龙凤陛石采用凤在上龙在下的独特设计。香妃墓（容妃园寝）因金庸小说《书剑恩仇录》而广为人知。清东陵的建筑融合了汉族传统礼制和满族文化特色，规模宏伟、布局严谨。游览时间约半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_209','白石山世界地质公园','景区','["白石山","保定","大理岩峰林","玻璃栈道","云海奇观","5A景区"]','["世界地质公园","中国唯一大理岩峰林","玻璃栈道","云中步道"]',4.4,43210,54321,39.2567000,114.6758000,'河北省保定市涞源县白石山镇','08:00-18:00（旺季4-10月），08:00-17:00（淡季11-3月）','uploads/images/白石山世界地质公园.jpg','白石山是中国唯一的大理岩峰林地貌景区，以险峻的玻璃栈道和壮美的云海佛光奇观著称。','白石山世界地质公园位于河北省保定市涞源县，是中国唯一一处由白色大理岩构成的峰林地貌景区，世界地质公园和国家5A级旅游景区。主峰海拔2096米，因山体多白色大理石而得名。白石山最著名的是其玻璃栈道，建在海拔1900米的悬崖峭壁上，全长95米、宽2米，站在透明的玻璃栈道上俯瞰万丈深渊，考验胆量。双雄石是白石山的标志性景观，两块巨岩并立山顶，如同两位将军守卫。佛光顶是观赏云海和佛光的最佳位置。白石山的云海可与黄山媲美，佛光现象也时有发生。山上还有万亩红桦林，秋季色彩斑斓。建议乘坐景区大巴至韭菜园后开始徒步，游览时间约1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_210','悬空寺','景区','["悬空寺","大同","悬空建筑","佛道儒","险峻奇观","4A景区"]','["世界十大奇险建筑","佛道儒三教合一","悬崖绝壁","巧夺天工"]',4.6,56789,87654,39.6593000,113.7086000,'山西省大同市浑源县恒山南路','08:00-18:00（旺季4-10月），08:30-17:30（淡季11-3月）','uploads/images/悬空寺.jpg','悬空寺是世界十大奇险建筑之一，悬挂在恒山金龙峡的悬崖绝壁上，以险峻奇巧的建筑格局令人惊叹。','悬空寺位于山西省大同市浑源县恒山金龙峡西侧翠屏峰的悬崖峭壁间，始建于北魏太和十五年（公元491年），距今已有1500余年历史。悬空寺原叫玄空阁，悬取自道家之玄，空源自佛家之空，后因整座寺院如悬挂在悬崖之上而改名为悬空寺。寺院距地面约50米，以27根横梁插入岩石之中作为基座，利用力学原理使建筑半插飞梁为基、巧借岩石暗托。寺内共有殿阁40间，供奉着儒、释、道三教的塑像，是中国现存唯一的三教合一的独特寺庙。诗仙李白游此后在岩壁上写下壮观二字，徐霞客称其为天下巨观。游览时间约1至2小时，恐高者慎入。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_211','乔家大院','景区','["乔家大院","晋中","晋商文化","民居建筑","大红灯笼","5A景区"]','["晋商大院文化","北方民居典范","大红灯笼高高挂","砖雕木雕石雕"]',4.4,45678,65432,37.2872000,112.4256000,'山西省晋中市祁县乔家堡村','08:00-18:30（旺季4-10月），08:30-17:00（淡季11-3月）','uploads/images/乔家大院.jpg','乔家大院是晋商大院的杰出代表，因电影《大红灯笼高高挂》的取景而闻名天下。','乔家大院位于山西省晋中市祁县，又名在中堂，是清代著名商业金融资本家乔致庸的宅第。大院始建于清乾隆二十一年（1756年），占地约8700平方米，由6个大院、20个小院、313间房屋组成。整个院落呈双喜字形布局，设计精巧，气势宏伟，被誉为北方民居建筑的一颗明珠。大院三面临街，四周是高约10米的封闭砖墙，如同城堡一般。院内砖雕、木雕、石雕工艺精湛，内容涵盖人物典故、花鸟鱼虫、琴棋书画等，处处体现了晋商文化的深厚底蕴。电影《大红灯笼高高挂》和电视剧《乔家大院》在此拍摄，使乔家大院名扬海内外。游览时间约2至3小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_212','壶口瀑布','景区','["壶口瀑布","临汾","黄河奇观","黄色瀑布","自然奇观","5A景区"]','["世界最大黄色瀑布","黄河咆哮","彩虹飞架","四季不同景"]',4.5,56789,76543,36.1472000,110.4436000,'山西省临汾市吉县壶口镇','08:00-18:00（4-10月），08:00-17:00（11-3月）','uploads/images/壶口瀑布.jpg','壶口瀑布是世界上最大的黄色瀑布，黄河奔流至此骤然收缩倾泻而下，形成千里黄河一壶收的壮丽奇观。','壶口瀑布位于山西省临汾市吉县与陕西省延安市宜川县交界的黄河中游，是世界上最大的黄色瀑布。黄河奔流至此，300余米宽的河面在不到500米的距离内骤然压缩到20至30米，从20余米高的陡崖上倾泻而下，浊浪排空、声震数里，形成了千里黄河一壶收的震撼奇观。壶口瀑布的壮观程度随季节而变化：春季桃花汛水量丰沛，最为壮阔；夏季巨浪翻滚，如万马奔腾；秋季水色清澄，彩虹横跨；冬季冰瀑玉壶，银装素裹。瀑布两岸均可观赏，山西一侧距瀑布更近，视觉冲击力最强。壶口瀑布是中华民族精神的象征，《黄河大合唱》的灵感即来源于此壮丽场景。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_213','乌兰布统草原','景区','["乌兰布统","赤峰","坝上草原","影视基地","欧式草原","4A景区"]','["欧式草原风光","影视拍摄基地","坝上摄影天堂","丘陵草甸"]',4.5,45678,54321,42.5789000,117.3025000,'内蒙古自治区赤峰市克什克腾旗乌兰布统苏木','全天开放（6-10月为旅游季）','uploads/images/乌兰布统草原.jpg','乌兰布统草原是坝上草原的精华所在，以欧式草原风光和影视拍摄基地而闻名。','乌兰布统草原位于内蒙古自治区赤峰市克什克腾旗，是坝上草原（木兰围场）的核心组成部分。乌兰布统蒙古语意为红色的坛形山。这里的草原与呼伦贝尔的一望无际不同，而是森林与草原交错、丘陵与河谷相间的欧式草原风光，被誉为摄影家的天堂。公主湖、将军泡子、影视基地、蛤蟆坝、五彩山等景点是拍摄草原风光的最佳位置。乌兰布统曾是清代康熙皇帝平定噶尔丹的古战场，将军泡子的名字即来源于此役。这里还是许多影视剧的取景地，《还珠格格》《康熙王朝》《芈月传》等近百部影视作品都曾在此拍摄。每年6至9月是最佳旅游季节，草原上野花盛开，牛马成群。游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_214','居延海','景区','["居延海","阿拉善","沙漠湖泊","胡杨林","日出观鸟","4A景区"]','["沙漠绿洲","候鸟天堂","居延汉简发现地","日出奇观"]',4.3,23456,34567,42.3456000,101.0987000,'内蒙古自治区阿拉善盟额济纳旗达来呼布镇','06:00-19:00（5-10月），冬季关闭','uploads/images/居延海.jpg','居延海是沙漠中的绿洲湖泊，以壮丽的日出、成群的候鸟和与胡杨林相映的独特景色而著称。','居延海位于内蒙古自治区阿拉善盟额济纳旗，是黑河（古称弱水）的尾闾湖。居延是匈奴语，意为天池。居延海在汉代被称为居延泽，是古丝绸之路的重要水源地和中国第二大内陆湖。20世纪60年代后曾多次干涸，经过生态治理后才恢复了碧波荡漾的景象。日出是居延海最震撼的景观，晨曦中湖面被染成金色，芦苇荡在晨光中摇曳，成群的水鸟在湖面飞翔（每年春秋两季有数十万只候鸟在此栖息）。老子出关的传说也与居延海有关。著名的居延汉简就是在此地汉代烽燧遗址中发现的。建议在金秋十月前往，结合额济纳胡杨林做二日游。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_215','阿斯哈图石林','景区','["阿斯哈图","赤峰","花岗岩石林","冰川遗迹","地质奇观","5A景区"]','["世界地质公园","冰川石林奇观","花岗岩地貌","克什克腾"]',4.4,32109,43210,43.7345000,117.3678000,'内蒙古自治区赤峰市克什克腾旗巴彦查干苏木','08:00-17:30（6-10月），冬季关闭','uploads/images/阿斯哈图石林.jpg','阿斯哈图石林是世界罕见的花岗岩冰川石林，以千姿百态的石柱石墙而成为地质奇观。','阿斯哈图石林位于内蒙古自治区赤峰市克什克腾旗，是世界地质公园的一部分。阿斯哈图是蒙古语，意为险峻的岩石。这里的石林与云南石林的喀斯特地貌不同，是第四纪冰川运动造就的独特花岗岩石林地貌，在全世界极为罕见。石林形态千姿百态：有的如擎天巨柱直插云霄，有的如城墙成排而立，有的如人似兽栩栩如生。七仙女峰、罗汉阵、月亮城堡、拴马桩等象形景点令人称奇。夏季草原野花盛开，石阵点缀在绿草如茵的丘陵之上，形成了刚柔相济的独特画面。石林地处大兴安岭西南边缘，海拔约1700米，夏季凉爽宜人。游览时间约半天，需乘坐景区观光车游览。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_216','千山风景名胜区','景区','["千山","鞍山","佛教名山","道教圣地","辽东第一山","5A景区"]','["辽东第一山","佛道共处","奇峰怪石","千年古刹"]',4.3,34567,45678,41.0312000,123.1234000,'辽宁省鞍山市千山区千山东路','08:00-17:00','uploads/images/千山风景名胜区.jpg','千山是辽东第一山，集佛教寺庙与道教宫观于一体，千座奇峰如莲花绽放，是东北佛教圣地。','千山风景名胜区位于辽宁省鞍山市东南17公里处，是长白山支脉，总面积约125平方公里，主峰仙人台海拔708.3米。千山因山峰总数近千座而得名，素有东北明珠、辽东第一山之美誉。千山是佛道两教共处的名山，有九宫八观十二茅庵五大禅林之说。龙泉寺是千山最古老的寺庙，始建于唐代，已有1300余年历史；无量观是千山最大的道观；天成弥勒大佛是一尊高达70余米的天然石佛。千山四季皆景：春来梨花漫山，夏季绿荫蔽日，秋天红叶似火，冬日银装素裹。千山每年举办梨花节和冰雪节等活动。游览时间约1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_217','本溪水洞','景区','["本溪水洞","本溪","地下暗河","溶洞奇观","钟乳石","5A景区"]','["世界最长地下充水溶洞","暗河泛舟","钟乳石奇观","地质奇观"]',4.4,45678,56789,41.3189000,124.0783000,'辽宁省本溪市本溪满族自治县谢家崴子村','08:30-17:00（旺季4-10月），09:00-16:30（淡季11-3月）','uploads/images/本溪水洞.jpg','本溪水洞是世界最长的地下充水溶洞，以暗河泛舟穿行于钟乳石林立的洞中而成为独特的旅游体验。','本溪水洞位于辽宁省本溪市，是目前发现的世界最长的地下充水溶洞，全长约5800米，已开发约2800米。水洞形成于数百万年前，由地下水长期溶蚀石灰岩而成。洞内常年恒温约12摄氏度，四季皆可游览。游览方式为乘坐电动船在暗河中穿行，河道最宽处约50米、最深处约7米。洞内钟乳石、石笋、石柱、石幔发育完好，形态各异，在彩灯的照射下光怪陆离、如梦如幻。水洞入口处的旱洞（又称九曲银河洞）长约300米，无需乘船步行游览。洞外有太子河漂流和温泉度假村等配套设施。本溪水洞被赞为钟乳奇峰景万千、轻舟碧水诗画间。游览时间约2至3小时，洞内温度低需带外套。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_218','红海滩国家风景廊道','景区','["红海滩","盘锦","湿地生态","丹顶鹤","碱蓬草","5A景区"]','["世界最大红海滩","湿地生态奇观","丹顶鹤之乡","碱蓬草奇景"]',4.5,54321,65432,40.8922000,121.8325000,'辽宁省盘锦市大洼区赵圈河镇','08:00-17:00（5-10月），冬季关闭','uploads/images/红海滩国家风景廊道.jpg','红海滩是世界最大的湿地红海滩，由碱蓬草染红的滩涂与芦苇荡和丹顶鹤构成独特的生态画卷。','红海滩国家风景廊道位于辽宁省盘锦市，地处辽河入海口三角洲的湿地之上，是世界最大的红海滩景观。红海滩的红色来自于一种名为碱蓬草的植物，每年4至10月，碱蓬草从嫩绿到赤红随季节渐次变色，9至10月最为红艳。站在木栈道上望去，红色的滩涂与碧蓝的渤海、翠绿的芦苇荡形成强烈的色彩对比，震撼人心。这里是丹顶鹤、黑嘴鸥等260余种鸟类的栖息地，也是中国最大的滨海湿地保护区。景区全长约18公里，设有接官厅、依水云舟、稻梦空间等观景点。建议在金秋十月前往，此时的碱蓬草最红、候鸟最多，游览时间约半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_219','雾凇岛','景区','["雾凇岛","吉林","雾凇奇观","松花江","冬日仙境","4A景区"]','["中国四大自然奇观","雾凇仙境","松花江畔","冰雪童话"]',4.6,56789,76543,43.9322000,126.4911000,'吉林省吉林市龙潭区乌拉街满族镇韩屯村','全天开放（12-2月为雾凇季）','uploads/images/雾凇岛.jpg','雾凇岛是中国观赏雾凇的最佳地点，冬日清晨松花江畔万树银花，被誉为中国四大自然奇观之一。','雾凇岛位于吉林省吉林市龙潭区乌拉街满族镇，是松花江上的一个小岛。吉林雾凇与桂林山水、云南石林、长江三峡并称为中国四大自然奇观。雾凇是空气中过冷雾滴遇到树枝等物体后冻结而成的白色冰晶层，吉林雾凇因松花江上游丰满水电站排放的江水温度较高（约4摄氏度），在零下20多度的严寒中蒸发出大量水汽，遇到江畔树枝后凝结成凇。雾凇岛因地处江心、水汽充沛，是雾凇出现概率最高的地方。最佳观赏时间是每年12月至次年2月，清晨日出前到上午10点左右是雾凇最壮观的时间段，阳光透过晶莹剔透的雾凇，整个小岛如同仙境。曾通屯和韩屯是岛上的主要观景点。建议早起前往，穿足保暖衣物。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_220','查干湖','景区','["查干湖","松原","冬捕","渔猎文化","蒙古族","4A景区"]','["中国最大内陆湖","查干湖冬捕","蒙古族渔猎文化","AAAA景区"]',4.3,34567,45678,45.2567000,124.4589000,'吉林省松原市前郭尔罗斯蒙古族自治县','全天开放，景区设施08:00-17:00','uploads/images/查干湖.jpg','查干湖是中国十大淡水湖之一，以传承千年的蒙古族冬捕文化和壮观的冰湖腾鱼奇观而闻名。','查干湖位于吉林省松原市前郭尔罗斯蒙古族自治县，是中国十大淡水湖之一，也是吉林省最大的内陆湖。查干湖蒙古语意为白色圣洁的湖。查干湖最著名的是一年一度的冬捕活动，这一传统可追溯到辽金时期，至今已有近千年历史。每年12月底至次年1月是最佳冬捕观赏期，渔工们在冰面上凿开数百个冰洞，将长达2000余米的大网放入冰下，一网可捕获数万斤鲜鱼。冬捕开幕式的祭湖醒网仪式融合了蒙古族萨满文化和藏传佛教元素，极具神秘色彩。查干湖胖头鱼被列为中国国家地理标志产品。夏季的查干湖同样是消暑胜地，可乘船游湖、赏芦苇荡和荷花。游览时间1天，冬捕开幕式需提前了解日期。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_221','镜泊湖世界地质公园','景区','["镜泊湖","牡丹江","火山堰塞湖","吊水楼瀑布","地下森林","5A景区"]','["世界最大火山堰塞湖","吊水楼瀑布","地下森林","熔岩地貌"]',4.4,45678,56789,43.8899000,128.9234000,'黑龙江省牡丹江市宁安市镜泊湖风景区','08:00-17:00（5-10月为主），冬季部分关闭','uploads/images/镜泊湖世界地质公园.jpg','镜泊湖是世界最大的火山熔岩堰塞湖，以吊水楼瀑布跳水表演和火山口地下森林而闻名。','镜泊湖世界地质公园位于黑龙江省牡丹江市宁安市，是中国最大、世界第二大的火山熔岩堰塞湖。镜泊湖形成于约一万年前火山喷发熔岩阻塞牡丹江河床而成，湖面约95平方公里。吊水楼瀑布是镜泊湖最壮观的景点，宽约40米、落差约20米，丰水期如万马奔腾。中国悬崖跳水第一人狄焕然每日在吊水楼瀑布表演悬崖跳水，已成为景区的标志性表演。火山口地下森林是镜泊湖的另一大奇观——在7个直径50至500米的古火山口内，生长着参天的原始森林，形成了火山口中生森林的世界罕见地质景观。夏季可乘船游湖，冬季湖面冰封后可以体验冰上捕鱼和冰瀑观赏。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_222','漠河北极村','景区','["漠河","大兴安岭","中国最北端","北极光","极昼极夜","5A景区"]','["中国最北端","北极光观测","极昼极夜","北国边陲"]',4.4,45678,56789,53.4856000,122.3572000,'黑龙江省大兴安岭地区漠河市北极镇','全天开放，景区设施08:00-17:00','uploads/images/漠河北极村.jpg','漠河北极村是中国最北端的村落，以有机会看到北极光和体验极昼极夜的独特魅力而吸引游客。','漠河北极村位于黑龙江省大兴安岭地区漠河市，是中国领土最北端的村镇，素有金鸡之冠、神州北极之称。北极村原名漠河村，紧邻黑龙江，与俄罗斯隔江相望。这里是中国唯一有机会看到北极光的地方（虽然概率很低，通常出现在太阳活动高峰年份的春秋两季）。每年夏至前后，北极村出现极昼现象，黑夜仅持续数小时（凌晨一两点天就亮），被称为白夜奇观，夏至节是当地最盛大的节日。冬季则可以体验零下40至50摄氏度的极寒，泼水成冰、马拉雪橇、冰上捕鱼等冰雪体验丰富多彩。北极村的最北点——神州北极广场、最北邮局、最北人家等打卡点趣味十足。建议夏季和冬季各去一次，体验截然不同的北极村。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_223','中国雪乡','景区','["雪乡","牡丹江","冰雪世界","蘑菇雪","童话雪景","4A景区"]','["中国最美雪景","蘑菇雪奇观","冰雪童话世界","东北民俗"]',4.5,56789,87654,44.3345000,128.1234000,'黑龙江省牡丹江市海林市双峰林场','全天开放（11-3月为雪季）','uploads/images/中国雪乡.jpg','中国雪乡以厚达2米的积雪和蘑菇状的雪屋顶而成为冬日童话世界，是中国最美雪景的代名词。','中国雪乡位于黑龙江省牡丹江市海林市双峰林场，地处张广才岭南麓。雪乡因受日本海暖湿气流与西伯利亚寒流交汇影响，每年十月开始降雪，积雪期长达7个月，积雪厚度可达2米。雪花层层堆积在房顶、木桩和树木上，形成了蘑菇状、馒头状的雪造型，如同童话世界里的奶油蛋糕房。雪乡的夜景最为梦幻——夜幕降临后，大红灯笼在白雪映衬下亮起暖光，炊烟袅袅，极具东北年味。雪韵大街是雪乡的主街，沿街有雪乡主题邮局、民俗展览馆和各种东北特色小吃。徒步穿越雪谷（羊草山）是户外爱好者的热门雪地徒步路线。雪乡还是《爸爸去哪儿》《智取威虎山》等影视作品的取景地。游览时间1至2天，需注意防寒保暖。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_224','上海外滩','景区','["外滩","上海","黄浦江","万国建筑","东方明珠","5A景区"]','["万国建筑博览群","浦江两岸风光","上海城市名片","百年历史街区"]',4.8,112345,167890,31.2400000,121.4903000,'上海市黄浦区中山东一路','全天开放','uploads/images/上海外滩.jpg','上海外滩是上海的城市名片，黄浦江西岸的万国建筑博览群与陆家嘴的摩天大楼群隔江相望。','上海外滩位于上海市黄浦区黄浦江畔，南起延安东路北至苏州河上的外白渡桥，全长约1.5公里。外滩自1844年被划为英租界后逐渐成为上海乃至远东的金融中心，矗立着52幢风格各异的建筑，包括哥特式、巴洛克式、罗马式、文艺复兴式等风格，被誉为万国建筑博览群。和平饭店、海关大楼、汇丰银行大楼等是其中的代表。隔江与陆家嘴金融贸易区相对，东方明珠、金茂大厦、环球金融中心、上海中心大厦等摩天大楼构成中国最壮观的天际线。外滩的夜景世界闻名，华灯初上时浦江两岸灯光璀璨如繁星洒落。陈毅广场和人民英雄纪念塔是外滩的重要地标。建议傍晚前往，欣赏落日余晖和璀璨夜景的双重美景。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_225','豫园','景区','["豫园","上海","江南园林","明代园林","城隍庙","4A景区"]','["江南古典园林","明代园林精品","上海老城厢","新春灯会"]',4.5,65432,87654,31.2272000,121.4922000,'上海市黄浦区福佑路168号','08:30-17:00（旺季至17:30）','uploads/images/豫园.jpg','豫园是上海保存最完好的明代古典园林，以精巧的江南园林建筑和每年新春的元宵灯会而闻名。','豫园位于上海市黄浦区老城厢，始建于明嘉靖三十八年（1559年），是明代四川布政使潘允端为父母晚年养老而建的私人园林，取豫悦老亲之意故称豫园。豫园占地约2公顷，虽不大却精巧绝伦：大假山由明代叠石名家张南阳设计，高约12米，由数千吨武康黄石堆叠而成；玉玲珑是一块玲珑剔透的太湖奇石，为中国古代三大名石之一；点春堂是1853年小刀会起义的指挥所。豫园外围的豫园商城和城隍庙小吃街是上海最热闹的旅游商业区之一，南翔小笼包、绿波廊等老字号美食店云集。每年农历正月初一至元宵节举办的豫园新春民俗灯会是上海最有年味的地方，花灯璀璨、人山人海。游览时间约2小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_226','上海迪士尼乐园','景区','["迪士尼","上海","主题乐园","童话城堡","家庭娱乐","5A景区"]','["世界级主题乐园","奇幻童话城堡","沉浸式体验","亲子度假天堂"]',4.6,102345,156789,31.1433000,121.6603000,'上海市浦东新区川沙镇黄赵路310号','08:30-20:30（以官方公告为准）','uploads/images/上海迪士尼乐园.jpg','上海迪士尼乐园是中国大陆首座迪士尼主题乐园，以奇幻童话城堡和七大主题园区创造魔法梦想。','上海迪士尼乐园位于上海市浦东新区川沙镇，是中国大陆首座迪士尼乐园，于2016年6月16日开园。乐园包括米奇大街、奇想花园、梦幻世界、探险岛、宝藏湾、明日世界和玩具总动员七大主题园区。奇幻童话城堡是全球最大、最高的迪士尼城堡，汇聚了所有迪士尼公主的故事。创极速光轮是全球迪士尼最快的过山车；飞越地平线以震撼的4D飞行体验环游世界；加勒比海盗沉落宝藏之战是全球最先进的主题乐园乘骑项目。米奇童话专列日间巡游和点亮奇梦夜光幻影秀是每天的压轴大戏。建议下载官方App查看实时排队时间，合理利用快速通行证。避开节假日和周末高峰，游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_227','瘦西湖风景区','景区','["瘦西湖","扬州","江南水景","园林艺术","乾隆御道","5A景区"]','["江南水上园林","二十四桥明月","烟花三月扬州","湖上园林"]',4.5,54321,76543,32.3954000,119.4199000,'江苏省扬州市邗江区大虹桥路28号','06:30-17:30（旺季3-10月），07:00-17:00（淡季11-2月）','uploads/images/瘦西湖风景区.jpg','瘦西湖是扬州最负盛名的湖上园林，以二十四桥和五亭桥构建了诗画般的江南水景长卷。','瘦西湖风景区位于江苏省扬州市邗江区，全长约4.3公里，以湖面瘦长蜿蜒而得名。瘦西湖汇聚了唐代至清代扬州园林的精华，形成了两堤花柳全依水、一路楼台直到山的湖上园林画卷。五亭桥是瘦西湖的标志，建于清乾隆二十二年（1757年），桥上五座亭子形态各异，是中国古桥中的孤例。白塔仿北京北海白塔而建，相传是乾隆南巡时扬州盐商一夜之间用盐堆砌而成的传奇建筑。二十四桥因杜牧二十四桥明月夜、玉人何处教吹箫的诗句而举世闻名。小金山是湖中最大的岛屿，钓鱼台相传是乾隆皇帝垂钓之处。每年农历三月是扬州最美的时节（烟花三月下扬州），琼花盛开、柳絮飞扬。游览时间约半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_228','同里古镇','景区','["同里","苏州","江南水乡","明清古镇","退思园","5A景区"]','["江南六大古镇","世界文化遗产退思园","小桥流水","千年古镇"]',4.4,45678,56789,31.1556000,120.7161000,'江苏省苏州市吴江区同里镇','07:30-17:30（旺季至21:00有夜游）','uploads/images/同里古镇.jpg','同里古镇是江南六大古镇之一，以世界文化遗产退思园和水多桥多的千年水乡风貌著称。','同里古镇位于江苏省苏州市吴江区，始建于宋代，是江南六大古镇之一。同里以水多、桥多、明清建筑多而著称，全镇被15条河流分割为7个小岛，由49座古桥相连。退思园是同里的镇镇之宝，建于清光绪十一年（1885年），是世界文化遗产苏州古典园林的重要组成部分，以贴水而建的独特设计著称，亭台楼阁皆紧贴水面如浮水上。三桥是同里最著名的古桥群——太平桥、吉利桥、长庆桥，当地有走过三桥的婚俗。穿心弄是古镇最窄的巷子，仅容一人通过。罗星洲是镇外湖中的一个小岛，集佛教寺庙与园林于一体。与周庄相比同里更为安静古朴，适合慢慢品味江南水乡的慢生活。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_229','千岛湖风景区','景区','["千岛湖","杭州","人工湖","青山绿水","度假天堂","5A景区"]','["千岛千姿","天下第一秀水","水上休闲","生态度假"]',4.5,65432,87654,29.6089000,119.0456000,'浙江省杭州市淳安县千岛湖镇','全天开放，游船08:00-16:00','uploads/images/千岛湖风景区.jpg','千岛湖因湖中散布1078座岛屿而得名，被誉为天下第一秀水，是中国最大的人工湖和顶级度假胜地。','千岛湖风景区位于浙江省杭州市淳安县，是1959年新安江水电站建成后形成的人工湖。湖区面积约580平方公里，湖中散布着1078个大小岛屿，故名千岛湖。千岛湖水质达到国家一类水体标准，能见度可达12米，被誉为天下第一秀水，也是农夫山泉的水源地之一。梅峰岛是登高俯瞰千岛湖全景的最佳位置，可观千岛竞秀的壮美画面。龙山岛上有海瑞祠，纪念明嘉靖年间在此任知县的清官海瑞。月光岛、渔乐岛、龙山岛、梅峰岛是中心湖区的主要游览岛。千岛湖有机鱼头汤鲜味美，是必尝的当地美食。环湖骑行和游艇休闲也极受欢迎。建议游览1至2天，在湖景度假酒店住一晚。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_230','乌镇古镇','景区','["乌镇","嘉兴","江南水乡","互联网大会","木心美术馆","5A景区"]','["江南六大古镇","互联网小镇","木心美术馆","西栅夜景"]',4.5,76543,102345,30.7456000,120.4956000,'浙江省嘉兴市桐乡市乌镇','09:00-22:00（西栅），09:00-17:30（东栅）','uploads/images/乌镇古镇.jpg','乌镇是江南六大古镇之一，以保存完好的水乡风貌和世界互联网大会永久会址的双重身份而闻名。','乌镇古镇位于浙江省嘉兴市桐乡市，是中国首批历史文化名镇。古镇以十字形市河为骨架，保存了大量明清时期的古建和石板街巷。东栅以原生态居民生活为主，有茅盾故居、立志书院等，更富生活气息；西栅为度假式景区，由12座小岛和70余座古桥构成，夜景最为迷人——灯笼映水，桨声灯影，充满诗情画意。乌镇是世界互联网大会乌镇峰会永久会址，现代科技与千年水乡奇妙交融。木心美术馆（建筑由贝聿铭弟子设计）展示了著名作家画家木心的艺术作品。乌镇戏剧节每年秋季举办，是全球最具影响力的戏剧盛会之一。建议在西栅住一晚体验夜色与晨光，游览时间1天半。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_231','西塘古镇','景区','["西塘","嘉兴","江南水乡","烟雨长廊","活着的古镇","5A景区"]','["江南六大古镇","千米烟雨长廊","活着的千年古镇","影视取景地"]',4.4,56789,76543,30.9389000,120.8864000,'浙江省嘉兴市嘉善县西塘镇','08:00-17:00（日间），17:00-22:00（夜游）','uploads/images/西塘古镇.jpg','西塘古镇以千米烟雨长廊和原汁原味的明清水乡生活而被称为活着的千年古镇。','西塘古镇位于浙江省嘉兴市嘉善县，古称胥塘，是江南六大古镇之一。西塘最大的特色是千米烟雨长廊——沿河而建的有顶走廊，为行人遮阳避雨，是江南古镇中独一无二的设计。西塘被称为活着的千年古镇，因为至今仍有大量原住民在古镇内生活，充满了人间烟火气。送子来凤桥、环秀桥、卧龙桥等古桥横跨市河，五福桥、永宁桥下的乌篷船桨声欸乃。石皮弄是西塘最窄的弄堂，宽仅约1米。西塘的塘东街是酒吧一条街，夜生活丰富多彩。每年西塘汉服文化周是汉服爱好者的盛大聚会。汤婆婆的民宿和管老太臭豆腐是西塘的热门打卡点。游览时间1天，建议下午到晚上游览，感受水乡夜色。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_232','莫干山风景名胜区','景区','["莫干山","湖州","避暑胜地","民宿文化","竹海山峦","4A景区"]','["中国四大避暑胜地","洋家乐民宿发源地","万亩竹海","民国别墅群"]',4.5,56789,76543,30.6234000,119.8856000,'浙江省湖州市德清县莫干山镇','全天开放（各民宿和景点时间不同）','uploads/images/莫干山风景名胜区.jpg','莫干山是中国四大避暑胜地之一，以万亩竹海和高端民宿群而成为中国最富盛名的山居度假目的地。','莫干山风景名胜区位于浙江省湖州市德清县，因春秋时期干将莫邪夫妇在此铸剑而得名，是中国四大避暑胜地之一。莫干山以竹、泉、云三绝著称，万亩竹海连绵起伏，山中泉水清澈甘洌，云雾缭绕时如入仙境。19世纪末至20世纪初，美、英、德、法等国传教士和商人在山上修建了大量欧式别墅，至今保存完好的民国老别墅有200余栋，是中国最大的近代别墅建筑群。近年来莫干山以洋家乐（高端民宿）闻名全国，裸心谷、法国山居等已成为中国民宿业的标杆。莫干山的Discovery探索极限基地是全球首个Discovery授权的户外极限体验乐园。芦花荡公园、剑池、武陵村等是主要景点。游览时间1至2天，适合周末休闲度假。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_233','横店影视城','景区','["横店","金华","影视基地","主题演艺","穿越体验","5A景区"]','["中国好莱坞","影视拍摄基地","沉浸式演艺","古装穿越"]',4.4,76543,102345,29.1789000,120.3156000,'浙江省金华市东阳市横店镇','08:00-17:00（各景区），梦幻谷至21:00','uploads/images/横店影视城.jpg','横店影视城是全球最大的影视拍摄基地，以各朝代实景建筑和精彩的沉浸式演艺秀而被称为中国好莱坞。','横店影视城位于浙江省金华市东阳市横店镇，是全球规模最大的影视拍摄基地，中国好莱坞。影视城包括秦王宫、清明上河图、明清宫苑、广州街香港街、圆明新园、梦幻谷等十余个跨越千年历史的影视实景拍摄区。秦王宫景区巍峨壮阔，仿秦代咸阳宫而建，是《英雄》《芈月传》取景地；清明上河图景区浓缩了宋代张择端画作中的汴京繁华景象；明清宫苑以北京故宫为蓝本1比1复制。各景区每天上演数十场精彩的演艺秀：梦幻谷的暴雨山洪和梦幻太极是横店最经典的两场大型实景演出。游客还可以在现场观看剧组拍摄，甚至参与群演体验。建议游览2至3天，购买联票更划算。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_234','宏村古村落','景区','["宏村","黄山","徽派建筑","世界遗产","水墨画乡","5A景区"]','["世界文化遗产","徽派古村落典范","牛形水系布局","中国画里乡村"]',4.6,67890,87654,29.9925000,117.9794000,'安徽省黄山市黟县宏村镇','全天开放','uploads/images/宏村古村落.jpg','宏村是徽派古村落的杰出代表，以独特的牛形村落水系和如画的白墙黛瓦被誉为中国画里乡村。','宏村古村落位于安徽省黄山市黟县，始建于南宋绍兴年间，距今约900年历史，是世界文化遗产。宏村最独特之处在于其牛形村落布局和精巧的人工水系：雷岗山为牛首，参天古树为牛角，错落民居为牛身，月沼为牛胃，南湖为牛肚，水圳为牛肠，古桥为牛腿。水圳穿堂过户，家家门前有清泉，月沼和南湖碧波荡漾，倒映着白墙黛瓦和马头墙，如同一幅天然水墨画。承志堂是村中规模最大的古宅，被誉为民间故宫。电影《卧虎藏龙》中周润发牵马走过的南湖桥已成为经典画面。宏村吸引着无数写生学生和摄影爱好者，清晨的月沼晨雾是最经典的画面。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_235','西递古村落','景区','["西递","黄山","徽派建筑","世界遗产","桃花源里","5A景区"]','["世界文化遗产","徽商故里","明清古民居群","桃花源里人家"]',4.4,43210,54321,29.8989000,117.9967000,'安徽省黄山市黟县西递镇','全天开放','uploads/images/西递古村落.jpg','西递是徽派古村落的又一杰作，以保存完整的明清古民居和徽商故里的深厚文化底蕴而成为世界文化遗产。','西递古村落位于安徽省黄山市黟县，始建于北宋，是世界文化遗产。西递因村边溪水西流和古时此处设有递送邮件的驿站而得名。全村现有保存完好的明清古民居124幢，祠堂3幢，包括胡文光牌坊（徽派石雕牌坊的精品）、追慕堂（胡氏宗祠）、西园、东园等著名建筑。西递的建筑以精美的石雕、砖雕、木雕三雕著称，体现了徽商雄厚的财力和高雅的审美情趣。西递被誉为桃花源里人家和世界上最美的村庄之一。村口的胡文光刺史牌坊是西递的标志，建于明万历六年（1578年），全部用青石雕砌。与宏村相比，西递更显古朴沉静。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_236','琅琊山风景名胜区','景区','["琅琊山","滁州","醉翁亭","唐宋文化","山水园林","4A景区"]','["醉翁亭记诞生地","中国四大名亭","唐宋摩崖石刻","山水诗画"]',4.3,32109,43210,32.3089000,118.2678000,'安徽省滁州市琅琊区琅琊山','08:00-17:00','uploads/images/琅琊山风景名胜区.jpg','琅琊山因欧阳修的千古名篇《醉翁亭记》而名扬天下，醉翁亭更是位列中国四大名亭之首。','琅琊山风景名胜区位于安徽省滁州市，因欧阳修被贬滁州时所写的千古名篇《醉翁亭记》而闻名遐迩。醉翁之意不在酒、在乎山水之间也的名句流传千年。醉翁亭是中国四大名亭之首，始建于北宋庆历年间，亭以文名，文以亭传。琅琊寺始建于唐大历年间，寺内有吴道子绘观音像、苏轼书《醉翁亭记》碑刻等珍贵文物。南天门是琅琊山的主峰，海拔321米，登顶可远眺长江。深秀湖、丰乐亭、同乐园等景点散布山中。琅琊山的唐宋摩崖石刻多达200余处，是中国书法艺术的珍贵遗产。每年金秋十月举办的中国农民歌会已成为琅琊山的一张文化名片。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_237','福建土楼（南靖）','景区','["福建土楼","漳州","世界遗产","客家文化","生土建筑","5A景区"]','["世界文化遗产","客家土楼","生土建筑奇观","东方古城堡"]',4.5,65432,87654,24.5067000,117.0625000,'福建省漳州市南靖县书洋镇','08:00-17:30','uploads/images/福建土楼（南靖）.jpg','福建土楼是世界文化遗产，以独特的圆形生土建筑群展现了客家先民的集体智慧和非凡的防御设计。','福建土楼（南靖）位于福建省漳州市南靖县，是客家人自宋代以来营建的独特生土夯筑民居建筑群，世界文化遗产。土楼以圆形为主、方形为辅，外墙厚达1至2米，用当地红壤土、砂石、竹片和糯米浆等材料分层夯实而成。田螺坑土楼群是南靖土楼的精华——四座圆形土楼围绕一座方形土楼（俗称四菜一汤），从观景台俯瞰极为壮观。裕昌楼（东倒西歪楼）已有700余年历史，内部木柱东歪西斜却历经多次地震不倒，堪称建筑奇迹。云水谣古镇因电影《云水谣》而得名，古榕树和鹅卵石古道充满诗意。振成楼被誉为土楼王子，是土楼设计的集大成者。游览时间1天，可在土楼民宿过夜体验客家生活。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_238','太姥山风景名胜区','景区','["太姥山","宁德","花岗岩峰林","海上仙都","白茶故乡","5A景区"]','["海上仙都","花岗岩峰林","太姥娘娘传说","福鼎白茶"]',4.4,34567,45678,27.1011000,120.1781000,'福建省宁德市福鼎市太姥山镇','08:00-17:00','uploads/images/太姥山风景名胜区.jpg','太姥山以花岗岩峰林景观和海上仙都的美誉而成为福建东部最壮丽的山海景区。','太姥山风景名胜区位于福建省宁德市福鼎市，三面临海，以花岗岩峰林地貌为主要特色，被誉为海上仙都、山海大观。太姥山得名于上古太姥娘娘在此得道飞升的传说。主峰摩霄峰海拔约917米，登顶可眺望东海碧波。太姥山以峰险、石奇、洞幽、雾幻四绝著称：夫妻峰、九鲤朝天等奇石惟妙惟肖；葫芦洞、一线天等洞壑幽深奇幻；云海雾涛赋予了太姥山变幻莫测的神秘气质。太姥山还是中国白茶（福鼎白茶）的核心产区，山中的白茶古树有数百年历史。太姥山脚下的牛郎岗海滩可以享受阳光沙滩。每年4至5月是太姥山杜鹃花盛开的季节，漫山红遍。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_239','三清山风景名胜区','景区','["三清山","上饶","道教圣地","花岗岩峰林","奇峰云海","5A景区"]','["世界自然遗产","道教名山","巨蟒出山","西海岸栈道"]',4.6,65432,87654,28.9367000,118.0733000,'江西省上饶市玉山县三清乡','08:00-17:00（旺季3-11月至17:30）','uploads/images/三清山风景名胜区.jpg','三清山是世界自然遗产，以奇特的花岗岩峰林和巨蟒出山等世界级象形石景观而闻名于世。','三清山风景名胜区位于江西省上饶市玉山县与德兴市交界处，是世界自然遗产和世界地质公园。三清山因玉京、玉虚、玉华三峰宛如道教三位尊神而得名。主峰玉京峰海拔1819.9米。三清山以奇峰怪石、古树名花、流泉飞瀑、云海雾涛并称四绝。巨蟒出山是一根高128米的独立花岗岩石柱，为世界级象形石奇观。东方女神形似一位中国女性的侧脸轮廓，是三清山最具代表性的景观。西海岸栈道建在海拔1600多米的悬崖绝壁上，是中国最高的高山栈道之一。三清山还有数千亩高山杜鹃林，每年5月花开如海。三清宫始建于东晋升平年间，已有1600余年历史。游览时间1至2天，建议乘坐金沙索道上山。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_240','龙虎山风景名胜区','景区','["龙虎山","鹰潭","道教祖庭","丹霞地貌","泸溪河","5A景区"]','["世界自然遗产","道教正一派祖庭","丹山碧水","悬棺之谜"]',4.5,54321,65432,28.1033000,116.9589000,'江西省鹰潭市贵溪市龙虎山镇','08:00-17:00（旺季至17:30）','uploads/images/龙虎山风景名胜区.jpg','龙虎山是道教正一派的祖庭和世界自然遗产，以丹霞地貌与道教文化完美融合的丹山碧水而闻名。','龙虎山风景名胜区位于江西省鹰潭市贵溪市，是中国道教发祥地之一和世界自然遗产。龙虎山是道教正一派（天师道）的祖庭，第一代天师张道陵在此创立道教，至今已传承至第65代天师。天师府是历代天师生活起居和祀神之处，规模宏大。上清古镇保存了大量与道教相关的古建筑。龙虎山的自然景观以丹霞地貌为主，泸溪河（竹筏漂流）蜿蜒穿行于红色丹霞峰林之间，构成了丹山碧水的诗画长卷。仙女岩（酷似女性外阴的天然岩壁裂缝）与金枪峰（形似男性生殖器的石柱）一阴一阳，被称为天下第一绝景。春秋战国崖墓群至今仍是未解之谜——数百具悬棺是如何放置在数十米高的悬崖洞中的。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_241','婺源篁岭景区','景区','["婺源","上饶","徽派民居","油菜花海","晒秋文化","5A景区"]','["中国最美乡村","婺源油菜花","篁岭晒秋","徽派民居"]',4.6,76543,98765,29.2767000,117.8678000,'江西省上饶市婺源县江湾镇篁岭村','08:00-17:30（旺季至18:00）','uploads/images/婺源篁岭景区.jpg','篁岭是婺源旅游的精华，以晒秋民俗和万亩梯田油菜花海而成为中国最美乡村的代言人。','婺源篁岭景区位于江西省上饶市婺源县，是中国最美乡村婺源最核心的景区。篁岭是一个挂在悬崖上的古村落，数百栋徽派民居依山就势、层层叠叠。晒秋是篁岭最具特色的民俗景观——由于村庄建在陡坡上，缺少平坦的晒场，村民就在自家屋顶和窗台架起竹匾晾晒辣椒、玉米、菊花、南瓜等农作物，五彩斑斓的晒匾与白墙黛瓦构成绚丽的秋日画卷，被誉为中国最美的秋天符号。每年3至4月，篁岭万亩梯田油菜花盛开，金黄色的花海与徽派建筑交相辉映。垒心桥是一座横跨两山之间的悬索桥，桥面部分为玻璃栈道，是《欢乐颂2》的取景地。建议春秋两季前往，游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_242','滕王阁','景区','["滕王阁","南昌","江南名楼","王勃","赣江风光","5A景区"]','["江南三大名楼","滕王阁序","落霞孤鹜","赣江夜景"]',4.4,54321,65432,28.6828000,115.8778000,'江西省南昌市东湖区仿古街58号','08:00-18:30（旺季至19:00）','uploads/images/滕王阁.jpg','滕王阁是江南三大名楼之一，因王勃的千古骈文《滕王阁序》而名垂千古，落霞与孤鹜齐飞是南昌最美风景。','滕王阁位于江西省南昌市东湖区赣江之滨，是江南三大名楼之一（与黄鹤楼、岳阳楼齐名）。滕王阁始建于唐永徽四年（公元653年），是唐太宗李世民之弟滕王李元婴所建。真正使滕王阁名垂千古的是初唐四杰之一王勃的《滕王阁序》，其中落霞与孤鹜齐飞、秋水共长天一色的名句成为中国文学史上的绝唱。现存建筑为1989年第29次重建，高57.5米共9层（明三暗七），是三大名楼中最高的一座。阁内收藏了大量与《滕王阁序》相关的书法碑刻和文物。登阁远眺，赣江滚滚北去，南昌新城尽收眼底。阁前的滕王阁广场每晚有音乐喷泉表演。游览时间1至2小时，傍晚时分可观赏落霞与孤鹜齐飞的经典画面。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_243','崂山风景名胜区','景区','["崂山","青岛","道教圣地","海上名山","山海奇观","5A景区"]','["海上第一名山","道教全真派圣地","山海相连","崂山矿泉水"]',4.5,56789,76543,36.1083000,120.6275000,'山东省青岛市崂山区梅岭路29号','07:00-17:30（旺季至18:00）','uploads/images/崂山风景名胜区.jpg','崂山是海上第一名山，耸立于黄海之滨，以山海相连的壮美景观和悠久的道教文化闻名于世。','崂山风景名胜区位于山东省青岛市崂山区，耸立于黄海之滨，是中国海岸线上的第一高峰，主峰巨峰海拔1132.7米。崂山是中国道教发祥地之一，全真龙门派创始人丘处机曾在此修炼。崂山以山海奇观著称——登高远眺，碧海蓝天、岛屿星罗、巨浪拍岸，这种山海交融的壮丽在中国名山中独一无二。太清宫是崂山最古老的道观，始建于西汉建元元年（公元前140年），汉柏、唐榆、宋银杏等古树见证千年沧桑。崂山矿泉是中国最著名的矿泉水。蒲松龄曾在崂山居住并创作了《聊斋志异》中的《崂山道士》。主要游览区有巨峰、太清宫、北九水（溪涧流泉）、仰口等。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_244','趵突泉公园','景区','["趵突泉","济南","泉水之都","天下第一泉","李清照","5A景区"]','["天下第一泉","泉城济南标志","漱玉泉边李清照","泉水文化"]',4.5,56789,76543,36.6611000,117.0156000,'山东省济南市历下区趵突泉南路1号','07:00-22:00（旺季至22:30）','uploads/images/趵突泉公园.jpg','趵突泉是天下第一泉和济南七十二名泉之首，以三股泉水喷涌不息而成为中国最著名的泉水景观。','趵突泉公园位于山东省济南市历下区，是天下第一泉风景区的核心。趵突泉是济南七十二名泉之冠，有天下第一泉的美誉。泉水从地下石灰岩溶洞中喷涌而出，三股并发，最大涌量可达每日24万吨，泉水四季恒温18摄氏度，冬暖夏凉。园内除了趵突泉还有漱玉泉、柳絮泉、金线泉等27处名泉。漱玉泉边建有李清照纪念堂，宋代婉约派词人李清照（号易安居士）曾居济南，她的许多名篇可能就是在泉水边完成的。万竹园是一座园中园，以翠竹和泉水见长。每年农历八月趵突泉灯会是济南最盛大的传统活动。泉水泡茶甘甜清冽，是济南人引以为傲的待客之礼。游览时间2至3小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_245','刘公岛风景名胜区','景区','["刘公岛","威海","甲午战争","北洋水师","爱国主义","5A景区"]','["甲午战争纪念地","北洋水师诞生地","海上森林公园","爱国主义教育基地"]',4.4,43210,54321,37.5012000,122.1843000,'山东省威海市环翠区刘公岛','07:30-17:00（旺季至18:00）','uploads/images/刘公岛风景名胜区.jpg','刘公岛是北洋水师的诞生地和甲午战争的主战场，以深厚的历史记忆和秀丽的海岛风光而成为重要的爱国主义教育基地。','刘公岛风景名胜区位于山东省威海市，是威海湾中的一座小岛，面积约3.15平方公里。刘公岛在中国近代史上占有特殊地位——这里是清朝北洋水师的诞生地，也是1894至1895年甲午战争的主战场之一。岛上的中国甲午战争博物馆通过大量历史文物、图片和场景复原，再现了那段悲壮的历史。定远舰1比1复制品停靠在岛边，可以登舰感受当年亚洲第一巨舰的雄姿。北洋水师提督署（海军公所）旧址保存完好。旗顶山炮台遗址上巨大的克虏伯大炮至今雄视海疆。刘公岛还是中国第一个国家级海上森林公园，岛上植被覆盖率达87%，还是大熊猫在山东的唯一饲养地。需从威海旅游码头乘船上岛，游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_246','老君山风景名胜区','景区','["老君山","洛阳","道教圣地","金顶金殿","云海仙境","5A景区"]','["道教名山","金殿金顶","云海云瀑","老子归隐处"]',4.7,87654,112345,33.7567000,111.6312000,'河南省洛阳市栾川县老君山景区','08:00-17:00（旺季至18:00）','uploads/images/老君山风景名胜区.jpg','老君山是道教始祖老子归隐之地，以金顶金殿和壮观的云海云瀑而成为近年来最火爆的网红名山。','老君山风景名胜区位于河南省洛阳市栾川县，是八百里伏牛山的主峰，海拔约2217米。老君山原名景室山，因道教始祖老子（李耳）在此归隐修炼而被唐太宗赐名老君山。老君山金顶道观群是核心景观——金殿、亮宝台、玉皇顶三座金灿灿的殿宇矗立在山巅绝壁之上，在阳光照射下金光万丈、如天宫仙阙。老君山的云海云瀑极为壮观，乘坐中天门至金顶的缆车穿行在云雾之中，如腾云驾雾直达天宫。老君山的十里画屏是一条建在崖壁上的悬崖栈道，沿途可观赏峰林峡涧和地质奇观。山顶的马鬃岭是观赏日出的最佳位置。老君山近年因短视频走红成为年轻游客的热门打卡地。游览时间1天，建议坐缆车至中天门后步行登顶。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_247','红旗渠','景区','["红旗渠","安阳","人工天河","太行山","水利奇迹","5A景区"]','["人工天河","太行山奇迹","红色教育基地","自力更生精神"]',4.4,43210,54321,36.1567000,113.7867000,'河南省安阳市林州市任村镇','08:00-18:00（旺季至18:00）','uploads/images/红旗渠.jpg','红旗渠是二十世纪六十年代林县人民在太行山上开凿的人工天河，是人类水利建设史上的奇迹。','红旗渠位于河南省安阳市林州市（原林县），是二十世纪六十年代林县人民在极其艰苦的条件下，在太行山悬崖绝壁上开凿出的一条人工引水渠。红旗渠全长约1500公里（干渠加支渠），削平1250座山头，架设151座渡槽，开凿211个隧洞，被誉为世界第八大奇迹和人工天河。青年洞是红旗渠最险要的工程段，由300名青年突击队员用一年多时间在悬崖上凿通。分水苑、络丝潭、青年洞是红旗渠的三大景区。红旗渠不仅是一项水利工程，更是中华民族自力更生、艰苦创业、团结协作、无私奉献精神的象征。每年有大量游客和研学团队来此接受教育。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_248','太行大峡谷','景区','["太行大峡谷","安阳","太行山脉","峡谷漂流","挂壁公路","5A景区"]','["国家地质公园","太行山最壮美峡谷","挂壁公路","漂流胜地"]',4.4,43210,54321,36.0892000,113.6545000,'河南省安阳市林州市石板岩镇','08:00-17:00（旺季至18:00）','uploads/images/太行大峡谷.jpg','太行大峡谷是太行山脉最壮美的峡谷段落，以悬崖绝壁、挂壁公路和惊险刺激的峡谷漂流而闻名。','太行大峡谷位于河南省安阳市林州市石板岩镇，地处太行山脉南段，是中国十大最美峡谷之一和国家地质公园。峡谷全长约50公里，最深处达800米，两侧绝壁如刀削斧劈。桃花谷以溪流瀑布、碧水潭池著称，被誉为太行山中的九寨沟。王相岩景区以险峻著称，悬空栈道和摩天筒梯考验胆量。太行平湖（石板岩水库）碧波万顷，是峡谷中的一颗明珠。峡谷漂流是夏季最受欢迎的项目。峡谷中还散落着多个保存完好的太行古村落，石屋石板路的原始风貌与壮美的峡谷风光相得益彰。这里也是写生基地，每年吸引大量美术院校师生前来写生。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_249','武当山风景区','景区','["武当山","十堰","道教圣地","武当武术","世界遗产","5A景区"]','["世界文化遗产","道教第一名山","武当武术发源地","皇家宫观群"]',4.6,65432,87654,32.4000000,111.0119000,'湖北省十堰市丹江口市武当山特区','08:00-17:00（旺季至17:30）','uploads/images/武当山风景区.jpg','武当山是道教第一名山和太极拳发源地，以规模宏大的皇家道观群而列入世界文化遗产。','武当山风景区位于湖北省十堰市丹江口市，古称太和山，是道教圣地。武当山道教建筑群始建于唐贞观年间，明永乐年间朱棣皇帝大兴土木，形成了九宫八观三十六庵堂的宏伟格局。紫霄宫是保存最完整的宫殿式道观，金殿位于天柱峰顶（海拔1612米），全部用铜鎏金构件组装而成，是中国现存最大的铜铸鎏金大殿。武当武术是中华武术重要流派，元末明初张三丰在此创立了武当内家拳，以柔克刚、以静制动，与少林武术齐名。南岩宫建在悬崖绝壁上，龙头香伸出悬崖外2.9米令人心惊。太子坡的一柱十二梁建筑奇迹展示了古代工匠的高超技艺。游览时间1至2天，建议乘坐索道至金顶。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_250','神农架国家公园','景区','["神农架","神农架","原始森林","野人传说","金丝猴","5A景区"]','["世界自然遗产","原始森林秘境","野人传说","生物多样性宝库"]',4.5,56789,76543,31.4767000,110.3919000,'湖北省神农架林区木鱼镇','08:00-17:00（各景点略有不同）','uploads/images/神农架国家公园.jpg','神农架以神秘的野人传说和完好的原始森林生态而闻名于世，是中国最富神秘色彩的旅游目的地。','神农架国家公园位于湖北省神农架林区，是中国唯一以林区命名的行政区，世界自然遗产。神农架因华夏始祖炎帝神农氏在此搭架采药而得名。神农顶（海拔3106.2米）是华中最高峰，有华中屋脊之称。神农架的原始森林保存了地球中纬度地区最完好的生态系统，是川金丝猴、珙桐等珍稀动植物的栖息地。大九湖是海拔1700米的高山湿地，由9个高原湖泊组成，晨雾缭绕时美如仙境。板壁岩以奇石怪岩和关于野人踪迹的传说而闻名。神农祭坛的巨大神农氏头像雕塑是景区的标志。每年5至10月是最佳旅游季节。游览时间2至3天，自驾是最方便的游览方式。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_251','恩施大峡谷','景区','["恩施大峡谷","恩施","喀斯特地貌","一炷香","清江","5A景区"]','["世界地质公园","一炷香奇观","清江升白云","与美国科罗拉多媲美"]',4.6,65432,87654,30.1789000,109.3895000,'湖北省恩施土家族苗族自治州恩施市沐抚办事处','08:00-17:00（旺季至17:30）','uploads/images/恩施大峡谷.jpg','恩施大峡谷以百里绝壁和千丈瀑布著称于世，与美国科罗拉多大峡谷结为姊妹峡谷。','恩施大峡谷位于湖北省恩施土家族苗族自治州恩施市，是清江大峡谷中的一段精华，世界地质公园。大峡谷全长约108公里，总面积约300平方公里。七星寨景区以大峡谷的最高峰和标志性景观一炷香最为著名——一根高约150米的独立岩柱拔地而起，底部直径约6米，最细处仅约4米，如一支擎天巨香直插云霄，历经亿万年风雨侵蚀而不倒。云龙地缝以瀑布群和地缝奇观著称，全程约3.6公里，地缝最深处近百米。绝壁长廊建在千仞绝壁之上，步行其上俯瞰谷底令人腿软。恩施大峡谷与美国科罗拉多大峡谷结为姊妹峡谷。游览时间1天，建议从游客中心乘索道上七星寨。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_252','岳阳楼','景区','["岳阳楼","岳阳","江南名楼","洞庭湖","范仲淹","5A景区"]','["江南三大名楼","洞庭天下水","岳阳天下楼","忧乐文化"]',4.4,54321,65432,29.3847000,113.0897000,'湖南省岳阳市岳阳楼区洞庭北路','07:00-18:30（旺季至19:00）','uploads/images/岳阳楼.jpg','岳阳楼是江南三大名楼之一，因范仲淹先天下之忧而忧的千古名句而成为中华民族精神的象征。','岳阳楼位于湖南省岳阳市洞庭湖畔的西门城墙上，是江南三大名楼之一。岳阳楼下瞰八百里洞庭，前望君山岛，视野极为开阔。北宋庆历六年（1046年），范仲淹应好友滕子京之邀写下了千古名篇《岳阳楼记》，其中先天下之忧而忧、后天下之乐而乐的名句使岳阳楼成为中国士大夫精神的最高象征。现存建筑为清光绪六年（1880年）重建，三层三檐盔顶式结构，高19.42米，是中国现存最大的盔顶式古建。楼内珍藏有毛泽东手书杜甫《登岳阳楼》诗和清代书法家张照书写的《岳阳楼记》雕屏。岳阳楼下的洞庭湖是中国第二大淡水湖。隔湖相望的君山岛以斑竹和银针茶闻名。游览时间2小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_253','凤凰古城','景区','["凤凰古城","湘西","苗族风情","沱江风光","沈从文边城","4A景区"]','["中国最美小城","苗族土家族风情","沱江吊脚楼","沈从文故里"]',4.5,76543,98765,27.9489000,109.5989000,'湖南省湘西土家族苗族自治州凤凰县','全天开放，景点08:00-17:30','uploads/images/凤凰古城.jpg','凤凰古城是中国最美的小城，以沱江两岸的吊脚楼和沈从文笔下的边城风情而成为湘西旅游的必游之地。','凤凰古城位于湖南省湘西土家族苗族自治州凤凰县，是中国历史文化名城，建于清康熙四十三年（1704年）。凤凰古城依沱江而建，江两岸的吊脚楼是苗族的传统建筑，青石板街道纵横交错。虹桥（风雨楼）横跨沱江之上，是凤凰的标志性建筑。沈从文故居展示了这位文学大师的生平和他笔下边城世界的原乡。熊希龄故居（民国第一任民选总理）、东门城楼、万名塔等古迹值得一看。沱江泛舟是最惬意的游览方式，撑船的老人会唱起湘西山歌。夜晚的凤凰灯火璀璨，沱江边的酒吧和民谣让古城多了几分文艺气息。建议在古城住一晚，清晨沱江上的薄雾最为迷人。游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_254','韶山风景名胜区','景区','["韶山","湘潭","毛泽东故里","红色旅游","伟人故居","5A景区"]','["伟人故里","红色教育基地","毛泽东故居","滴水洞"]',4.5,45678,65432,27.9156000,112.5267000,'湖南省湘潭市韶山市韶山乡','08:00-17:00（旺季至17:30）','uploads/images/韶山风景名胜区.jpg','韶山是毛泽东主席的故乡，以伟人故里和深厚的红色文化底蕴而成为中国最重要的红色旅游景区之一。','韶山风景名胜区位于湖南省湘潭市韶山市，是一代伟人毛泽东的故乡。毛泽东同志故居是一栋坐南朝北的土木结构农舍，1893年12月26日毛泽东在此诞生并度过了童年和少年时代。故居前的池塘和稻田保持着百年前的原貌。毛泽东铜像广场矗立着高10.1米的毛主席铜像，每天前来献花瞻仰的游客络绎不绝。毛泽东纪念馆陈列了大量珍贵的历史文物和照片，系统展示了伟人的革命生涯。滴水洞是毛泽东1966年回韶山时居住的地方，被称为西方的山洞。毛泽东诗词碑林镌刻了主席多首著名诗词。每年12月26日毛泽东诞辰纪念日韶山会举行隆重的纪念活动。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_255','崀山风景名胜区','景区','["崀山","邵阳","丹霞地貌","世界遗产","辣椒峰","5A景区"]','["世界自然遗产","中国丹霞之一","辣椒峰","骆驼峰"]',4.4,32109,43210,26.3714000,110.8125000,'湖南省邵阳市新宁县崀山镇','08:00-17:00','uploads/images/崀山风景名胜区.jpg','崀山是世界自然遗产中国丹霞的重要组成部分，以辣椒峰等独特的丹霞象形石而闻名。','崀山风景名胜区位于湖南省邵阳市新宁县，是世界自然遗产中国丹霞的组成部分。崀山因舜帝南巡至此感叹山之良也而得名。辣椒峰是崀山最著名的景观——一座高约180米的丹霞石柱，形如一只巨大的红辣椒倒立在地上，是丹霞地貌中的孤例。2002年法国蜘蛛人阿兰罗伯特徒手攀爬辣椒峰成功，使崀山名扬世界。骆驼峰形如双峰骆驼跪卧，背上建有骆驼峰栈道。天一巷是崀山最窄的巷谷，全长238米，最窄处仅33厘米，仅容一人侧身通过。八角寨是崀山的最高点，登顶可观鲸鱼闹海（云海中群峰如鲸鱼出没）的壮丽景象。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_256','深圳世界之窗','景区','["世界之窗","深圳","主题公园","微缩景观","世界文化","5A景区"]','["世界著名景观微缩","埃菲尔铁塔","环球文化体验","灯光秀"]',4.3,56789,76543,22.5372000,113.9732000,'广东省深圳市南山区深南大道9037号','09:00-22:30（夜场17:30起）','uploads/images/深圳世界之窗.jpg','深圳世界之窗汇集了全球100多个著名景观的微缩建筑，是了解世界文化的一站式窗口。','深圳世界之窗位于广东省深圳市南山区华侨城，是中国最著名的大型文化旅游景区之一。园区占地约48万平方米，汇集了全球100多个世界著名文化景观和建筑奇迹的微缩模型。其中埃菲尔铁塔按1比3比例建造，高108米，可乘电梯登顶俯瞰深圳全景。景区分为世界广场、亚洲区、大洋洲区、欧洲区、非洲区、美洲区等八大区域。夜晚的世界之窗更加璀璨——《盛世纪》大型音乐舞蹈史诗是园区最顶级的演出。每逢节假日举办的烟花表演绚丽多彩。万圣节、圣诞节等主题活动精彩纷呈。阿尔卑斯冰雪世界可以体验室内滑雪。游览时间半天至1天，夜场性价比高。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_257','开平碉楼与村落','景区','["开平碉楼","江门","世界遗产","华侨文化","中西合璧","5A景区"]','["世界文化遗产","华侨文化结晶","中西合璧建筑","让子弹飞取景地"]',4.4,45678,54321,22.3139000,112.5806000,'广东省江门市开平市塘口镇','08:30-17:30','uploads/images/开平碉楼与村落.jpg','开平碉楼是世界文化遗产，以中西合璧的独特建筑风格展现了华侨文化的非凡创造力。','开平碉楼与村落位于广东省江门市开平市，是世界文化遗产。碉楼是开平籍海外华侨于20世纪初回乡修建的中西合璧多层塔楼式建筑，集居住和防御功能于一体。全盛时期开平有3000多座碉楼，现存1833座。自力村碉楼群是最集中的观赏区，铭石楼（电影《让子弹飞》中黄四郎府邸的取景地）是其中的代表。马降龙碉楼群掩映在竹林之中，环境清幽，被联合国专家评为世界最美的村落。瑞石楼有开平第一楼之称，高9层25米，装饰最精美。立园是旅美华侨谢维立的私家园林，融合了中国园林的意境和西方别墅的舒适。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_258','罗浮山风景名胜区','景区','["罗浮山","惠州","道教名山","百粤群山之祖","葛洪炼丹","5A景区"]','["岭南第一山","道教第七洞天","葛洪炼丹处","百粤群山之祖"]',4.3,32109,43210,23.2875000,114.0581000,'广东省惠州市博罗县长宁镇','08:00-17:30','uploads/images/罗浮山风景名胜区.jpg','罗浮山是岭南第一山，道教第七洞天，因葛洪在此炼丹修行而成为中国道教和中医药文化的重要圣地。','罗浮山风景名胜区位于广东省惠州市博罗县，是岭南第一山和中国十大道教名山之一。罗浮山由罗山和浮山合并而成，方圆约260平方公里，大小山峰432座，飞瀑流泉980多处。冲虚古观是罗浮山最著名的道观，始建于东晋咸和年间，由道教理论家、炼丹家葛洪创建，至今已有1600余年历史。葛洪在此写下了《肘后备急方》，其中关于青蒿治疗疟疾的记载启发了屠呦呦发现青蒿素（2015年诺贝尔生理学或医学奖）。朱明洞、黄龙观、华首寺等景点散布山间。罗浮山还是道教第七洞天和第三十一福地。飞云顶是罗浮山最高峰，海拔约1296米。游览时间1天，可乘坐缆车至半山再徒步登顶。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_259','德天跨国瀑布','景区','["德天瀑布","崇左","跨国瀑布","中越边境","归春河","5A景区"]','["亚洲第一跨国瀑布","中越边境风光","德天板约双瀑","喀斯特峰林"]',4.5,54321,65432,22.8556000,106.7286000,'广西壮族自治区崇左市大新县硕龙镇','08:00-17:30','uploads/images/德天跨国瀑布.jpg','德天瀑布是亚洲第一跨国瀑布，横跨中越两国边境，以三级跌落和归春河的喀斯特峰林风光闻名。','德天跨国瀑布位于广西壮族自治区崇左市大新县硕龙镇中越边境的归春河上游。瀑布宽约120米、落差约70米，分三级跌落，与越南的板约瀑布紧密相邻，丰水期两瀑布连为一体总宽达200余米。每年6至11月丰水期水量最大，如万马奔腾声震数里，水雾升腾形成道道彩虹。53号界碑是中越两国的分界线，游客可在此一步跨两国。景区还包含明仕田园（花千骨取景地），归春河畔的喀斯特峰林田园画卷被誉为小桂林。景区内可乘坐竹筏近距离感受瀑布的水雾轰鸣。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_260','涠洲岛','景区','["涠洲岛","北海","火山岛","海岛风光","天主教堂","5A景区"]','["中国最年轻火山岛","海岛度假天堂","百年天主教堂","海鲜美食"]',4.5,56789,76543,21.0392000,109.1122000,'广西壮族自治区北海市海城区涠洲镇','全天开放（需乘船上岛，最早航班07:00）','uploads/images/涠洲岛.jpg','涠洲岛是中国最大最年轻的火山岛，以火山熔岩海岸和百年法式天主教堂而成为广西最受欢迎的海岛。','涠洲岛位于广西壮族自治区北海市南部海域，距市区约36海里，面积约24.74平方公里，是中国最大最年轻的火山岛。涠洲岛形成于约100万年至7000年前的多次火山喷发。鳄鱼山火山公园是核心景区，火山口遗迹和黑色火山岩海岸线震撼人心。盛塘天主教堂建于1853年，由法国传教士用岛上珊瑚岩和火山岩建造，中西合璧风格独特。五彩滩以海蚀平台上的青苔在晨光中五彩斑斓而得名，是岛上看日出的最佳地点。石螺口海滩和滴水丹屏适合游泳和看日落。涠洲岛的海鲜物美价廉，皮皮虾和石斑鱼是必尝美食。游览时间1至2天，需从北海国际客运港乘船约70分钟。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_261','龙脊梯田','景区','["龙脊梯田","桂林","梯田景观","壮族瑶族","世界遗产","4A景区"]','["全球重要农业文化遗产","千层天梯","壮族瑶族文化","梯田光影"]',4.6,65432,87654,25.7567000,110.1256000,'广西壮族自治区桂林市龙胜各族自治县龙脊镇','全天开放（最佳观赏5-10月）','uploads/images/龙脊梯田.jpg','龙脊梯田是全球重要农业文化遗产，以千层天梯的壮美曲线和壮族瑶族的农耕文化而闻名于世。','龙脊梯田位于广西壮族自治区桂林市龙胜各族自治县，始建于元朝，距今已有650余年历史，是全球重要农业文化遗产。梯田从海拔300米的河谷盘绕而上至海拔1100米的山顶，层层叠叠如链似带，最大坡度达50度。平安壮族梯田以七星伴月景观最为经典——七块小田环绕一块大田如众星拱月。金坑大寨红瑶梯田规模最大，千层天梯和西山韶乐（1号观景台）是看日出的最佳位置。每年农历四月灌水季节，梯田水面如千万块镜面倒映天光云影，是摄影的最佳时节。金秋收割前稻田一片金黄同样壮观。龙脊的壮族竹筒饭、瑶族油茶是特色美食。建议在山上民宿住一晚以便拍摄日出。游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_262','天涯海角','景区','["天涯海角","三亚","热带海滨","天涯石","海角石","5A景区"]','["天涯海角石","热带滨海风光","浪漫爱情圣地","南天一柱"]',4.3,54321,76543,18.2936000,109.3467000,'海南省三亚市天涯区天涯镇','07:30-18:00','uploads/images/天涯海角.jpg','天涯海角是三亚最著名的地标景区，以天涯和海角巨石闻名，是中国最南端的浪漫海滨胜地。','天涯海角位于海南省三亚市天涯区，距三亚市区约23公里。景区因海滩上矗立着天涯和海角两块巨石而得名。清雍正年间崖州知州程哲题刻天涯二字于巨石之上，后有文人题刻海角二字于相邻巨石。南天一柱石印在第四套人民币2元纸币背面。天涯海角因其寓意被赋予了浓厚的爱情色彩，是中国最著名的爱情圣地之一，每年在此举办的天涯海角国际婚庆节吸引众多情侣参加。景区背靠马岭山、面向南海，椰林沙滩绵延约2公里。天涯海角星雕塑和爱情邮局是热门打卡点。游览时间2至3小时，建议上午前往避开正午烈日。海边拍照注意涨潮。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_263','南山文化旅游区','景区','["南山","三亚","佛教文化","海上观音","长寿文化","5A景区"]','["108米海上观音圣像","佛教文化主题","南山寺","热带园林风光"]',4.5,56789,76543,18.3061000,109.2061000,'海南省三亚市崖州区南山村','08:00-17:30','uploads/images/南山文化旅游区.jpg','南山文化旅游区以108米高的三面海上观音圣像闻名于世，是中国最南端的佛教文化主题景区。','南山文化旅游区位于海南省三亚市崖州区，是中国最南端的佛教文化主题景区。景区的标志是三面海上观音圣像，高108米（超过美国自由女神像），一体化三尊造型：正面持经箧象征智慧，右边持莲花象征平安，左边持念珠象征慈悲。观音圣像矗立于直径120米的金刚洲上，通过280米长的普济桥与陆地相连，从海上远眺极为壮观。南山寺是海南最著名的佛教寺院。金玉观音阁内供奉了世界最大的金玉佛像。不二法门是景区的入口标志，寓意佛教的不二法门。长寿谷以南山长寿文化为主题。这里的素斋也非常有名。游览时间半天至1天，园区较大可乘坐游览车。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_264','蜈支洲岛','景区','["蜈支洲岛","三亚","潜水胜地","海岛度假","珊瑚礁","5A景区"]','["中国最佳潜水基地","海岛度假天堂","情人岛","热带雨林"]',4.6,56789,87654,18.3147000,109.7606000,'海南省三亚市海棠区蜈支洲岛','08:00-17:30（最后一班船离岛17:30）','uploads/images/蜈支洲岛.jpg','蜈支洲岛是中国最佳潜水基地之一，以清澈见底的海水和丰富的珊瑚礁生态而成为海岛度假天堂。','蜈支洲岛位于海南省三亚市海棠区，距海岸线约2.7公里，面积约1.48平方公里。蜈支洲岛因形似一种叫蜈支的海洋生物而得名，又称情人岛。这里海水能见度可达27米，是中国最优质的潜水胜地，海底珊瑚礁保存完好。岛上设有潜水、摩托艇、拖曳伞等30余项海上娱乐项目。情人桥是岛上标志性景点和观日出最佳位置。观日岩是制高点，可360度俯瞰南海碧波。妈祖庙供奉着渔民的海上保护神。岛上植被茂密，热带雨林覆盖率达80%以上。游览时间1天，需从蜈支洲岛码头乘船约20分钟上岛，建议提前网上购票。岛上物价较陆地高可自带水和零食。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_265','亚龙湾','景区','["亚龙湾","三亚","碧海银沙","热带海滨","天下第一湾","4A景区"]','["天下第一湾","碧海银沙","热带滨海度假","国际顶级酒店群"]',4.6,76543,98765,18.2292000,109.6396000,'海南省三亚市吉阳区亚龙湾','全天开放','uploads/images/亚龙湾.jpg','亚龙湾被誉为天下第一湾，以绵长洁白的沙滩和碧蓝透亮的海水而成为中国最顶级的热带滨海度假天堂。','亚龙湾位于海南省三亚市吉阳区，是中国最优质的热带滨海度假区。亚龙湾又称牙龙湾，因海湾形状如巨龙昂首而得名。沙滩全长约7公里，沙粒洁白细腻（富含珊瑚和贝壳碎屑），海水湛蓝透明能见度达10米以上，被誉为天下第一湾，与夏威夷、巴厘岛齐名。亚龙湾中心广场的图腾柱高26.8米，雕刻着中国各民族的神话图腾。湾区沿岸聚集了数十家国际顶级五星级度假酒店，每家酒店都拥有专属沙滩。蝴蝶谷和贝壳馆展示了海南丰富的海洋生物多样性。亚龙湾热带天堂森林公园在湾区背后的山上，《非诚勿扰2》的鸟巢度假村就在其中。过江龙索桥是电影中舒淇走过的经典场景。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_266','大足石刻','景区','["大足石刻","重庆","佛教石窟","世界遗产","唐宋艺术","5A景区"]','["世界文化遗产","唐宋石刻艺术宝库","儒释道三教合一","民间艺术瑰宝"]',4.6,54321,65432,29.7003000,105.7067000,'重庆市大足区宝顶镇','08:30-17:30','uploads/images/大足石刻.jpg','大足石刻是唐宋石刻艺术的巅峰之作，以千手观音和长达31米的卧佛而成为世界文化遗产。','大足石刻位于重庆市大足区，是唐末宋初时期的摩崖石刻群，与敦煌莫高窟、云冈石窟、龙门石窟并称中国四大石窟，世界文化遗产。宝顶山大佛湾是大足石刻最集中的区域，在长约500米的U形岩壁上雕刻着近万尊精美石刻造像。千手观音像（实际有1007只手）金光灿烂，面积达88平方米，掌心各有一眼，是世界石刻中绝无仅有的珍品。释迦牟尼涅槃图（卧佛）长达31米，是中国最大的卧佛石刻之一。父母恩重经变相和地狱变相以生动的图像传达了孝道和因果报应等伦理思想，极具生活气息。大足石刻最大的特点是世俗化和生活化，被誉为中国石窟艺术的最后一座丰碑。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_267','武隆喀斯特','景区','["武隆","重庆","喀斯特地貌","天生三桥","天坑地缝","5A景区"]','["世界自然遗产","天生三桥","天坑奇观","变形金刚取景地"]',4.5,56789,76543,29.4445000,107.7989000,'重庆市武隆区仙女山镇','08:00-17:00（旺季至17:30）','uploads/images/武隆喀斯特.jpg','武隆喀斯特以世界最大的天生桥群和壮观的天坑地缝而列入世界自然遗产，是变形金刚4的取景地。','武隆喀斯特位于重庆市武隆区，是世界自然遗产中国南方喀斯特的重要组成部分。天生三桥（天龙桥、青龙桥、黑龙桥）是亚洲最大的天生桥群，三座天然石拱桥平均高度200米以上，横跨于羊水河峡谷之上。天龙天坑和神鹰天坑位于桥群之间，构成了桥中有坑、坑中有桥的奇特地貌。这里曾是《变形金刚4》和《满城尽带黄金甲》的取景地。仙女山国家森林公园有高山草原和森林景观，夏季避暑冬季滑雪。芙蓉洞是中国最美溶洞之一，洞内钟乳石千姿百态。龙水峡地缝深约200米，最窄处仅1米。游览时间1至2天，建议住仙女山镇。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_268','洪崖洞','景区','["洪崖洞","重庆","吊脚楼","嘉陵江","千与千寻","4A景区"]','["重庆城市名片","巴渝吊脚楼","现实版千与千寻","嘉陵江夜景"]',4.5,87654,134567,29.5630000,106.5792000,'重庆市渝中区嘉陵江滨江路88号','全天开放，店铺10:00-22:00','uploads/images/洪崖洞.jpg','洪崖洞是重庆最具标志性的城市景观，以层层叠叠的巴渝吊脚楼建筑群和如千与千寻般的夜景而闻名。','洪崖洞位于重庆市渝中区嘉陵江畔，是重庆最著名的城市地标之一。洪崖洞原名洪崖门，是古重庆城门之一。现有建筑为2006年改造完成的仿古吊脚楼群，共13层（从1楼和11楼都可走到马路上感受山城特色），汇集了餐饮、娱乐、休闲、购物等多种业态。夜晚灯光亮起后整座建筑群如宫崎骏动画《千与千寻》中的汤屋般璀璨梦幻，是重庆最具辨识度的网红打卡地。从洪崖洞可以步行至解放碑重庆最繁华的商圈。旁边嘉陵江上的千厮门大桥是拍摄洪崖洞全景的最佳机位。洪崖洞的洞见山城展览展示了重庆的巴渝文化和城市变迁。建议傍晚前往欣赏日落和夜景，节假日人流量极大需提前规划。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_269','磁器口古镇','景区','["磁器口","重庆","千年古镇","巴渝文化","陈麻花","4A景区"]','["千年古镇","巴渝文化","重庆老码头","特色小吃一条街"]',4.3,54321,76543,29.5814000,106.4531000,'重庆市沙坪坝区磁器口街道','全天开放，店铺09:00-21:00','uploads/images/磁器口古镇.jpg','磁器口是重庆主城区内保存最完好的千年古镇，以巴渝码头文化和琳琅满目的特色小吃而闻名。','磁器口古镇位于重庆市沙坪坝区嘉陵江畔，始建于宋真宗咸平年间（公元998至1003年），原名龙隐镇，后因瓷器贸易繁荣而改名磁器口，是重庆主城区保存最完好的千年古镇。青石板街道是磁器口的主轴，两旁明清风格的店铺鳞次栉比。古镇以三多著称：庙宇多（宝轮寺最为著名）、茶馆多、小吃多。陈麻花是磁器口最著名的特产，每天排队购买的游客绵延数十米。毛血旺、酸辣粉、重庆小面、山城汤圆等重庆特色小吃在这里都能品尝到地道的味道。钟家院是古镇内保存最完整的清代民居。嘉陵江边的老码头承载了千年水运记忆。古镇每年春节和元宵灯会最为热闹。游览时间2至3小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_270','稻城亚丁','景区','["稻城亚丁","甘孜","雪山圣湖","香格里拉","高原秘境","4A景区"]','["蓝色星球最后净土","三怙主神山","高原海子","摄影天堂"]',4.8,98765,134567,28.4567000,100.3456000,'四川省甘孜藏族自治州稻城县香格里拉镇','07:00-18:00（旺季4至11月）','uploads/images/稻城亚丁.jpg','稻城亚丁被称为蓝色星球上的最后一片净土，以三座神山和纯净的雪山海子景观而成为世界级的徒步摄影圣地。','稻城亚丁位于四川省甘孜藏族自治州稻城县香格里拉镇，藏语意为向阳之地。景区以三座雪山为核心：仙乃日（海拔6032米观音菩萨化身）、央迈勇（海拔5958米文殊菩萨化身）、夏诺多吉（海拔5958米金刚手菩萨化身），三神山呈品字形排列、终年积雪不化。冲古寺和洛绒牛场是拍摄雪山倒影的最佳位置。牛奶海（海拔4600米）在央迈勇山脚下，湖水呈乳蓝色如镶嵌在雪山间的翡翠。五色海（海拔4700米）在阳光下呈现五种不同颜色。珍珠海倒映仙乃日雪峰是最经典的画面。景区海拔高（4000米以上），需做好高原反应预防。建议游览1至2天，从香格里拉镇乘景区大巴进入。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_271','海螺沟','景区','["海螺沟","甘孜","冰川森林公园","贡嘎雪山","温泉","5A景区"]','["贡嘎雪山东坡","低海拔现代冰川","冰川温泉","原始森林"]',4.5,54321,65432,29.6123000,102.1048000,'四川省甘孜藏族自治州泸定县磨西镇','08:00-17:00（旺季至17:30）','uploads/images/海螺沟.jpg','海螺沟以低海拔现代冰川和沸腾的冰川温泉而闻名，是近距离观赏蜀山之王贡嘎山的绝佳之地。','海螺沟位于四川省甘孜藏族自治州泸定县，是贡嘎雪山东坡下的一个冰川峡谷，国家5A级旅游景区。海螺沟有全世界海拔最低的现代冰川（冰舌末端海拔仅2850米），普通人无需专业装备即可走近冰川。大冰瀑布宽约1100米、落差约1080米，是中国最大的冰瀑布。海螺沟的温泉是名副其实的冰川温泉——露天温泉池就建在冰川森林中，可以泡着温泉看雪山冰川。贡嘎山（海拔7556米）是蜀山之王，海螺沟是观赏贡嘎山主峰的最佳位置之一，日照金山是摄影爱好者的终极追求。冰川城门洞（冰洞）在夏季更加壮观。每年的5至10月是最佳旅游季节。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_272','四姑娘山','景区','["四姑娘山","阿坝","雪山攀登","东方阿尔卑斯","高山草甸","4A景区"]','["东方阿尔卑斯","雪山攀登胜地","双桥沟","长坪沟"]',4.6,65432,76543,30.9989000,102.8333000,'四川省阿坝藏族羌族自治州小金县四姑娘山镇','08:00-17:00（旺季至17:30）','uploads/images/四姑娘山.jpg','四姑娘山以四座雪山并立如四位少女而被称为东方阿尔卑斯，是中国最美的雪山攀登和徒步胜地之一。','四姑娘山位于四川省阿坝藏族羌族自治州小金县，是世界自然遗产四川大熊猫栖息地的组成部分。四座雪峰一字排开：大峰（海拔5025米，入门级雪山攀登）、二峰（5276米）、三峰（5355米）、幺妹峰（6250米，有蜀山之后之称，至今登顶者极少）。其中幺妹峰被认为是中国最难攀登的山峰之一。双桥沟是四姑娘山最精华的游览区，全程有观光车，雪山森林草甸如瑞士风光。长坪沟适合徒步，木骡子是观赏四姑娘山倒影的经典位置。海子沟以高山海子和草原著称。每年6至7月高山杜鹃盛开，10月中下旬彩林满山。游览时间1至2天，徒步爱好者可计划更长时间。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_273','剑门关','景区','["剑门关","广元","蜀道天险","三国文化","古关隘","5A景区"]','["蜀道难难于上青天","天下第一雄关","三国古战场","悬崖鸟道"]',4.4,45678,54321,32.1883000,105.5756000,'四川省广元市剑阁县剑门关镇','08:00-17:30（旺季至18:00）','uploads/images/剑门关.jpg','剑门关是蜀道天险的核心，李白笔下一夫当关万夫莫开的天下第一险关，也是三国文化的重要遗址。','剑门关位于四川省广元市剑阁县，是古蜀道的核心关隘，素有剑门天下险之誉。李白《蜀道难》中剑阁峥嵘而崔嵬、一夫当关万夫莫开写的就是这里。关楼横跨在大小剑山之间的隘口上，地势极为险要，自古是中原入蜀的咽喉要道。三国时期诸葛亮在此设关、姜维在此退敌。猿猱道和鸟道是两条建在绝壁上的惊险步道，垂直落差约500米，行走其上令人心惊胆寒。剑门关镇的豆腐宴是当地最有名的美食——据说当年姜维军队被困在此，靠吃豆腐补充体力，剑门豆腐因此名扬天下。翠云廊是剑门关至梓潼的古柏树大道，三千余株千年古柏苍劲挺拔。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_274','黄果树瀑布','景区','["黄果树","安顺","大瀑布","喀斯特地貌","水帘洞","5A景区"]','["亚洲最大瀑布群","水帘洞穿瀑","喀斯特地貌","西游记取景地"]',4.6,87654,112345,25.9922000,105.6667000,'贵州省安顺市镇宁布依族苗族自治县黄果树镇','07:30-18:00（旺季至18:30）','uploads/images/黄果树瀑布.jpg','黄果树瀑布是亚洲最大的瀑布群，以穿行水帘洞的独特体验和壮美的喀斯特瀑布群景观而闻名天下。','黄果树瀑布景区位于贵州省安顺市镇宁布依族苗族自治县，是亚洲最大的瀑布群。黄果树大瀑布高约77.8米宽约101米，是瀑布群中最壮观的一座。徐霞客曾赞其为捣珠崩玉飞沫反涌。黄果树最独特之处在于瀑布背后有一条134米长的水帘洞，游客可从洞内穿行，在瀑布后方观赏飞流直下的壮观景象，这是世界瀑布中仅有的体验。陡坡塘瀑布（宽105米）是《西游记》片尾师徒四人走过的瀑布取景地。天星桥以水上石林、溶洞和银链坠潭瀑布为特色。黄果树瀑布群共有18个大小瀑布，被吉尼斯评为世界最大的瀑布群。每年6至8月丰水期水量最大最为壮观。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_275','梵净山','景区','["梵净山","铜仁","佛教名山","红云金顶","黔金丝猴","5A景区"]','["世界自然遗产","弥勒菩萨道场","红云金顶","珍稀动植物"]',4.6,65432,76543,27.9239000,108.6989000,'贵州省铜仁市江口县太平镇','08:00-18:00（旺季至18:30）','uploads/images/梵净山.jpg','梵净山是弥勒菩萨道场和世界自然遗产，以红云金顶的一柱擎天奇观而令人叹为观止。','梵净山位于贵州省铜仁市江口县，是武陵山脉主峰海拔2572米，世界自然遗产。梵净山得名于梵天净土。红云金顶（新金顶）是最震撼的景观——一座高近百米的巨石峰如擎天柱般从山脊上拔地而起，峰顶被一分为二、由天桥相连，两边各建有一座小庙分别供奉释迦牟尼和弥勒。蘑菇石是梵净山的另一标志，高约10米上大下小形如蘑菇，是亿万年风化形成的奇观。梵净山是全球同纬度生物多样性最丰富的地区，是黔金丝猴（全球仅存约800只）的唯一栖息地。建议乘坐索道至万宝岩后步行登顶，游览时间1天。清晨云雾缭绕时分最为神秘壮观。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_276','西江千户苗寨','景区','["千户苗寨","黔东南","苗族文化","吊脚楼","民族风情","4A景区"]','["世界最大苗寨","苗族原生态文化","千户吊脚楼群","万家灯火夜景"]',4.5,65432,87654,26.4939000,108.1743000,'贵州省黔东南苗族侗族自治州雷山县西江镇','全天开放','uploads/images/西江千户苗寨.jpg','西江千户苗寨是世界最大的苗族聚居村寨，以满山遍野的吊脚楼和如星河般璀璨的万家灯火而闻名。','西江千户苗寨位于贵州省黔东南苗族侗族自治州雷山县，由十余个自然村寨相连而成，共1300多户6000余人，苗族人口占99%以上，是世界上最大的苗族聚居村寨。千余户吊脚楼依山而建从山脚层层叠叠延伸到山顶，气势恢宏。夜景尤为壮观——万家灯火点缀在群山之间如同满天繁星洒落人间，从观景台俯瞰是最经典的画面。苗族银饰、刺绣、蜡染是国家级非物质文化遗产。拦门酒、长桌宴、芦笙舞展现了苗族的热情好客。每年苗年节（农历十月）和姊妹节期间活动最为丰富多彩。建议在苗寨住一晚体验万家灯火的夜景和清晨薄雾中炊烟袅袅的苗寨。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_277','荔波樟江','景区','["荔波","黔南","喀斯特山水","小七孔","水上森林","5A景区"]','["世界自然遗产","小七孔古桥","水上森林","地球腰带上的绿宝石"]',4.6,65432,76543,25.4025000,107.8736000,'贵州省黔南布依族苗族自治州荔波县','08:00-17:00（旺季至17:30）','uploads/images/荔波樟江.jpg','荔波樟江以小七孔的碧水古桥和水上森林闻名，被誉为地球腰带上的绿宝石。','荔波樟江风景名胜区位于贵州省黔南布依族苗族自治州荔波县，是世界自然遗产中国南方喀斯特的组成部分。小七孔是荔波最精华的景区——一座建于清道光十五年（1835年）的七孔古石桥横跨在碧绿的响水河上。水上森林是小七孔最独特的景观，千年古木扎根于湍急的水流之中却依然枝繁叶茂，溪水在密林中千回百转形成数百级瀑布。卧龙潭瀑布以弧形的钙化坝和碧蓝的潭水而成为网红打卡地。鸳鸯湖因湖中有两棵参天古树并生如鸳鸯而得名可划船游览。大七孔以恐怖峡和天生桥的峡谷奇观著称。最佳游览季节为5至10月丰水期，游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_278','元阳梯田','景区','["元阳梯田","红河","哈尼梯田","世界遗产","农耕文明","4A景区"]','["世界文化遗产","哈尼农耕文明","大地雕塑","光影奇观"]',4.7,65432,76543,23.1192000,102.7453000,'云南省红河哈尼族彝族自治州元阳县','全天开放（最佳观赏05:30-18:00）','uploads/images/元阳梯田.jpg','元阳梯田是哈尼族历经千年雕刻的大地艺术作品，以日出时分千层水镜般的光影奇观闻名天下。','元阳梯田位于云南省红河哈尼族彝族自治州元阳县，是哈尼族人民1300多年农耕文明的杰作，世界文化遗产。梯田从海拔144米的红河河谷一直延伸到近3000米的山顶，共有约17000级。多依树是看日出的最佳位置，晨光中层层梯田如千万面镜子倒映天空色彩斑斓。坝达以壮观的日落著称，夕阳将千层梯田染成金色和红色。老虎嘴梯田线条优美如一幅巨大的抽象画。每年11月至次年3月灌水季节是元阳梯田最美的时段。箐口民俗村展示了哈尼族的蘑菇房和民俗文化。长街宴是哈尼族最盛大的节日，每年农历十月年期间举办。游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_279','抚仙湖','景区','["抚仙湖","玉溪","高原湖泊","琉璃碧波","水下古城","4A景区"]','["中国最深高原淡水湖","琉璃万顷","水下古城之谜","滇中明珠"]',4.5,45678,54321,24.4614000,102.9011000,'云南省玉溪市澄江市','全天开放','uploads/images/抚仙湖.jpg','抚仙湖是中国最深的高原淡水湖，以琉璃般清澈的湖水和传说中的水下古城而充满神秘色彩。','抚仙湖位于云南省玉溪市澄江市，是中国最深的高原淡水湖（最深处约158米）和蓄水量最大的湖泊之一。湖水极度清澈能见度可达8至12米，唐代文献称之为琉璃万顷。湖中曾发现水下古城遗址，据考古推测距今约2000余年，至今仍是未解之谜。禄充风景区是抚仙湖最著名的景点，笔架山登顶可俯瞰整个湖面。孤山岛是湖中唯一的岛屿素有滇中碧玉之称。红山咀以粉红色沙滩（国内罕见）成为网红打卡地。抚仙湖的铜锅鱼和洋芋焖饭是当地特色美食。每年11月至次年3月红嘴鸥在湖面飞翔。抚仙湖距离昆明约60公里是昆明人的后花园。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_280','普者黑','景区','["普者黑","文山","喀斯特湿地","荷花万亩","彝族风情","5A景区"]','["喀斯特湿地","万亩荷花","三生三世取景地","彝族撒尼文化"]',4.4,45678,54321,24.1067000,104.0956000,'云南省文山壮族苗族自治州丘北县','全天开放（5-9月为荷花季）','uploads/images/普者黑.jpg','普者黑以三百余座孤峰和万亩野生荷花的喀斯特湿地景观而成为云南最具仙气的人间仙境。','普者黑位于云南省文山壮族苗族自治州丘北县，是中国独一无二的喀斯特山水田园风光景区。普者黑是彝族语意为盛满鱼虾的湖泊。三百余座喀斯特孤峰散布在58平方公里的湿地湖泊中，构成了水上田园、湖泊峰林、彝家水乡的独特景观。每年6至9月万亩野生荷花盛开接天莲叶无穷碧，乘一叶扁舟穿行于荷花丛中最为惬意。电视剧《三生三世十里桃花》和综艺《爸爸去哪儿》在此取景。青龙山登顶看日出可俯瞰普者黑全景峰林如盆景。仙人洞村是彝族撒尼人的聚落可体验火把节和抹花脸等民俗。游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_281','虎跳峡','景区','["虎跳峡","迪庆","金沙江","徒步圣地","峡谷奇观","4A景区"]','["世界最深峡谷之一","金沙江咆哮","世界经典徒步路线","玉龙哈巴双雪山"]',4.6,54321,65432,27.1878000,100.1167000,'云南省迪庆藏族自治州香格里拉市虎跳峡镇','08:00-17:00','uploads/images/虎跳峡.jpg','虎跳峡是世界上最深的峡谷之一，金沙江在此咆哮奔腾，也是全球最经典的徒步路线之一。','虎跳峡位于云南省迪庆藏族自治州香格里拉市，是世界上最深的峡谷之一，最窄处仅约30米。金沙江自玉龙雪山和哈巴雪山之间咆哮穿过，形成了上虎跳、中虎跳、下虎跳三段。上虎跳是游客最常到达的地方，一块巨石（虎跳石）横卧江中，江水撞击巨石激起惊涛骇浪声震山谷。中虎跳是徒步者的天堂，满天星和一线天险峻异常。下虎跳以金沙江大拐弯（长江第一湾）最为壮观。虎跳峡高路徒步线被誉为世界十大经典徒步路线之一，全程约22公里，沿途可欣赏玉龙雪山和哈巴雪山的壮美风光。最佳游览季节为4至6月和9至11月避免雨季。游览时间1天（乘车+短途步行）或2天（全程徒步）。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_282','雅鲁藏布大峡谷','景区','["雅鲁藏布","林芝","世界最深峡谷","南迦巴瓦","雅鲁藏布江","5A景区"]','["世界最深最长峡谷","南迦巴瓦峰","高原河流奇观","生物多样性宝库"]',4.7,56789,65432,29.5234000,94.9012000,'西藏自治区林芝市米林市派镇','08:00-18:00（4-10月）','uploads/images/雅鲁藏布大峡谷.jpg','雅鲁藏布大峡谷是世界上最深最长的峡谷，以南迦巴瓦峰和雅鲁藏布江大拐弯的壮美景观震撼人心。','雅鲁藏布大峡谷位于西藏自治区林芝市米林市，是世界上最深（最深处达5382米）、最长（约504.6公里）的峡谷。雅鲁藏布江在喜马拉雅山脉东端切出一个巨大的马蹄形拐弯（大拐弯），环绕南迦巴瓦峰（海拔7782米，中国最美雪山之一）。南迦巴瓦峰因常年云雾缭绕十人九不遇，见到真容极为幸运。峡谷内从高山冰雪带到热带雨林，涵盖了极完整的垂直生态系统。每年3至4月峡谷内桃花盛开（林芝桃花节的核心区域），雪山、桃花、江水层次极为丰富。直白村是最接近南迦巴瓦峰的地方，索松村是拍摄雪山峡谷的最佳机位。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_283','珠穆朗玛峰大本营','景区','["珠穆朗玛峰","日喀则","世界之巅","喜马拉雅","极限挑战","4A景区"]','["世界最高峰","日照金山","喜马拉雅山脉","高原极致风光"]',4.8,65432,87654,28.1456000,86.8602000,'西藏自治区日喀则市定日县扎西宗乡','全天开放（需办边防证，4-10月最佳）','uploads/images/珠穆朗玛峰大本营.jpg','珠穆朗玛峰大本营是普通人离世界之巅最近的地方，仰望8848米的日照金山是一生必去的极致体验。','珠穆朗玛峰大本营位于西藏自治区日喀则市定日县，海拔5200米，是世界最高峰珠穆朗玛峰（海拔8848.86米）北坡的登山大本营。这里是普通游客能够到达的距珠峰最近的位置。清晨日出时分金色的阳光洒在珠峰顶上形成日照金山的绝美景象（最佳观赏时间为每年10月至次年4月）。加乌拉山口（海拔5198米）在天气晴好时可以看到5座8000米以上高峰（珠峰、洛子峰、马卡鲁峰、卓奥友峰、希夏邦马峰）一字排开的震撼场面。绒布寺是世界上海拔最高的寺庙之一（海拔约5100米）。前往珠峰需提前办理边防证并在定日县适应高海拔环境。游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_284','羊卓雍措','景区','["羊卓雍措","山南","圣湖","高原湖泊","蓝宝石","4A景区"]','["西藏三大圣湖","蓝宝石湖面","岗巴拉山口","雪山环绕"]',4.7,65432,76543,28.9345000,90.6456000,'西藏自治区山南市浪卡子县','全天开放','uploads/images/羊卓雍措.jpg','羊卓雍措是西藏三大圣湖之一，在岗巴拉山口俯瞰那一抹令人窒息的宝石蓝是西藏最经典的画面。','羊卓雍措位于西藏自治区山南市浪卡子县，是西藏三大圣湖之一（纳木措、玛旁雍措、羊卓雍措）。藏语意为天鹅之湖。湖面海拔约4441米面积约638平方公里。湖水呈现令人难以置信的宝石蓝在不同天气和角度下变幻出蓝绿相间的迷人光泽。岗巴拉山口（海拔4990米）是俯瞰羊卓雍措全景的最佳位置，从山口望去蓝色的湖面如一块巨大的宝石镶嵌在群山之间。羊卓雍措的湖水深度达20至40米。沿湖公路可以走近湖边近距离感受湖水的清澈。湖边的桑丁寺是西藏唯一由女活佛主持的寺庙。每年藏历四月萨嘎达瓦节期间当地藏民来此转湖祈福。游览时间半天可从拉萨一日往返。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_285','扎什伦布寺','景区','["扎什伦布寺","日喀则","班禅驻锡","藏传佛教","金顶白塔","5A景区"]','["历代班禅驻锡地","藏传佛教格鲁派","世界最大铜佛","后藏宗教中心"]',4.6,45678,54321,29.2669000,88.8831000,'西藏自治区日喀则市桑珠孜区几吉朗卡路1号','09:00-18:00','uploads/images/扎什伦布寺.jpg','扎什伦布寺是班禅喇嘛的驻锡地，以世界最大的鎏金铜佛和璀璨的金顶白塔群而闻名于藏传佛教世界。','扎什伦布寺位于西藏自治区日喀则市桑珠孜区，藏语意为吉祥须弥寺，是藏传佛教格鲁派（黄教）在后藏地区的最高寺院，也是历代班禅喇嘛的驻锡地。寺院由一世达赖喇嘛根敦朱巴于明正统十二年（1447年）创建，占地约15万平方米。措钦大殿（大经堂）可容纳2000余名喇嘛同时诵经。强巴佛殿内供奉着世界最大的铜佛——强巴佛（弥勒佛）坐像高26.2米，用黄金约279公斤和铜约11.5万公斤铸造，眉间镶嵌一颗核桃大的钻石。历代班禅灵塔殿以十世班禅灵塔最为宏伟，塔高11.55米用黄金包裹。每年藏历五月展佛节是扎寺最盛大的佛事活动。游览时间2至3小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_286','法门寺','景区','["法门寺","宝鸡","佛教圣地","佛指舍利","唐代地宫","5A景区"]','["佛教圣物","释迦牟尼佛指真身舍利","唐代皇家寺院","地宫出土珍宝"]',4.6,56789,76543,34.4433000,107.8925000,'陕西省宝鸡市扶风县法门镇','08:30-18:00（旺季至18:30）','uploads/images/法门寺.jpg','法门寺因供奉释迦牟尼佛指骨真身舍利而成为世界佛教圣地，其地宫宝藏震惊世界。','法门寺位于陕西省宝鸡市扶风县，始建于东汉末年，距今已有1800余年历史。法门寺因供奉释迦牟尼佛指骨真身舍利而成为世界佛教徒朝拜的圣地。1987年在清理地宫时发现了佛指骨舍利及2499件唐代皇室供奉的绝世珍宝（金银器、秘色瓷器、丝绸、琉璃器等），其数量之多、等级之高、品类之丰震惊世界，被称为世界第九大奇迹。合十舍利塔高148米双手合十造型是现代佛教建筑的杰作，佛指舍利每逢农历初一、十五和节假日升至上层供人瞻仰。法门寺博物馆收藏了地宫出土的大量珍贵文物。每年农历四月初八浴佛节是法门寺最盛大的节日。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_287','太白山国家森林公园','景区','["太白山","宝鸡","秦岭主峰","高山湖泊","滑雪胜地","5A景区"]','["秦岭最高峰","六月积雪","大爷海冰川湖","户外登山胜地"]',4.4,45678,54321,33.9567000,107.7683000,'陕西省宝鸡市眉县汤峪镇','08:00-17:00（旺季至17:30）','uploads/images/太白山国家森林公园.jpg','太白山是秦岭主峰和最高峰，以六月积雪的奇观和高山湖泊大爷海而成为户外登山爱好者的圣地。','太白山国家森林公园位于陕西省宝鸡市眉县，是秦岭山脉主峰，海拔3771.2米，为中国大陆青藏高原以东的最高峰。太白山得名于山顶常年积雪（虽然近年来雪线已经上移），古称太乙山。拔仙台是太白山最高点，登顶可观秦岭群峰连绵起伏的壮丽景象。大爷海、二爷海、三爷海是第四纪冰川形成的高山冰斗湖，湖水碧蓝澄澈。太白山垂直植被带从阔叶林到高山草甸分布完整，秋季红叶漫山色彩斑斓。太白积雪六月天为关中八景之一。太白山是中国南北地理分界线秦岭的核心地段，有中国南北分界岭的标志。游览时间1至2天，可乘坐天下索道至3511米天圆地方处。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_288','黄帝陵','景区','["黄帝陵","延安","华夏始祖","中华文明","轩辕黄帝","5A景区"]','["华夏第一陵","中华文明发祥地","轩辕黄帝","祭祖圣地"]',4.5,45678,56789,35.5856000,109.2694000,'陕西省延安市黄陵县桥山镇','08:00-17:30','uploads/images/黄帝陵.jpg','黄帝陵是中华民族始祖轩辕黄帝的陵寝，被誉为华夏第一陵，是全球华人的精神故乡。','黄帝陵位于陕西省延安市黄陵县桥山之上，是中华民族始祖轩辕黄帝的陵寝。司马迁《史记》记载黄帝崩葬桥山，黄帝陵因此被称为天下第一陵和华夏第一陵。桥山古柏参天，黄帝手植柏（相传为黄帝亲手所栽）树龄约5000年，是中国最古老的柏树。轩辕庙（黄帝庙）是历代帝王祭祀黄帝的场所，庙内有孙中山、毛泽东、蒋介石、邓小平、江泽民等历代名人的题词碑刻。每年清明节举行的清明公祭轩辕黄帝典礼是中国最高规格的祭祀活动，全球华人代表齐聚桥山共祭始祖。重阳节也有祭祀活动。香港澳门回归纪念碑和台湾光复纪念碑分立两侧。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_289','莫高窟','景区','["莫高窟","敦煌","世界遗产","佛教艺术","丝绸之路","5A景区"]','["世界文化遗产","佛教艺术宝库","丝绸之路明珠","跨越千年的壁画"]',4.9,112345,167890,40.0415000,94.8036000,'甘肃省酒泉市敦煌市莫高镇','08:00-18:00（旺季），09:00-17:30（淡季），需提前预约','uploads/images/莫高窟.jpg','莫高窟是世界现存规模最大内容最丰富的佛教艺术圣地，以跨越十个朝代的精美壁画和彩塑而成为丝路明珠。','莫高窟位于甘肃省酒泉市敦煌市东南25公里的鸣沙山东麓，俗称千佛洞。始建于前秦建元二年（公元366年），历经十六国、北朝、隋唐五代宋西夏元等朝代连续开凿，现存洞窟735个壁画4.5万平方米彩塑2415尊，是世界上现存规模最大内容最丰富的佛教艺术圣地。藏经洞于1900年出土公元4至11世纪佛经文书画卷等文物5万余件。敦煌学由此成为一门国际显学。第96窟弥勒大佛高35.5米是莫高窟第一大佛。第45窟彩塑七尊和第112窟反弹琵琶伎乐天是敦煌艺术经典。游览需提前在官网预约每天限流6000人，参观约3至4小时先看数字展示中心电影再参观实体洞窟。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_290','鸣沙山月牙泉','景区','["鸣沙山","敦煌","沙漠奇观","月牙泉","丝路风光","5A景区"]','["沙漠第一泉","鸣沙奇观","丝路驼铃","沙水共生绝景"]',4.6,76543,98765,40.0864000,94.6711000,'甘肃省酒泉市敦煌市鸣沙山月牙泉景区','06:00-19:30（旺季至20:00）','uploads/images/鸣沙山月牙泉.jpg','鸣沙山月牙泉以沙动成响和沙漠中千年不涸的月牙形清泉而成为中国最美的沙漠奇观。','鸣沙山月牙泉位于甘肃省酒泉市敦煌市城南5公里。鸣沙山因沙动成响而得名，沙山东西绵延约40公里最高海拔约1715米。月牙泉被鸣沙山环抱，因形状酷似一弯新月而得名，泉水千年不涸在茫茫沙漠中形成一汪碧水水草丛生清澈见底，被誉为沙漠第一泉。沙不填泉泉不涸竭的沙泉共生奇观至今是未解之谜。骑骆驼穿越沙丘是体验丝路风情的经典项目。滑沙从百米沙丘滑下刺激有趣。日落时分是最佳游览时间，夕阳将沙山染成金色极为壮美。景区门票3日内有效可多次入园。今年新增的万人星空演唱会（在沙山上躺看演出）火爆全网。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_291','嘉峪关关城','景区','["嘉峪关","嘉峪关","天下第一雄关","明长城","丝绸之路","5A景区"]','["天下第一雄关","明长城西端起止","丝路军事要塞","关城建筑群"]',4.5,54321,65432,39.8012000,98.2162000,'甘肃省嘉峪关市峪泉镇','08:00-20:00（旺季），08:30-18:00（淡季）','uploads/images/嘉峪关关城.jpg','嘉峪关是明长城西端起点天下第一雄关，以巍峨的关城建筑和万里长城第一墩的险峻而闻名。','嘉峪关关城位于甘肃省嘉峪关市西5公里处，是明长城西端的起点，建于明洪武五年（1372年），自古有天下第一雄关之称。关城由内城外城罗城瓮城城壕和两翼长城组成，周长约733米城墙高约10米。关城设计极为精密巧妙，据说建成后仅多出一块砖（现放于会极门后）。游击将军府是明清最高军事指挥官办公地。悬壁长城建在45度山脊上如倒挂天际。长城第一墩（讨赖河墩）是明长城最西端的墩台矗立在讨赖河峡谷悬崖边缘。嘉峪关也是古丝绸之路重要关隘。嘉峪关方特欢乐世界在关城附近为大型主题乐园。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_292','张掖丹霞','景区','["张掖丹霞","张掖","丹霞地貌","七彩丘陵","地质奇观","5A景区"]','["世界地质公园","七彩丹霞","彩色丘陵","全球25个梦幻旅行地"]',4.7,76543,98765,38.9317000,100.1081000,'甘肃省张掖市临泽县倪家营镇','06:30-18:00（夏季至19:00）','uploads/images/张掖丹霞.jpg','张掖丹霞是中国最美的彩色丘陵，被《中国国家地理》评为中国最美的七大丹霞之一，如同上帝打翻的调色盘。','张掖丹霞地质公园位于甘肃省张掖市临泽县和肃南县境内，世界地质公园。张掖丹霞是中国唯一的丹霞地貌与彩色丘陵景观复合区。七彩丹霞连绵的山丘呈现出红橙黄绿白灰紫等不同色彩如同一块巨大的调色板铺展在大地上，被《美国国家地理》评为全球25个梦幻旅行地之一。4个观景台（七彩仙缘台七彩云海台七彩锦绣台七彩红霞台）各有千秋，其中七彩红霞台是看日落的最佳位置。冰沟丹霞以窗棂状和宫殿式丹霞为特色造型奇特。日出和日落时分低角度阳光使彩色丘陵层次感最为鲜明是摄影的最佳时间。景区内有热气球和动力伞可以从空中俯瞰七彩丹霞。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_293','祁连山草原','景区','["祁连山","海北","高原草原","雪山牧场","丝绸之路","4A景区"]','["中国最美六大草原","祁连雪山","夏季牧场","丝绸之路南线"]',4.5,45678,54321,38.1234000,100.2567000,'青海省海北藏族自治州祁连县','全天开放（6-9月为最佳旅游季）','uploads/images/祁连山草原.jpg','祁连山草原是中国最美六大草原之一，以雪山草原油菜花交相辉映的壮美风光而成为青海旅游的必游之地。','祁连山草原位于青海省海北藏族自治州祁连县，是中国最美六大草原之一。祁连山是古丝绸之路南线的重要通道。祁连山下好牧场——祁连草原以夏季牧场风光最为迷人，蓝天白云下绿色的草甸与远处的岗什卡雪峰交相辉映，成群的牦牛和羊群散落其间。每年7月门源的万亩油菜花盛开，金黄的花海与祁连雪山构成震撼的色彩对比。卓尔山是观赏祁连草原和阿咪东索神山的最佳位置，被称为东方小瑞士。祁连鹿场是中国最大的半野生马鹿养殖基地。海拔较高（3000米以上）需注意高反应对。最佳旅游季节为6至9月，游览时间1至2天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_294','门源油菜花海','景区','["门源","海北","油菜花海","百里花海","祁连雪山","4A景区"]','["世界最大油菜花海","百里油菜花","祁连雪山背景","7月限定"]',4.6,56789,76543,37.3731000,101.6238000,'青海省海北藏族自治州门源回族自治县','全天开放（7月为最佳赏花期）','uploads/images/门源油菜花海.jpg','门源油菜花海是世界最大的油菜花种植区，万亩金黄与祁连雪峰同框的壮观画面是青海最美的夏日名片。','门源油菜花海位于青海省海北藏族自治州门源回族自治县，是中国乃至世界最大的油菜花种植区，种植面积达50余万亩。每年7月（最佳观赏期为7月中旬），万亩油菜花同时绽放，金黄色的花海绵延近百公里，与远处终年积雪的岗什卡雪峰和祁连山脉构成天地间最壮丽的色彩对比。圆山观景台是拍摄油菜花海全景的最佳位置，从高处俯瞰，整片大地如同一张巨大的金黄地毯。青石嘴镇是花海的交通枢纽。当地还会举办门源油菜花文化旅游节，有赛马、射箭等藏族民俗活动表演。花期仅约20天，错过就要等一年。海拔约3000米需注意防晒和高反。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_295','沙坡头','景区','["沙坡头","中卫","沙漠黄河","麦草方格","羊皮筏子","5A景区"]','["大漠黄河交汇","麦草方格治沙奇迹","羊皮筏子漂流","沙漠娱乐"]',4.5,56789,76543,37.4989000,105.0231000,'宁夏回族自治区中卫市沙坡头区','08:00-18:00（夏季至19:00）','uploads/images/沙坡头.jpg','沙坡头是中国最美的沙漠旅游区之一，大漠黄河高山绿洲在此神奇交汇，创造了人类治沙史上的奇迹。','沙坡头位于宁夏回族自治区中卫市沙坡头区，地处腾格里沙漠东南缘。唐代王维在此写下大漠孤烟直长河落日圆的千古绝唱。沙坡头以麦草方格治沙闻名世界，这一技术被联合国评为全球环境保护五百佳之一。景区分为沙漠区和黄河区：黄河区可体验羊皮筏子漂流（用充气羊皮制成的传统渡河工具）、黄河飞索（飞越黄河的高空滑索）；沙漠区可骑骆驼穿越沙丘、体验沙海冲浪车和沙漠越野。沙坡头的滑沙场是中国最大坡度最陡的之一。沙漠星星酒店是国内顶级沙漠野奢酒店。夜晚的沙漠星空极为璀璨。建议游览时间1天，沙漠昼夜温差大需带外套。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_296','西夏王陵','景区','["西夏王陵","银川","西夏文化","东方金字塔","帝王陵寝","4A景区"]','["东方金字塔","西夏帝国遗迹","党项文化","贺兰山风光"]',4.3,34567,45678,38.4417000,105.9886000,'宁夏回族自治区银川市西夏区贺兰山东麓','08:00-18:00（旺季至18:30）','uploads/images/西夏王陵.jpg','西夏王陵是西夏帝国的皇家陵寝群，九座金字塔形的巨大夯土陵台被誉为神秘的东方金字塔。','西夏王陵位于宁夏回族自治区银川市西夏区贺兰山东麓，是西夏王朝（1038至1227年）的皇家陵寝群，占地面积约50平方公里。现存9座帝陵和253座陪葬墓，每座帝陵由一个金字塔形巨大夯土封土堆（高约20至30米）及内外城月城献殿墓道等组成。因形似埃及金字塔被称为东方金字塔。3号陵（推测为开国皇帝李元昊之陵）保存最完整。西夏王陵蕴含大量未解之谜：为什么夯土历经近千年风雨冲刷不塌？为什么陵区不长草鸟不落？西夏博物馆展示了独特的西夏文字（仿汉字创制）、鎏金铜牛（国宝级）、西夏佛经等珍贵文物。景区背靠贺兰山，夕阳下金字塔与苍茫贺兰山构成极为壮美的画面。游览时间半天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_297','镇北堡西部影城','景区','["镇北堡","银川","影视基地","西北风情","大话西游","5A景区"]','["中国电影从这里走向世界","大话西游取景地","西北民俗","影视拍摄基地"]',4.5,56789,87654,38.5992000,106.0639000,'宁夏回族自治区银川市西夏区镇北堡镇','08:00-18:00（旺季至18:30）','uploads/images/镇北堡西部影城.jpg','镇北堡西部影城是中国最具西北特色的影视拍摄基地，《大话西游》《新龙门客栈》等经典影片诞生于此。','镇北堡西部影城位于宁夏回族自治区银川市西夏区，是中国三大影视城之一，被誉为中国电影从这里走向世界。影城由两座明清时期的古堡（明城和清城）改造而成，保持了西北特有的黄土夯筑原始风貌。1993年张贤亮创办了西部影城，至今已有200余部影视剧在此取景。《大话西游》中至尊宝和紫霞仙子的经典对白场景就拍摄于此，月亮门和盘丝洞成为无数影迷的朝圣之地。《新龙门客栈》《红高粱》《东邪西毒》等经典影片都在这里留下印记。影城内还有西北民俗博物馆和民间艺术表演。游客可以租借古装拍照留念，体验侠客江湖的快意恩仇。游览时间2至3小时。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_298','可可托海','景区','["可可托海","阿勒泰","地质奇观","神钟山","额尔齐斯河","5A景区"]','["世界地质公园","神钟山","额尔齐斯河源头","宝石之乡"]',4.5,45678,54321,47.1789000,89.8001000,'新疆维吾尔自治区阿勒泰地区富蕴县可可托海镇','08:00-19:00（5至10月），冬季关闭','uploads/images/可可托海.jpg','可可托海是世界地质公园，以神钟山的震撼花岗岩奇观和额尔齐斯河的源头风光闻名于世。','可可托海位于新疆维吾尔自治区阿勒泰地区富蕴县，额尔齐斯河源头，世界地质公园。可可托海哈萨克语意为绿色的丛林蒙古语意为蓝色的河湾。神钟山是景区标志——一整块巨大花岗岩如一口倒扣的巨钟矗立在额尔齐斯河畔，高约365米底部周长约1000米。三号矿脉曾是中国最大的稀有金属矿，为偿还苏联债务和中国航天事业做出巨大贡献，地质陈列馆展示了这段历史。卡拉先格尔地震断裂带是1931年8级大地震造成的壮观地表破裂。可可苏里湖（野鸭湖）秋季芦苇金黄野鸭成群。秋季（9月中下旬）是最佳旅游季节，白桦林金黄一片。景区还有温泉疗养设施。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_299','赛里木湖','景区','["赛里木湖","博尔塔拉","高山湖泊","净海明珠","花海草原","5A景区"]','["大西洋最后一滴眼泪","高山冷水湖","湖畔花海","蓝冰奇观"]',4.7,65432,87654,44.6095000,81.1649000,'新疆维吾尔自治区博尔塔拉蒙古自治州博乐市','全天开放（5至10月为最佳旅游季）','uploads/images/赛里木湖.jpg','赛里木湖被称为大西洋的最后一滴眼泪，以极度清澈的湛蓝湖水和夏季湖畔的五彩花海而成为新疆最美的高山湖泊。','赛里木湖位于新疆维吾尔自治区博尔塔拉蒙古自治州博乐市，是天山山脉中海拔最高面积最大的高山冷水湖。湖面海拔约2073米面积约458平方公里。赛里木湖古称净海，因是大西洋暖湿气流最后眷顾的地方被称为大西洋的最后一滴眼泪。湖水极度清澈透明度可达12米在阳光和天色变化下呈现从碧绿到湛蓝的多种色彩。每年6至7月湖畔草原上各色野花盛开（金莲花紫菀勿忘我等），将湖畔装点成五彩缤纷的花海。湖南岸的果子沟大桥是新疆最美桥梁之一。冬季湖面完全冰封形成蓝冰和冰泡湖奇观同样令人叹为观止。环湖公路约90公里可自驾或骑行游览。游览时间半天至1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_300','巴音布鲁克草原','景区','["巴音布鲁克","巴音郭楞","天鹅湖","九曲十八弯","土尔扈特","5A景区"]','["中国第二大草原","九曲十八弯落日","天鹅故乡","土尔扈特东归"]',4.6,56789,65432,43.0345000,84.1456000,'新疆维吾尔自治区巴音郭楞蒙古自治州和静县','08:00-20:00（5至10月），冬季关闭','uploads/images/巴音布鲁克草原.jpg','巴音布鲁克草原是中国第二大草原，以开都河九曲十八弯的九个太阳落日奇观和天鹅湖而闻名于世。','巴音布鲁克草原位于新疆维吾尔自治区巴音郭楞蒙古自治州和静县，是中国第二大草原（仅次于呼伦贝尔），面积约2.3万平方公里。巴音布鲁克蒙古语意为丰泉。开都河的九曲十八弯是最震撼的景观——河水在草原上蜿蜒曲折，日落时分如果角度合适最多可以看到9个太阳的倒影同时映在河湾中，被称为九日连珠。天鹅湖自然保护区是中国第一个天鹅保护区，每年4至10月数千只大天鹅在此栖息繁衍。巴音布鲁克还是土尔扈特蒙古族东归的定居地，1771年土尔扈特部在首领渥巴锡率领下从伏尔加河流域万里东归最终定居于此。每年的那达慕大会有赛马摔跤射箭等活动。海拔约2500米昼夜温差大需带保暖外套。游览时间1天。',0);
INSERT INTO `spot_place` (`id`,`name`,`type`,`keywords`,`features`,`rating`,`rating_count`,`click_count`,`lat`,`lng`,`address`,`open_time`,`image`,`description`,`detail_description`,`deleted`) VALUES ('place_301','喀拉峻草原','景区','["喀拉峻","伊犁","空中草原","哈萨克文化","天山世界遗产","5A景区"]','["世界自然遗产","人体草原","天山雪峰","哈萨克游牧文化"]',4.5,45678,54321,43.0234000,82.5012000,'新疆维吾尔自治区伊犁哈萨克自治州特克斯县','08:00-20:00（5至10月），冬季关闭','uploads/images/喀拉峻草原.jpg','喀拉峻草原是世界自然遗产天山的核心组成部分，以波浪般起伏的人体草原曲线而成为新疆最美的立体草原。','喀拉峻草原位于新疆维吾尔自治区伊犁哈萨克自治州特克斯县，是世界自然遗产天山的核心组成部分。喀拉峻是哈萨克语意为山脊上的莽原。喀拉峻最独特的是其立体起伏的地形——草原不是一马平川而是波浪般起伏，形成了人体草原（曲线优美如人体）的独特景观。东喀拉峻以五花草甸著称，每年5至7月各色野花竞相绽放如织锦般绚烂。西喀拉峻以阔克苏大峡谷的悬崖峭壁和鳄鱼湾（峡谷形如巨鳄）最为壮观。这里还是哈萨克牧民的传统夏牧场，夏季可以看到成群的牛羊和白色毡房点缀在绿色草原上。喀拉峻也是世界自然遗产中国天山的组成部分。游览时间1天，6至7月草原最绿野花最多。',0);
